-- Poems batch 51
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2a3948f4-9eb0-4990-80c9-c4641ef5a2c8','奉酬李中丞洪湖州西亭即事見寄兼呈吳馮處士時中丞量移湖州長史','皎然','唐','唐诗','tang','','[]','愛君溪上住，遲月開前扃。',84,'全唐诗/poet.tang.44000.json','["愛君溪上住，遲月開前扃。", "山火照書卷，野風吹酒瓶。", "爲誰留此物，意在眼中青。", "樵子逗煙墅，漁翁宿沙汀。", "主人非楚客，莫謾譏獨醒。", "宿昔邢城功，道高心已冥。", "貪將到處士，放醉烏家亭。"]'),
('7876c6c9-3d24-4f17-85eb-03d786a28e18','苕溪草堂自大曆三年夏新營洎秋及春彌覺境勝因紀其事簡潘丞述湯評事衡四十三韻','皎然','唐','唐诗','tang','','[]','萬慮皆可遺，愛山情不易。',288,'全唐诗/poet.tang.44000.json','["萬慮皆可遺，愛山情不易。", "自從東溪住，始與人羣隔。", "應物非宿心，遺身是吾策。", "先民崆峒子，淪景事金液。", "綺里猶近名，於陵未泯跡。", "吾師逆流教，禪隱殊古昔。", "洗足臨潺湲，銷聲寄松柏。", "緗荷採堪服，柔草持可席。", "道心制野猨，法語授幽客。", "境淨萬象真，寄目皆有益。", "原上無情花，山中聽經石。", "竹生自蕭散，雲性常潔白。", "却見羇世人，遠高摩霄翮。", "達賢觀此意，煩想遂冰蘖。", "伊予戰苦勝，覽境情不溺。", "智以動念昏，功由無心積。", "形骸爾何有，生死誰所戚。", "爲與勝悟冥，不憂頹齡迫。", "春風自駘蕩，禪地常闃寂。", "擲札成柳枝，溉瓶養泉脉。", "道人知止足，盥漱聊自適。", "學外見古賢，頗令我心惕。", "眇綿雲官世，夢幻羽陵籍。", "鬼籙徒相矜，九原誰家宅。"]'),
('3ac6a53b-f083-4371-bba7-934d31a2ffe7','荅裴集陽伯明二賢各垂贈二十韻今以一章用酬兩作','皎然','唐','唐诗','tang','','[]','知音如瓊枝，天生爲予有。',240,'全唐诗/poet.tang.44000.json','["知音如瓊枝，天生爲予有。", "攀折若無階，何殊天上柳。", "裴生清通嗣，陽子盛德後。", "詩名比元長，賦體凌延壽。", "珠生驪龍頷，或生靈蛇口。", "何似雙瓊章，英英曜吾手。", "白日不可汙，清源肯容垢。", "持此山上心，待君忘情友。", "且伴丘壑賞，未隨名宦誘。", "坐石代瓊茵，製荷捐艾綬。", "清宵集我寺，烹茗開禪牖。", "發論教可垂，正文言不朽。", "白雲供詩用，清吹生座右。", "不嫌逸令醉，莫試仙壺酒。", "皎皎尋陽隱，千年可爲偶。", "一從漢道平，世事無紛糺。", "星文齊七政，天軸明二斗。", "召士揚弓旌，知君在林藪。", "莫學潁陽子，請師高山叟。", "出處藩我君，還來會厓阜。"]'),
('eef9ff7e-274e-4474-a36b-92a47cb7183b','荅豆盧居士春夜遊東園見懷','皎然','唐','唐诗','tang','','[]','春意賞不足，承夕步東園。',48,'全唐诗/poet.tang.44000.json','["春意賞不足，承夕步東園。", "事表精慮遠，月中華木繁。", "開襟寄清景，遐想屬空門。", "安得纚芳屣，看君幽徑萱。"]'),
('20564f12-8067-47f0-8dba-2ca90c1ba0e9','寄崔萬芳夔','皎然','唐','唐诗','tang','','[]','氣殺高隼擊，惜芳步寒林。',72,'全唐诗/poet.tang.44000.json','["氣殺高隼擊，惜芳步寒林。", "風搖蒼琅根，霜剪荍𦾾心。", "歸思忽眇眇，佳氣亦沈沈。", "我身豈遐遠，如隔湘漢深。", "事邇智莫及，願乖情不任。", "遲君忘言侶，一笑開吾襟。"]'),
('959f922c-1bdd-4e38-b1ee-14ad030f8409','訪朱放山人','皎然','唐','唐诗','tang','','[]','野人未相識，何處異鄉隔。',62,'全唐诗/poet.tang.44000.json','["野人未相識，何處異鄉隔。", "昨逢雲陽信，教向雲陽覓。", "空聞天上風，飄颻不可覿。", "應非矍[鑠]翁，或是滄浪客。", "早晚從我遊，共攜春山策。"]'),
('2058509a-b6ac-4aa7-86c3-593a36de1f3e','晚冬廢溪東寺懷李司直縱','皎然','唐','唐诗','tang','','[]','廢溪無人跡，益見離思深。',156,'全唐诗/poet.tang.44000.json','["廢溪無人跡，益見離思深。", "歸來始昨日，恍惚驚歲陰。", "清想屬遙夜，圓景當空林。", "宿昔月未改，何如故人心。", "遊從間芳趾，搖落棲寒岑。", "眇眇湖上別，含情初至今。", "道流安寂寞，世路倦嶇嶔。", "此意欲誰見，懷賢獨難任。", "徽聲反冥默，夕籟何哀吟。", "禪念破離夢，吾師誡援琴。", "耿耿已及旦，曷由開此襟。", "幽期諒未偶，勝境徒自尋。", "安得西歸雲，因之傳素音。"]'),
('42e5d343-91fa-411c-934f-a223ebfd8de0','兵後與故人別予西上至今在揚楚因有是寄','皎然','唐','唐诗','tang','','[]','日月不相待，思君魂屢驚。',84,'全唐诗/poet.tang.44000.json','["日月不相待，思君魂屢驚。", "草玄寄楊子，作賦得蕪城。", "溫溫獨游跡，遙遙相望情。", "淮上青草歇，楚子秋風生。", "辟士天下盡，君何獨屏營。", "運開應佐世，業就可成名。", "誰借楚山住，年年事耦耕。"]'),
('7d6f675e-030d-47ba-88b1-cef976d1938f','因遊支硎寺寄邢端公','皎然','唐','唐诗','tang','','[]','大廈資多士，掄材得豫章。',288,'全唐诗/poet.tang.44000.json','["大廈資多士，掄材得豫章。", "清門推問望，早歲騁康莊。", "作用方開物，聲名久擅塲。", "丹延分塞郡，宿昔領戎行。", "始馭屏星乘，旋陰蔽茀棠。", "朝端瞻鶚立，關右仰鷹揚。", "威令兼寧朔，英聲重護羌。", "三軍成父子，雜虜避封疆。", "身執金吾貴，時遭寶運昌。", "雍容持漢矟，肅穆衛周堂。", "排難知臣節，攻疑定國章。", "一言明大義，千載揖休光。", "踐職勳庸列，修躬志行彰。", "優游應慕陸，止足定師張。", "中扆懷殊政，南州佇小康。", "仁爲桂江雨，威是柏臺霜。", "謇諤言無隱，公忠禍不防。", "譴深辭紫禁，恩在副朱方。", "切玉鋒休淬，垂天翅罷翔。", "論文徵賈馬，述隱許求羊。", "肘後看金碧，腰間笑水蒼。", "詩題白羽扇，酒挈綠油囊。", "曠達機何有，深沈器莫量。", "時應登古寺，佳趣在春岡。"]'),
('1c001d0b-844c-408f-b999-e9d6b419b6a1','同諸公奉侍祭岳瀆使大理盧幼平自會稽迴經平望將赴於朝廷期過故林不至','皎然','唐','唐诗','tang','','[]','望祀崇周典，皇華出漢庭。',120,'全唐诗/poet.tang.44000.json','["望祀崇周典，皇華出漢庭。", "紫泥頒會計，玄酒薦芳馨。", "聖慮多虔肅，齋心合至靈。", "占祥刊史竹，筮日數堯蓂。", "禮秩加新命，朝章篤理刑。", "敷誠通北闕，遺愛在南亭。", "苕水思曾泛，磯山憶重經。", "清風門客仰，佳頌國人聽。", "攀桂留卿月，徵文待使星。", "春郊迴駟牡，遙識故林青。"]'),
('aee3ca29-261b-4a10-9e26-c9b189add436','早秋桐廬思歸示道諺上人','皎然','唐','唐诗','tang','','[]','桐江秋信早，憶在故山時。',48,'全唐诗/poet.tang.44000.json','["桐江秋信早，憶在故山時。", "靜夜風鳴磬，無人竹掃墀。", "猨來觸淨水，鳥下啄寒棃。", "可即關吾事，歸心自有期。"]'),
('625ace04-666e-437e-a936-a227dc8fbef5','勞勞山居寄呈吳處士','皎然','唐','唐诗','tang','','[]','山事繇來別，只應中老身。',48,'全唐诗/poet.tang.44000.json','["山事繇來別，只應中老身。", "寒園掃綻栗，秋浪拾乾薪。", "領鶴閑書竹，誇雲笑向人。", "俗家相去遠，野水作東鄰。"]'),
('ba975704-55d9-4eb3-b676-ed76e0e92f0d','寄報德寺從上人','皎然','唐','唐诗','tang','','[]','宗流許身子，物表養高閑。',48,'全唐诗/poet.tang.44000.json','["宗流許身子，物表養高閑。", "空色清涼寺，秋聲鼓吹山。", "看心水磬後，行道雨花間。", "七葉翻章句，時時啓義關。"]'),
('065d3757-006b-42c4-8489-d1f927495747','山中月夜寄無錫長官','皎然','唐','唐诗','tang','','[]','湖上涼風早，雙峰月色秋。',48,'全唐诗/poet.tang.44000.json','["湖上涼風早，雙峰月色秋。", "遙知秣陵令，今夜在西樓。", "別葉蕭蕭下，含霜處處流。", "如何共清景，異縣不同遊。"]'),
('d67d9d4a-0356-4439-9e1b-436fb42dfbd0','奉賀顏使君真卿二十八郎隔絕自河北遠歸','皎然','唐','唐诗','tang','','[]','相失值氛煙，纔應掌上年。',48,'全唐诗/poet.tang.44000.json','["相失值氛煙，纔應掌上年。", "久離驚貌長，多難喜身全。", "比信尚書重，如威太守憐。", "滿庭看玉樹，更有一枝連。"]'),
('cfac166d-3934-4149-bb77-4d1361f57a5f','題湖上蘭若示清會上人','皎然','唐','唐诗','tang','','[]','峰心惠忍寺，嵊頂謝公山。',48,'全唐诗/poet.tang.44000.json','["峰心惠忍寺，嵊頂謝公山。", "何似南湖近，芳洲一畝間。", "意中雲木秀，事外水堂閑。", "永日無人到，時看獨鶴還。"]'),
('ceef4f3f-70b7-443b-b2ae-45ae11aac8d9','秋宵書事寄吳憑處士','皎然','唐','唐诗','tang','','[]','真性在方丈，寂寥無四鄰。',48,'全唐诗/poet.tang.44000.json','["真性在方丈，寂寥無四鄰。", "秋天月色正，清夜道心真。", "大夢觀前事，浮名悟此身。", "不知庭樹意，榮落感何人。"]'),
('9d0ccf8a-4d43-47e2-a9f5-3699aeaed84c','題山壁示道維上人','皎然','唐','唐诗','tang','','[]','獨居何意足，山色在前門。',48,'全唐诗/poet.tang.44000.json','["獨居何意足，山色在前門。", "身野長無事，心冥自不言。", "閑行數亂竹，靜坐照清源。", "物外從知少，禪徒不耐煩。"]'),
('ea2609ba-ee56-4e2b-afa0-52b1abb966c1','晚秋登佛川南峰懷裴例','皎然','唐','唐诗','tang','','[]','登嶺望落日，眇然傷別魂。',48,'全唐诗/poet.tang.45000.json','["登嶺望落日，眇然傷別魂。", "亭臯秋色徧，遊子在荆門。", "世故東西客，山空斷續猨。", "此心誰復見，寂寞偶芳蓀。"]'),
('6a194bbd-57a8-423b-8275-f6d90f2f9d3f','訪陸處士羽','皎然','唐','唐诗','tang','','["\u592a\u6e56"]','太湖東西路，吳主古山前。',48,'全唐诗/poet.tang.45000.json','["太湖東西路，吳主古山前。", "所思不可見，歸鴻自翩翩。", "何山賞春茗，何處弄春泉。", "莫是滄浪子，悠悠一釣船。"]'),
('266be4f6-6260-4b1e-9f86-beef2c8ff4bc','酬李侍御萼題看心道塲賦以眉毛腸心牙等五字','皎然','唐','唐诗','tang','','[]','我法從誰悟，心師是貫花。',48,'全唐诗/poet.tang.45000.json','["我法從誰悟，心師是貫花。", "三塵觀種子，一雨發萌芽。", "定起輪燈缺，宵分印月斜。", "了空如藏史，始肯會禪家。"]'),
('26add434-21ca-44c0-bc88-35d8861735e9','酬姚補闕南仲雲溪館中戲題隨書見寄','皎然','唐','唐诗','tang','','[]','寺溪臨使府，風景借仁祠。',48,'全唐诗/poet.tang.45000.json','["寺溪臨使府，風景借仁祠。", "補衮周官貴，能名漢主思。", "臥雲知獨處，望月憶同時。", "忽枉緘中贈，瓊瑤滿手持。"]'),
('cae6ab0a-237c-4e21-b48a-5b175721c9df','春夜期裴都曹濟集心上人院不至','皎然','唐','唐诗','tang','','[]','東林期隱吏，日月爲虛盈。',48,'全唐诗/poet.tang.45000.json','["東林期隱吏，日月爲虛盈。", "遠望浮雲隔，空憐定水清。", "逍遙方外侶，荏苒府中情。", "漸聽寒鞞發，淵淵在郡城。"]'),
('e438ac36-0098-48c2-9f19-538b3864b9eb','和裴少府懷京兄弟','皎然','唐','唐诗','tang','','[]','宦遊三楚外，家在五陵原。',48,'全唐诗/poet.tang.45000.json','["宦遊三楚外，家在五陵原。", "涼夜多歸夢，秋風滿故園。", "北書無遠信，西候獨傷魂。", "空念青門別，殷勤岐路言。"]'),
('5827d143-1f3e-4968-95cd-a50208c0659c','和閻士和望池月荅人','皎然','唐','唐诗','tang','','[]','片月忽臨池，雙蛾憶畫時。',48,'全唐诗/poet.tang.45000.json','["片月忽臨池，雙蛾憶畫時。", "光浮空似粉，影散不成眉。", "孤枕應驚夢，寒林正入帷。", "情知兩處望，莫怨獨相思。"]'),
('d2c31d26-e45b-441c-aad5-54f2d24801be','遙和塵外上人與陸澧夜集山寺問湼槃義兼陸生文卷','皎然','唐','唐诗','tang','','[]','共是竹林賢，心從貝葉傳。',48,'全唐诗/poet.tang.45000.json','["共是竹林賢，心從貝葉傳。", "說經看月喻，開卷愛珠連。", "清淨遙城外，蕭疎古塔前。", "應隨北山子，高頂枕雲眠。"]'),
('443e078d-95b3-4650-846b-7de1cd41e6a7','春日和盧使君幼平開元寺聽妙奘上人講','皎然','唐','唐诗','tang','','[]','仁聖垂文在，虛空日月懸。',72,'全唐诗/poet.tang.45000.json','["仁聖垂文在，虛空日月懸。", "陵遲追哲匠，宗旨發幽詮。", "法受諸侯請，心教四子傳。", "春生雪山草，香下棘林天。", "顧我從今日，聞經悟宿緣。", "涼山萬里去，應爲教猶偏。"]'),
('9a07e5e5-a579-4693-abdd-cafb3ed67bfa','荅李侍御問','皎然','唐','唐诗','tang','','[]','入道曾經離亂前，長干古寺住多年。',64,'全唐诗/poet.tang.45000.json','["入道曾經離亂前，長干古寺住多年。", "愛貧唯製蓮花足，取性閑書樹葉篇。", "自笑不歸看石牓，誰高無事弄苔泉。", "身外空名何足問，吾心已出第三禪。"]'),
('8ccc72f0-4e2b-4591-acdc-1b70630167a0','奉酬李員外使君嘉祐蘇臺屏營居春首有懷','皎然','唐','唐诗','tang','','[]','昔歲爲邦初未識，今朝休沐始相親。',64,'全唐诗/poet.tang.45000.json','["昔歲爲邦初未識，今朝休沐始相親。", "移家水巷貧依靜，種柳風窗欲占春。", "詩思先邀烏府客，山情還訪白樓人。", "登臨許作煙霞伴，高在方袍間幅巾。"]'),
('f73594d4-caa0-4115-917f-a9c07e2161dd','和李舍人使君紓題雲明府道室','皎然','唐','唐诗','tang','','[]','許令如今道姓雲，曾經西岳事桐君。',64,'全唐诗/poet.tang.45000.json','["許令如今道姓雲，曾經西岳事桐君。", "流霞手把應憐壽，黃鶴心期擬作羣。", "金籙時教弟子檢，砂牀不遣世人聞。", "桂陽亦是神仙守，分別無嗟兩地分。"]'),
('bff89d79-e08b-4ed4-815b-4843aec821c1','奉和陸中丞使君長源寒食日作','皎然','唐','唐诗','tang','','[]','寒食江天氣最清，庾公晨望動高情。',64,'全唐诗/poet.tang.45000.json','["寒食江天氣最清，庾公晨望動高情。", "因逢內火千家靜，便覩行春萬木榮。", "深淺山容飛雨細，縈紆水態拂雲輕。", "腰章本郡誰相似，數日臨人政已成。"]'),
('21cb9562-b70e-4ec5-a79d-78a68c1be706','奉酬袁使君送陸灞却迴期道寺院','皎然','唐','唐诗','tang','','[]','欲別湖上客，暮期西林還。',36,'全唐诗/poet.tang.45000.json','["欲別湖上客，暮期西林還。", "高歌風音表，放舟月色間。", "更人莫報夜，禪閣本無關。"]'),
('1da61721-336f-4f70-9fe4-fc96d8eb9794','招韓武康章','皎然','唐','唐诗','tang','','[]','山僧雖不飲，酤酒引陶潛。',24,'全唐诗/poet.tang.45000.json','["山僧雖不飲，酤酒引陶潛。", "此意無人別，多爲俗士嫌。"]'),
('6002df1d-0ba7-4497-b370-f3a873600439','秋居法華寺下院望高頂贈如獻上人','皎然','唐','唐诗','tang','','[]','峰色秋天見，松聲靜夜聞。',24,'全唐诗/poet.tang.45000.json','["峰色秋天見，松聲靜夜聞。", "影孤長不出，行道在寒雲。"]'),
('f31c396a-eef7-452f-9f62-b3afdc43c51f','贈韋早陸羽','皎然','唐','唐诗','tang','','[]','只將陶與謝，終日可忘情。',24,'全唐诗/poet.tang.45000.json','["只將陶與謝，終日可忘情。", "不欲多相識，逢人懶道名。"]'),
('8771fe65-6982-444c-8a41-410c25c2b104','戲呈薛彝','皎然','唐','唐诗','tang','','[]','山僧不厭野，才子會須狂。',24,'全唐诗/poet.tang.45000.json','["山僧不厭野，才子會須狂。", "何處銷君興，春風擺綠楊。"]'),
('b8d80a88-b7a2-4e3c-8002-783940ad5901','贈顏主簿','皎然','唐','唐诗','tang','','[]','漢家儀禮盛，名教出諸顏。',24,'全唐诗/poet.tang.45000.json','["漢家儀禮盛，名教出諸顏。", "更見尚書後，能文在子山。"]'),
('6edd2d8d-fbb2-4709-9ea5-e6091d26b3e5','贈融上人','皎然','唐','唐诗','tang','','[]','常愛西林寺，池中月出時。',24,'全唐诗/poet.tang.45000.json','["常愛西林寺，池中月出時。", "芭蕉一片葉，書取寄吾師。"]'),
('d5e803eb-f34f-4b69-ae74-75d05285ecb3','聽寒更寄朱兵曹巨川','皎然','唐','唐诗','tang','','[]','欹枕聽寒更，寒更發還住。',24,'全唐诗/poet.tang.45000.json','["欹枕聽寒更，寒更發還住。", "一夜千萬聲，幾聲到君處。"]'),
('4b4fd7a6-139e-49f3-b28a-e5eb3ffe497f','早春書懷寄李少府仲宣','皎然','唐','唐诗','tang','','[]','早年初問法，因悟目中花。',84,'全唐诗/poet.tang.45000.json','["早年初問法，因悟目中花。", "忽值胡雛起，芟夷如亂麻。", "脫身投彼岸，弔影念生涯。", "跡與空門合，心將世路賒。", "東田已蕪沒，南澗益傷嗟。", "崇替驚人事，凋殘感物華。", "知君過我里，惆悵舊煙霞。"]'),
('c4ce7e08-88c0-4dc0-a2bc-fe504b31a8fa','贈和評事判官','皎然','唐','唐诗','tang','','[]','廷評年少法家流，心似澄江月正秋。',64,'全唐诗/poet.tang.45000.json','["廷評年少法家流，心似澄江月正秋。", "學究天人知遠識，權分鹽鐵許良籌。", "春風憶酒烏家近，好月論禪謝寺幽。", "清白比來誰見賞，憐君獨有富人侯。"]'),
('9419fd9a-b053-4d34-9fc5-4350e10e473c','酬秦系山人題贈','皎然','唐','唐诗','tang','','[]','雲林出空烏未歸，松吹時飄雨浴衣。',32,'全唐诗/poet.tang.45000.json','["雲林出空烏未歸，松吹時飄雨浴衣。", "石語花愁徒自詫，吾心見境盡爲非。"]'),
('1b4023af-9abc-4b0d-bba8-455a4395e39f','酬秦系山人戲贈','皎然','唐','唐诗','tang','','[]','正論禪寂忽狂歌，莫是塵心顛倒多。',32,'全唐诗/poet.tang.45000.json','["正論禪寂忽狂歌，莫是塵心顛倒多。", "白足行花曾不染，黃囊貯酒欲如何。"]'),
('d1be0ebf-036a-41cf-962c-7b20b347f263','貽李湯','皎然','唐','唐诗','tang','','[]','茅氏常論七真記，壺公愛說三山事。',96,'全唐诗/poet.tang.45000.json','["茅氏常論七真記，壺公愛說三山事。", "寧知梅福在人間，獨爲蒼生作仙吏。", "日服丹砂骨自清，膚如冰雪心更明。", "山中玉筍是仙藥，袖裏素書題養生。", "願隨黃鶴一輕舉，仰望青霄獨延佇。", "平生好駿君已知，何必山陰訪王許。"]'),
('2fd1cd3d-a7d6-4fc5-aa55-b13448d9b3b4','述祖德贈湖上諸沈','皎然','唐','唐诗','tang','','[]','我祖文章有盛名，千年海內重嘉聲。',160,'全唐诗/poet.tang.45000.json','["我祖文章有盛名，千年海內重嘉聲。", "雪飛梁苑操奇賦，春發池塘得佳句。", "世業相承及我身，風流自謂過時人。", "初看甲乙矜言語，對客偏能鴝鵒舞。", "飽用黃金無所求，長裾曳地干王侯。", "一朝金盡長裾裂，吾道不行計亦拙。", "歲晚高歌悲苦寒，空堂危坐百憂攢。", "昔時軒蓋金陵下，何處不傳沈與謝。", "綿綿芳籍至今聞，眷眷通宗有數君。", "誰見予心獨飄泊，依山寄水似浮雲。"]'),
('f152c170-82c8-4cc8-a1a7-ce1037f1569e','舟行懷閻士和','皎然','唐','唐诗','tang','','[]','二月湖南春草徧，橫山渡口花如霰。',32,'全唐诗/poet.tang.45000.json','["二月湖南春草徧，橫山渡口花如霰。", "相思一日在孤舟，空見歸雲兩三片。"]'),
('3aa22ac0-3f81-434e-a4ae-468fbf435975','贈張道士','皎然','唐','唐诗','tang','','[]','玉京真子名太一，因服日華心如日。',32,'全唐诗/poet.tang.45000.json','["玉京真子名太一，因服日華心如日。", "此心不許世人知，只向仙宮未曾出。"]'),
('55593b78-8ce4-413b-ab56-cd3d3416e319','戲呈吳馮','皎然','唐','唐诗','tang','','[]','世人不知心是道，只言道在他方妙。',32,'全唐诗/poet.tang.45000.json','["世人不知心是道，只言道在他方妙。", "還如瞽者望長安，長安在西向東笑。"]'),
('1ef3f17a-c05b-45b0-ba05-3135f4cdfed8','宿山寺寄李中丞洪','皎然','唐','唐诗','tang','','[]','偶來中峰宿，閑坐見真境。',52,'全唐诗/poet.tang.45000.json','["偶來中峰宿，閑坐見真境。", "寂寂孤月心，亭亭圓泉影。", "□□□滿山，花落始知靜。", "從他半夜愁猨驚，不廢此心長杳冥。"]'),
('0ad11014-288e-4860-9ac7-e9819470d12f','戲贈吳馮','皎然','唐','唐诗','tang','','[]','予讀古人書，遂識古人面。',56,'全唐诗/poet.tang.45000.json','["予讀古人書，遂識古人面。", "不是識古人，邪正心自見。", "貴義輕財求俗譽，一錢與人便驕倨。", "昨朝爲火今爲冰，此道非君獨撫膺。"]'),
('03cf8eaf-8e37-46cc-99b6-0929eadceb87','感興贈烏程李明府伯宜兼簡諸秀才','皎然','唐','唐诗','tang','','[]','門前峴山近，無路可登陟。',36,'全唐诗/poet.tang.45000.json','["門前峴山近，無路可登陟。", "徒愛峴山高，仰之常歎息。", "不如松與桂，生在重巖側。"]'),
('e9f63abe-1137-4588-a5f6-24de23368c50','晚秋宿李軍道所居','皎然','唐','唐诗','tang','','[]','清溪路不遙，都尉每相招。',48,'全唐诗/poet.tang.45000.json','["清溪路不遙，都尉每相招。", "落日休戎馬，秋風罷射鵰。", "朮花生野徑，柏實滿寒條。", "永夜依山府，禪心共寂寥。"]'),
('98a22f14-aef7-4b95-a305-97ec10ae9c58','送陸判官歸杭州','皎然','唐','唐诗','tang','','[]','芳草潛州路，乘軺憶再旋。',48,'全唐诗/poet.tang.45000.json','["芳草潛州路，乘軺憶再旋。", "餘花故林下，殘月舊池邊。", "峰色雲端寺，潮聲海上天。", "明朝富春渚，應見謝公船。"]'),
('3efe3373-2dd4-4189-a818-4fce16cd49cf','奉和顏使君真卿與陸處士羽登妙喜寺三癸亭','皎然','唐','唐诗','tang','','[]','秋意西山多，列岑縈左次。',132,'全唐诗/poet.tang.45000.json','["秋意西山多，列岑縈左次。", "繕亭歷三癸，疏趾鄰什寺。", "元化隱靈蹤，始君啓高誄。", "誅榛養翹楚，鞭草理芳穗。", "俯砌披水容，逼天掃峰翠。", "境新耳目換，物遠風煙異。", "倚石忘世情，援雲得真意。", "嘉林幸勿剪，禪侶欣可庇。", "衛法大臣過，佐遊羣英萃。", "龍池護清澈，虎節到深邃。", "徒想嵊頂期，於今沒遺記。"]'),
('e45a7251-e7b2-46e5-971c-a55c4c63dbb7','奉陪陸使君長源裴端公樞春遊東西武丘寺','皎然','唐','唐诗','tang','','[]','雲水夾雙剎，遙疑涌平陂。',96,'全唐诗/poet.tang.45000.json','["雲水夾雙剎，遙疑涌平陂。", "入門見藏山，元化何由窺。", "曳組探詭怪，停驄訪幽奇。", "情高氣爲爽，德暖春亦隨。", "瑤草自的皪，蕙樓爭蔽虧。", "金精落壞陵，劒彩沈古池。", "一覽币天界，中峰步未移。", "應嘉生公石，列坐援松枝。"]'),
('6dfb1fe5-5862-4db0-b3dd-977e7a0992ea','奉和陸使君長源夏月遊太湖','皎然','唐','唐诗','tang','','["\u592a\u6e56"]','庾公心曠遠，府事局耳目。',120,'全唐诗/poet.tang.45000.json','["庾公心曠遠，府事局耳目。", "遂與南湖遊，虛襟滌煩燠。", "始知皇天意，積水在亭育。", "細流信不讓，動物欣所蓄。", "萬頃合天容，洗然無雲族。", "峭蒨矚仙嶺，超遙隨明牧。", "知公愛澄清，波靜氣亦肅。", "已見橫流極，況聞長鯨戮。", "中洲暫採蘋，南郡思剖竹。", "向夕分好風，飄然送歸舳。"]'),
('10837c16-9587-4251-84fe-69d822946433','奉和崔中丞使君論李侍御萼登爛柯山宿石橋寺効小謝體','皎然','唐','唐诗','tang','','[]','常愛謝公郡，幽期願相從。',120,'全唐诗/poet.tang.45000.json','["常愛謝公郡，幽期願相從。", "果迴青驄臆，共躡玄仙踪。", "靈境若髣髴，爛柯思再逢。", "飛梁丹霞接，古局蒼苔封。", "往想冥昧理，誰親冰雪容。", "蕙樓聳空界，蓮宇開中峰。", "昔化沖虛鶴，今藏護法龍。", "雲窺香樹沓，月見色天重。", "永夜寄岑寂，清言滌心胸。", "盛遊千年後，書在巖中松。"]'),
('144e8b40-7119-4952-9e37-fde527ad7fb1','同顏使君真卿李侍御萼遊法華寺登鳳翅山望太湖','皎然','唐','唐诗','tang','','["\u592a\u6e56"]','雙峰開鳳翅，秀出南湖州。',98,'全唐诗/poet.tang.45000.json','["雙峰開鳳翅，秀出南湖州。", "地勢抱郊樹，山威增郡樓。", "正逢周柱史，來會魯諸侯。", "緩步凌彩蒨，清鐃發颼飀。", "披雲得靈境，拂石臨芳洲。", "積翠遙空碧，含風廣澤秋。", "蕭辰資麗思，高論驚精修。", "何似鍾山集，[徵]文及惠休。"]'),
('92ca8a87-e2f9-4cdc-8357-21ed2a7972a1','奉陪陸使君長源諸公遊支硎寺','皎然','唐','唐诗','tang','','[]','嘗覽高逸傳，山僧有遺蹤。',84,'全唐诗/poet.tang.45000.json','["嘗覽高逸傳，山僧有遺蹤。", "佐遊繼雅篇，嘉會何繇逢。", "塵世即下界，色天當上峰。", "春暉徧衆草，寒色留高松。", "繚繞彩雲合，參差綺樓重。", "瓊葩灑巾舃，石瀃清心胸。", "靈境若可託，道情知所從。"]'),
('5a6c5797-7ca9-4b01-be84-1d654803d0ae','奉陪鄭使君諤遊太湖至洞庭山登上真觀却望湖水','皎然','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','郡齋得無事，放舟下南湖。',108,'全唐诗/poet.tang.45000.json','["郡齋得無事，放舟下南湖。", "湖中見仙邸，果與心賞俱。", "不遠風物變，忽如寰宇殊。", "背雲視層崖，別是登蓬壺。", "突兀盤水府，參差沓天衢。", "迴瞻平蕪盡，洪流豁中區。", "氣吞江山勢，色淨氛靄無。", "靈長習水德，勝勢當地樞。", "朝宗動歸心，萬里思鴻途。"]'),
('6955a27f-37a1-4b5f-968b-f933ed97805f','奉和袁使君高郡中新亭會張鍊師晝會二上人','皎然','唐','唐诗','tang','','[]','置亭隱城堞，事簡跡易幽。',84,'全唐诗/poet.tang.45000.json','["置亭隱城堞，事簡跡易幽。", "公性崇儉素，雅才非廣求。", "傍簷竹雨清，拂案杉風秋。", "不移府中步，登茲如遠遊。", "坐覺詩思高，俯知物役休。", "虛寂偶禪子，逍遙親道流。", "更聞臨川作，下節安能酬。"]'),
('ec78521c-ea41-4da5-9d14-282471da0d1d','奉和陸使君長源水堂納涼効曹劉體','皎然','唐','唐诗','tang','','[]','柳家陶暑亭，意遠不可齊。',96,'全唐诗/poet.tang.45000.json','["柳家陶暑亭，意遠不可齊。", "煩襟蕩朱弦，高步援綠荑。", "愛公滿亭客，來是清風攜。", "瀅渟前溪上，曠望古郡西。", "六月正中伏，水軒氣常淒。", "野香襲荷芰，道性親鳧鷖。", "禪子顧惠休，逸民重劉黎。", "乃知高世量，不以出處暌。"]'),
('eced748b-2e7b-4991-82e4-5898eb8e8e77','夏日奉陪陸使君長源公堂集','皎然','唐','唐诗','tang','','[]','府中自清遠，六月高梧間。',48,'全唐诗/poet.tang.45000.json','["府中自清遠，六月高梧間。", "寥亮泛雅瑟，逍遙扣玄關。", "嶺雲與人靜，庭鶴隨公閑。", "動息諒兼遂，茲情即東山。"]'),
('1c61ad4f-d648-4851-bc9d-7718e4b99bf8','九日和于使君思上京親故','皎然','唐','唐诗','tang','','[]','霽景滿水國，我公望江城。',48,'全唐诗/poet.tang.45000.json','["霽景滿水國，我公望江城。", "碧山與黃花，爛熳多秋情。", "搖落見松柏，歲寒比忠貞。", "歡娛在鴻都，是日思朝英。"]'),
('916d2a7a-fa6b-43bf-9faa-140f1e79c203','伏日就湯評事衡湖上避暑','皎然','唐','唐诗','tang','','[]','大火方燥石，停雲晝亦收。',72,'全唐诗/poet.tang.45000.json','["大火方燥石，停雲晝亦收。", "將從賞心侶，寸景難遠遊。", "擁几苦炎伏，出門望汀洲。", "迴溪照軒宇，廣陌臨梧楸。", "釋悶命雅瑟，放情思亂流。", "更持無生論，可以清煩憂。"]'),
('5e26809a-d48a-4d15-abe6-ba54c28792e7','奉和顏使君真卿修韻海畢會諸文士東堂重校','皎然','唐','唐诗','tang','','[]','外學宗碩儒，游焉從後進。',84,'全唐诗/poet.tang.45000.json','["外學宗碩儒，游焉從後進。", "恃以仁恕廣，不學門欄峻。", "著書裨理化，奉上表誠信。", "探討始河圖，紛綸歸海韻。", "親承大匠琢，況覩頹波振。", "錯簡記鉛槧，閱書移玉鎮。", "曷繇旌不朽，盛美流歌引。"]'),
('3a48f3f5-6e61-4e22-8da8-0f164e72d54c','喜義興權明府自君山至集陸處士羽青塘別業','皎然','唐','唐诗','tang','','[]','應難久辭秩，暫寄君陽隱。',60,'全唐诗/poet.tang.45000.json','["應難久辭秩，暫寄君陽隱。", "已見縣名花，會逢闈是粉。", "本自尋人至，寧因看竹引。", "身關白雲多，門占春山盡。", "最賞無事心，籬邊釣溪近。"]'),
('f99a4443-293c-43db-afde-7bedd638580e','夏日集李司直縱溪齋','皎然','唐','唐诗','tang','','[]','修景屬良會，遠飆生煩襟。',72,'全唐诗/poet.tang.45000.json','["修景屬良會，遠飆生煩襟。", "泄雲收淨綠，衆木積芳陰。", "疏滌府中務，迢遙湖上心。", "習閑得招我，賞夜宜泛琴。", "山近資性靜，月來寄情深。", "澹然若事外，豈藉隳華簪。"]'),
('daa348f2-e36c-4742-a8d8-2c083162208d','夏日題桐廬楊明府納涼山齋','皎然','唐','唐诗','tang','','[]','陶家無炎暑，自有林中峰。',48,'全唐诗/poet.tang.45000.json','["陶家無炎暑，自有林中峰。", "席上落山影，桐梢迴水容。", "放懷涼風至，緩步清陰重。", "何事親堆案，猶多高世蹤。"]'),
('058af41c-0711-4f11-9a5a-c3e9f19a4df9','和楊明府早秋遊法華寺','皎然','唐','唐诗','tang','','[]','釋事出縣閤，初聞茲山靈。',96,'全唐诗/poet.tang.45000.json','["釋事出縣閤，初聞茲山靈。", "寺扉隱天色，影剎遙丁丁。", "碧峰委合沓，香蔓垂蓂苓。", "清景爲公有，放曠雲邊亭。", "秋賞石潭潔，夜嘉杉月清。", "誦空性不昧，助道跡又經。", "是以於物理，紛然若未形。", "移來字人要，全與此道冥。"]'),
('a74d2e6d-1a6f-470c-92b4-11614201d736','宿道士觀','皎然','唐','唐诗','tang','','[]','古觀秋木秀，冷然屬鮮飆。',60,'全唐诗/poet.tang.45000.json','["古觀秋木秀，冷然屬鮮飆。", "瓊葩被修蔓，柏實滿寒條。", "影殿山寂寂，寥天月昭昭。", "幽期寄仙侶，習定至中宵。", "清佩聞虛步，真官方宿朝。"]'),
('747eba0a-0cbc-406d-9a8f-3e45c60a170a','冬日天井西峰張鍊師所居','皎然','唐','唐诗','tang','','[]','採薪逢野泉，漸見棲閑所。',72,'全唐诗/poet.tang.45000.json','["採薪逢野泉，漸見棲閑所。", "坎坎山上聲，幽幽林中語。", "仙鄉何代隱，鄉服言亦楚。", "開水淨藥苗，掃雪候山侶。", "零葉聚敗籬，幽花積寒渚。", "冥冥孤鶴性，天外思輕舉。"]'),
('4ea14494-6cc2-4c8e-93c5-e1e83816dddc','奉同顏使君真卿開元寺經藏院會觀樹文殊碑','皎然','唐','唐诗','tang','','[]','萬國布殊私，千年降祖師。',48,'全唐诗/poet.tang.45000.json','["萬國布殊私，千年降祖師。", "雁門傳法至，龍藏立言時。", "故實刊周典，新聲播魯詩。", "六銖那更拂，劫石盡無期。"]'),
('39c7a954-06d2-4886-815f-33df6c3ccba2','奉同盧使君幼平遊精舍寺','皎然','唐','唐诗','tang','','[]','影剎西方在，虛空翠色分。',48,'全唐诗/poet.tang.45000.json','["影剎西方在，虛空翠色分。", "人天霽後見，猨鳥定中聞。", "真界隱青壁，春山凌白雲。", "今朝石門會，千古仰斯文。"]'),
('461849d0-d0c0-43f0-a778-89fb40140ace','奉同顏使君真卿袁侍御駱駝橋翫月','皎然','唐','唐诗','tang','','[]','山中常見月，不及共遊時。',48,'全唐诗/poet.tang.45000.json','["山中常見月，不及共遊時。", "水上恐將缺，林端愛落遲。", "烏驚憲府客，人詠鮑家詩。", "永夜南橋望，裴回若有期。"]'),
('588a3bdb-03ab-45c2-89df-2aef3ec414a6','和邢端公登臺春望句句有春字之什','皎然','唐','唐诗','tang','','[]','春日繡衣輕，春臺別有情。',48,'全唐诗/poet.tang.45000.json','["春日繡衣輕，春臺別有情。", "春煙間草色，春鳥隔花聲。", "春樹亂無次，春山遙得名。", "春風正飄蕩，春甕莫須傾。"]'),
('00148577-1689-4ef2-ae7f-9bc484345c53','經仙人渚即沈山下古人沈義白日昇仙處','皎然','唐','唐诗','tang','','[]','日月人間短，何時此得仙。',48,'全唐诗/poet.tang.45000.json','["日月人間短，何時此得仙。", "古山春已盡，遺渚事空傳。", "不見騰雲駕，徒臨洗藥泉。", "如今成逝水，翻使恨流年。"]'),
('c4981d78-fa46-4ecb-a281-4f88075a98aa','獨遊二首 一','皎然','唐','唐诗','tang','','[]','性野趣無端，春晴路又乾。',48,'全唐诗/poet.tang.45000.json','["性野趣無端，春晴路又乾。", "逢泉破石弄，放鶴向雲看。", "好僻誰相似，從狂我自安。", "芳洲亦有意，步上白沙灘。"]'),
('16ea8a69-f21b-42cc-ac32-f59752a88248','獨遊二首 二','皎然','唐','唐诗','tang','','[]','臨水興不盡，虛舟可同嬉。',48,'全唐诗/poet.tang.45000.json','["臨水興不盡，虛舟可同嬉。", "還雲與歸鳥，若共山僧期。", "世事吾不預，此心誰得知。", "西峰有禪老，應見獨遊時。"]'),
('bdf7d9da-1f5e-4ef9-a6be-b210aa5fcf66','遊溪待月','皎然','唐','唐诗','tang','','[]','溪色思泛月，沿洄欲未歸。',48,'全唐诗/poet.tang.45000.json','["溪色思泛月，沿洄欲未歸。", "殘燈逢水店，疎磬憶山扉。", "夜浦魚驚少，空林鵲遶稀。", "可中纔望見，撩亂擣寒衣。"]'),
('c2ed6f9c-5526-4c32-9bc0-bc8f3d272fdb','西溪獨泛','皎然','唐','唐诗','tang','','[]','道情何所居，素舸漫流間。',48,'全唐诗/poet.tang.45000.json','["道情何所居，素舸漫流間。", "真性憐高鶴，無名羨野山。", "經寒叢竹秀，入靜片雲閑。", "泛泛誰爲侶，唯應共月還。"]'),
('a165cb66-168f-4906-8a08-5b4586bc6df9','早秋陪韓明府泛阮元公溪','皎然','唐','唐诗','tang','','[]','雨信清殘暑，蕭條古縣西。',48,'全唐诗/poet.tang.45000.json','["雨信清殘暑，蕭條古縣西。", "早涼生浦溆，秋意滿高低。", "前事雖堆案，閑情得泝溪。", "何言戰未勝，空寂用還齊。"]'),
('039f75f6-1973-49c0-9e88-35f0b4882d4f','九日陪顏使君真卿登水樓','皎然','唐','唐诗','tang','','[]','重陽荆楚尚，高會此難陪。',48,'全唐诗/poet.tang.45000.json','["重陽荆楚尚，高會此難陪。", "偶見登龍客，同遊戲馬臺。", "風文向水疊，雲態擁歌迴。", "持菊煩相問，捫襟媿不才。"]'),
('1f259d08-91cd-4faa-8740-f77e3d195e4a','與盧孟明別後宿南湖對月','皎然','唐','唐诗','tang','','[]','五湖生夜月，千里滿寒流。',48,'全唐诗/poet.tang.45000.json','["五湖生夜月，千里滿寒流。", "曠望煙霞盡，淒涼天地秋。", "相思路渺渺，獨夢水悠悠。", "何處空江上，裴回送客舟。"]'),
('2bc58364-1fb9-43f1-91ce-02bf101db06b','自義亭驛送李長史縱夜泊臨平東湖','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','長亭賓馭散，岐路起悲風。',48,'全唐诗/poet.tang.45000.json','["長亭賓馭散，岐路起悲風。", "千里勤王事，驅車明月中。", "寒生洞庭水，夜度塞門鴻。", "處處堪傷別，歸來山又空。"]'),
('a134d9d7-4a3c-4354-94c4-d28cbaf074b5','出遊','皎然','唐','唐诗','tang','','[]','少時不見山，便覺無奇趣。',36,'全唐诗/poet.tang.45000.json','["少時不見山，便覺無奇趣。", "狂發從亂歌，情來任閑步。", "此心誰共證，笑向風吹樹。"]'),
('4d1bf2bd-7722-4904-b05b-a1f54223b410','界石守風望天竺靈隱二寺','皎然','唐','唐诗','tang','','[]','山頂東西寺，江中旦暮潮。',24,'全唐诗/poet.tang.45000.json','["山頂東西寺，江中旦暮潮。", "歸心不可到，松路在青霄。"]'),
('482a0d82-c168-405d-86f4-083b0a5279f0','奉和顏使君真卿修韻海畢州中重宴','皎然','唐','唐诗','tang','','[]','世學高南郡，身封盛魯邦。',48,'全唐诗/poet.tang.45000.json','["世學高南郡，身封盛魯邦。", "九流宗韻海，七字揖文江。", "借賞雲歸堞，留歡月在窗。", "不知名教樂，千載與誰雙。"]'),
('d1b53657-010b-4711-969f-c489cace7eb5','晦日陪顏使君白蘋洲集','皎然','唐','唐诗','tang','','[]','南朝分古郡，山水似湘東。',48,'全唐诗/poet.tang.45000.json','["南朝分古郡，山水似湘東。", "堤月吳風在，湔裾楚客同。", "桂寒初結斾，蘋小欲成叢。", "時晦佳游促，高歌聽未終。"]'),
('c514d273-5ffb-4e9e-97a1-ca88a4089ca9','冬至日陪裴端公使君清水堂集','皎然','唐','唐诗','tang','','[]','亞歲崇佳宴，華軒照淥波。',48,'全唐诗/poet.tang.45000.json','["亞歲崇佳宴，華軒照淥波。", "渚芳迎氣早，山翠向晴多。", "推往知時訓，書祥辨政和。", "從公惜日短，留賞夜如何。"]'),
('e251843e-76da-430c-949e-eb57d8fdf72a','陪盧判官水堂夜宴','皎然','唐','唐诗','tang','','[]','暑氣當宵盡，裴回坐月前。',48,'全唐诗/poet.tang.45000.json','["暑氣當宵盡，裴回坐月前。", "靜依山堞近，涼入水扉偏。", "久是棲林客，初逢佐幕賢。", "愛君高野意，烹茗釣淪漣。"]'),
('2e1a7b90-3797-4d42-b417-955929adf2b8','新秋同盧侍御薛員外白蘋洲月夜','皎然','唐','唐诗','tang','','[]','隔暑蘋洲近，迎涼欲泛舟。',48,'全唐诗/poet.tang.45000.json','["隔暑蘋洲近，迎涼欲泛舟。", "榮從憲府至，喜會夕郎遊。", "氣奪滄浪色，風欺汗漫流。", "誰言三伏夜，獨此月前秋。"]'),
('ba140ceb-52a5-4e61-8638-2752d36c2b5d','夏日集裴錄事北亭避暑','皎然','唐','唐诗','tang','','[]','前林夏雨歇，爲我生涼風。',48,'全唐诗/poet.tang.45000.json','["前林夏雨歇，爲我生涼風。", "一室煩暑外，衆山清景中。", "忘歸親野水，適性許雲鴻。", "蕭散都曹吏，還將靜者同。"]'),
('9089124b-cc0b-4c73-9ed6-0fde025402c5','與王錄事會張徵君姊妹鍊師院翫雪兼懷清會上人','皎然','唐','唐诗','tang','','[]','何意廉從事，還來會默仙。',48,'全唐诗/poet.tang.45000.json','["何意廉從事，還來會默仙。", "寒空驚雪徧，春意入歌偏。", "瑤草三花發，瓊林七葉連。", "飄颻過柳寺，應滿譯經前。"]'),
('7e11e0e1-e387-49ca-82ca-9192b10275ba','和李侍御萼歲初夜集處士書閣','皎然','唐','唐诗','tang','','[]','遲賢心置閣，高意此郊居。',48,'全唐诗/poet.tang.45000.json','["遲賢心置閣，高意此郊居。", "古徑行春早，新窗見月初。", "放歌還倚瑟，講道亦觀書。", "爲我留禪位，來逢此會疎。"]'),
('67ee9790-feb6-464f-9867-7bb5deca29a3','湯評事衡水亭會覺禪師','皎然','唐','唐诗','tang','','[]','山侶相逢少，清晨會水亭。',48,'全唐诗/poet.tang.45000.json','["山侶相逢少，清晨會水亭。", "雪晴松葉翠，煙暖藥苗青。", "靜對滄洲鶴，閑看古寺經。", "應憐叩關子，了義共心冥。"]'),
('8ab2763a-0c33-4c93-8fa5-c19bd50904cd','與朝陽山人張朝夜集湖亭賦得各言其志','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭孤月在，秋色望無邊。',48,'全唐诗/poet.tang.45000.json','["洞庭孤月在，秋色望無邊。", "零露積衰草，寒螿鳴古田。", "茫茫區中想，寂寂塵外緣。", "從此悟浮世，胡爲傷暮年。"]'),
('c17be4a5-897c-4042-968b-bd47ab088643','晦夜李侍御萼宅集招潘述湯衡海上人飲茶賦','皎然','唐','唐诗','tang','','[]','晦夜不生月，琴軒猶爲開。',48,'全唐诗/poet.tang.45000.json','["晦夜不生月，琴軒猶爲開。", "墻東隱者在，淇上逸僧來。", "茗愛傳花飲，詩看卷素裁。", "風流高此會，曉景屢裴回。"]'),
('1827e6bc-7165-4d01-be72-2dba106bde6b','寄昱上人上方居','皎然','唐','唐诗','tang','','[]','厭向人間住，逢山欲懶歸。',48,'全唐诗/poet.tang.45000.json','["厭向人間住，逢山欲懶歸。", "片雲閑似我，日日在禪扉。", "地靜松陰徧，門空鳥語稀。", "夜涼疎磬盡，師友自相依。"]'),
('1e620d71-ca49-4c19-bb6d-1c8666de7ad5','夏日與綦毋居士昱上人納涼','皎然','唐','唐诗','tang','','[]','爲依爐峰住，境勝增道情。',48,'全唐诗/poet.tang.45000.json','["爲依爐峰住，境勝增道情。", "涼日暑不變，空門風自清。", "坐援香實近，轉愛綠蕪生。", "宗炳青霞士，如何知我名。"]'),
('6cf38d83-ee7f-4f5d-b670-c2115430cb34','建元寺集皇甫侍御書閣','皎然','唐','唐诗','tang','','[]','不因居佛里，無事得相逢。',48,'全唐诗/poet.tang.45000.json','["不因居佛里，無事得相逢。", "名重朝端望，身高俗外蹤。", "機閑看淨水，境寂聽疎鐘。", "宣室恩長在，知君志未從。"]'),
('af34f329-2874-4117-977d-b34dd5625b48','郭北尋徐主簿別業','皎然','唐','唐诗','tang','','[]','近依城北住，幽遠少人知。',48,'全唐诗/poet.tang.45000.json','["近依城北住，幽遠少人知。", "積雪行深巷，閑雲繞古籬。", "竹花冬更發，橙實晚仍垂。", "還共巖中鶴，今朝下淥池。"]'),
('20899a0e-5908-485d-93da-593e01c572da','題報德寺清幽上人西峰','皎然','唐','唐诗','tang','','[]','陳世凋亡後，仁祠識舊山。',48,'全唐诗/poet.tang.45000.json','["陳世凋亡後，仁祠識舊山。", "帝鄉喬木在，空見白雲還。", "雙塔寒林外，三陵暮雨間。", "此中難戰勝，君獨啓禪關。"]'),
('2a70afd0-2a5e-4580-a511-4bfe77d229f6','題鄭谷江畔桐齋','皎然','唐','唐诗','tang','','[]','客齋開別住，坐占綠江濆。',48,'全唐诗/poet.tang.45000.json','["客齋開別住，坐占綠江濆。", "流水非外物，閑雲長屬君。", "浮榮未可累，曠達若爲羣。", "風起高梧下，清弦日日聞。"]'),
('73bd06a0-e5b1-4a6e-aaf4-666792e20efa','和閻士和李蕙冬夜重集','皎然','唐','唐诗','tang','','[]','郡理日閑曠，洗心宿香峰。',48,'全唐诗/poet.tang.45000.json','["郡理日閑曠，洗心宿香峰。", "雙林秋見月，萬壑靜聞鐘。", "珮玉行山翠，交麾動水容。", "如何股肱守，塵外得相從。"]'),
('21729050-31ef-4fa3-8dfb-cc7ce524225c','春日陪顏使君真卿皇甫曾西亭重會韻海諸生','皎然','唐','唐诗','tang','','[]','爲重南臺客，朝朝會魯儒。',48,'全唐诗/poet.tang.45000.json','["爲重南臺客，朝朝會魯儒。", "暄風衆木變，清景片雲無。", "峰翠飄簷下，溪光照座隅。", "不將簪艾隔，知與道情俱。"]'),
('1c56ba10-a01b-4cff-9a74-528e69ca54d3','寒食日同陸處士行報德寺宿解公房','皎然','唐','唐诗','tang','','[]','古寺章陵下，潛公住幾年。',48,'全唐诗/poet.tang.45000.json','["古寺章陵下，潛公住幾年。", "安心生輭草，灌頂引春泉。", "寂寂傳燈地，寥寥禁火天。", "世間多暗室，白日爲誰懸。"]'),
('6a9a70f9-1a52-4e48-8327-d14e2f94af41','兵馬曹季良宅夜集','皎然','唐','唐诗','tang','','[]','清景不可失，尋君趣有餘。',72,'全唐诗/poet.tang.45000.json','["清景不可失，尋君趣有餘。", "身高避事後，道長問心初。", "出處名則異，遊從跡何疎。", "吟看刻盡燭，笑卷讀殘書。", "露彩生筆硯，風音入庭除。", "平明仙侶散，觳觫動迴車。"]'),
('498fbb85-8e95-41cf-9320-31baa99f5049','同李侍御萼李判官集陸處士羽新宅','皎然','唐','唐诗','tang','','[]','素風千戶敵，新語陸生能。',72,'全唐诗/poet.tang.45000.json','["素風千戶敵，新語陸生能。", "借宅心常遠，移籬力更弘。", "釣絲初種竹，衣帶近裁藤。", "戎佐推兄弟，詩流得友朋。", "柳陰容過客，花徑許招僧。", "不爲墻東隱，人家到未曾。"]'),
('f75a1947-d95a-4243-bcc8-67e306914348','題報恩寺惟照上人房','皎然','唐','唐诗','tang','','[]','上界雨色乾，涼宮日遲遲。',60,'全唐诗/poet.tang.45000.json','["上界雨色乾，涼宮日遲遲。", "水文披菡萏，山翠動罘罳。", "中有清真子，愔愔步閑墀。", "手縈頗黎縷，願證黃金姿。", "旋草堦下生，看心當此時。"]'),
('54f33f90-b7d7-43e1-a340-33167ea05bcf','尋天目徐君','皎然','唐','唐诗','tang','','[]','常見仙翁變姓名，豈知松子號初平。',64,'全唐诗/poet.tang.45000.json','["常見仙翁變姓名，豈知松子號初平。", "逢人不道往來處，賣藥還將雞犬行。", "獨鶴天邊俱得性，浮雲世上共無情。", "三花落地君猶在，笑撫安期昨日生。"]'),
('3d6c53ef-dfc3-41c7-aad3-36ef946709fa','同李著作縱題塵外上人院','皎然','唐','唐诗','tang','','[]','百緣唯有什公瓶，萬法但看一字經。',64,'全唐诗/poet.tang.45000.json','["百緣唯有什公瓶，萬法但看一字經。", "從遣鳥喧心不動，任教香醉境常冥。", "蓮花天晝浮雲卷，貝葉宮春好月停。", "禪伴欲邀何著作，空音宜向夜中聽。"]'),
('0b222621-d127-4df5-b8a9-c1499378aa19','題周諫別業','皎然','唐','唐诗','tang','','[]','隱身苕上欲如何，不著青袍愛綠蘿。',64,'全唐诗/poet.tang.45000.json','["隱身苕上欲如何，不著青袍愛綠蘿。", "柳巷任疎容馬入，水籬從破許船過。", "昂藏獨鶴閑心遠，寂歷秋花野意多。", "若訪禪齋遙可見，竹窗書幌共煙波。"]'),
('28b7720d-a738-4d2b-b713-20e395c0de75','同李中丞洪水亭夜集','皎然','唐','唐诗','tang','','[]','佳人但莫吹參差，正憐月色生酒巵。',32,'全唐诗/poet.tang.45000.json','["佳人但莫吹參差，正憐月色生酒巵。", "山公取醉不關我，爲愛尊前白鷺鶿。"]'),
('d11823fe-453a-4fe1-a0cd-985a7a328ce9','題秦系山人麗句亭','皎然','唐','唐诗','tang','','[]','獨將詩教領諸生，但看青山不愛名。',32,'全唐诗/poet.tang.45000.json','["獨將詩教領諸生，但看青山不愛名。", "滿院竹聲堪愈疾，亂牀花片足忘情。"]'),
('96b6e211-3145-43ac-989a-90646f04b0d2','春夜集陸處士居翫月','皎然','唐','唐诗','tang','','[]','欲賞芳菲肯待辰，忘情人訪有情人。',32,'全唐诗/poet.tang.45000.json','["欲賞芳菲肯待辰，忘情人訪有情人。", "西林可是無清景，祗爲忘情不記春。"]'),
('bc174219-f611-4024-8870-625b9f426ea5','寄題雲門寺梵月無側房','皎然','唐','唐诗','tang','','[]','越山千萬雲門絕，西僧貌古還名月。',32,'全唐诗/poet.tang.45000.json','["越山千萬雲門絕，西僧貌古還名月。", "清朝掃石行道歸，林下眠禪看松雪。"]'),
('6d861c19-984d-4c03-b441-167e99ca9c2c','法華寺上方題江上人禪空','皎然','唐','唐诗','tang','','[]','路入松聲遠更奇，山光水色共參差。',32,'全唐诗/poet.tang.45000.json','["路入松聲遠更奇，山光水色共參差。", "中峰禪寂一僧在，坐對梁朝老桂枝。"]'),
('8712a9d5-1263-4584-9e47-f6e0234ca731','冬日山行過薛徵君','皎然','唐','唐诗','tang','','[]','我行倦修坂，四顧無平陸。',72,'全唐诗/poet.tang.45000.json','["我行倦修坂，四顧無平陸。", "雨霽鳴鷹鸇，天寒聚麋鹿。", "幽人訪名士，家在南岡曲。", "菜實縈小園，稻花遶山屋。", "深居寡憂悔，勝境怡耳目。", "徵心尚與我，永言謝浮俗。"]'),
('f8e32064-bcb3-41ca-ad12-5a40f34bb4a0','往丹陽尋陸處士不遇','皎然','唐','唐诗','tang','','[]','遠客殊未歸，我來幾惆悵。',108,'全唐诗/poet.tang.45000.json','["遠客殊未歸，我來幾惆悵。", "叩關一日不見人，繞屋寒花笑相向。", "寒花寂寂徧荒阡，柳色蕭蕭愁暮蟬。", "行人無數不相識，獨立雲陽古驛邊。", "鳳翅山中思本寺，魚竿村口望歸船。", "歸船不見見寒煙，離心遠水共悠然。", "他日相期那可定，閑僧著處即經年。"]'),
('d1906765-01c9-4567-857d-716acaf87341','集湯評事衡湖上望微雨','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蒼涼遠景中，雨色緣山有。',36,'全唐诗/poet.tang.45000.json','["蒼涼遠景中，雨色緣山有。", "雲送滿洞庭，風吹繞楊柳。", "蕭蕭解輕袂，盡日隨林叟。"]'),
('ad2dc5eb-1d86-45ff-bf5f-11d0844c3c52','九日與陸處士羽飲茶','皎然','唐','唐诗','tang','','[]','九日山僧院，東籬菊也黃。',24,'全唐诗/poet.tang.45000.json','["九日山僧院，東籬菊也黃。", "俗人多泛酒，誰解助茶香。"]'),
('021c0196-f295-4ddb-b2c9-d6c54735c1cb','夜過康錄事造會兄弟','皎然','唐','唐诗','tang','','[]','愛君門館夜來清，瓊樹雙枝是弟兄。',32,'全唐诗/poet.tang.45000.json','["愛君門館夜來清，瓊樹雙枝是弟兄。", "月在詩家偏足思，風過客位更多情。"]'),
('41f0ddee-825d-4060-9ef9-b05888155f32','題沈少府書齋','皎然','唐','唐诗','tang','','[]','不下南昌縣，書齋每日閑。',48,'全唐诗/poet.tang.45000.json','["不下南昌縣，書齋每日閑。", "野花當砌落，溪鳥遂人還。", "有興常臨水，無時不見山。", "千峰數可盡，不出小窗間。"]'),
('35811b12-3828-42e8-8bc1-384b8cdfc57b','春夜與諸公同宴呈陸郎中','皎然','唐','唐诗','tang','','[]','南國宴佳賓，交情老倍親。',48,'全唐诗/poet.tang.45000.json','["南國宴佳賓，交情老倍親。", "月慙紅淚燭，花笑白頭人。", "寶瑟絚餘怨，瓊枝不讓春。", "更聞歌子夜，桃李豔妝新。"]'),
('e549f0c3-e351-42ba-b739-c49b62bb8680','九日阻雨簡高侍御','皎然','唐','唐诗','tang','','[]','江上重雲起，何曾裛□塵。',48,'全唐诗/poet.tang.45000.json','["江上重雲起，何曾裛□塵。", "不能成落帽，翻欲更摧巾。", "素髮閑依枕，黃花暗待人。", "且應攜下價，芒屨就諸鄰。"]'),
('9fab5260-1455-49e8-868a-9ac4fb558bfd','晚春尋桃源觀','皎然','唐','唐诗','tang','','[]','武陵何處訪仙鄉，古觀雲根路已荒。',64,'全唐诗/poet.tang.45000.json','["武陵何處訪仙鄉，古觀雲根路已荒。", "細草擁壇人跡絕，落花沈磵水流香。", "山深有雨寒猶在，松老無風韻亦長。", "全覺此身離俗境，玄機亦可照迷方。"]'),
('3a4bef6d-003b-4b4b-9add-8e87825166cd','同盧使君幼平郊外送閻侍御歸臺','皎然','唐','唐诗','tang','','[]','留餞飛旌駐，離亭草色間。',72,'全唐诗/poet.tang.45000.json','["留餞飛旌駐，離亭草色間。", "柏臺今上客，竹使舊朝班。", "日落東西水，天寒遠近山。", "古江分楚望，殘柳入隋關。", "戀闕心常積，迴軒日不閑。", "芳辰倚門道，猶得及春還。"]'),
('1478521e-b545-4d8c-9775-c9063f3f7c70','送梁拾遺肅歸朝','皎然','唐','唐诗','tang','','[]','明主重文諫，才臣出江東。',84,'全唐诗/poet.tang.45000.json','["明主重文諫，才臣出江東。", "束書辭東山，改服臨北風。", "萬里望皇邑，九重當曙空。", "天開芙蓉闕，日上蒲桃宮。", "天子初未起，金閨籍先通。", "身逢軒轅世，名貴鴛鸞中。", "故人榮此別，何用悲絲桐。"]'),
('62514170-aa7c-4664-afd8-6bddb4b6c65e','奉陪楊使君頊送段校書赴南海幕','皎然','唐','唐诗','tang','','[]','碩賢靜廣州，信爲天下貞。',96,'全唐诗/poet.tang.45000.json','["碩賢靜廣州，信爲天下貞。", "屈茲大將佐，藉彼延閣英。", "聲動柳吳興，郊餞意不輕。", "吾知段夫子，高論關蒼生。", "處以得爲藩，出則道可行。", "遙知南樓會，新景當詩情。", "天高林瘴洗，秋遠海色清。", "時泰罷飛檄，唯應頌公成。"]'),
('832673b1-038f-4eda-bc92-10b938233652','送陸侍御士佳赴上京','皎然','唐','唐诗','tang','','[]','長安三千里，喜行不言永。',72,'全唐诗/poet.tang.45000.json','["長安三千里，喜行不言永。", "清路黃塵飛，大河滄流靜。", "更懷西川府，主公昔和鼎。", "伊鬱瑤瑟情，威遲花驄影。", "此時已難別，日又無停景。", "出餞闕相從，心隨過前嶺。"]'),
('26f2689d-0bfc-4b06-b78f-5486bd4ddad2','奉陪顏使君真卿登峴山送張侍御嚴歸臺','皎然','唐','唐诗','tang','','[]','峴首千里情，北轅自茲發。',72,'全唐诗/poet.tang.45000.json','["峴首千里情，北轅自茲發。", "煙霞正登覽，簪筆限趨謁。", "黃鶴望天衢，白雲歸帝闕。", "客心南浦柳，離思西樓月。", "留賞景不延，感時芳易歇。", "他晨有山信，一爲訪林樾。"]'),
('8161a068-be19-4104-a253-41c822f3774b','酬元主簿子球別贈','皎然','唐','唐诗','tang','','[]','故人方遠適，訪我陳別情。',132,'全唐诗/poet.tang.45000.json','["故人方遠適，訪我陳別情。", "此夜偶禪室，一言了無生。", "覽君緘中寶，如搴清玉瑛。", "胡爲蘊高價，歲晚徒營營。", "辭秩貧且病，何人見艱貞。", "出無黃金橐，空歌白苧行。", "威遲策駑馬，獨望故關樹。", "渺渺千里心，春風起中路。", "近聞新拜命，鸞鳳猶棲棘。", "勸君寄一枝，且養冥冥翼。", "甘泉多竹花，明年待君食。"]'),
('2516d4b3-0226-4238-8134-d7d4e84a86d7','荅道素上人別','皎然','唐','唐诗','tang','','[]','春色徧遠道，寂寞閩中行。',168,'全唐诗/poet.tang.45000.json','["春色徧遠道，寂寞閩中行。", "碧水何渺渺，白雲亦英英。", "離人不可望，日暮芳洲情。", "黃鶴有逸翮，翹首白雲傾。", "欲爲山中侶，肯祕遼天聲。", "藍縷真子褐，葳蕤近臣纓。", "以茲奪爾懷，常恐道不成。", "吾門弟子中，不減惠休名。", "一性研已遠，五言功更精。", "從君汗漫遊，莫廢學無生。", "忍草肯搖落，禪枝不枯榮。", "采采慰長路，知吾心不輕。", "幻情有去住，真性無離別。", "留取老桂枝，歸來共攀折。"]'),
('cc888ce8-b4db-485c-9855-061b240845e0','霅溪館送韓明府章辭滿歸','皎然','唐','唐诗','tang','','[]','洛令從告還，故人東門餞。',60,'全唐诗/poet.tang.45000.json','["洛令從告還，故人東門餞。", "惠愛三年積，軒車一夜遠。", "曉月離館空，秋風故山晚。", "榮君有嘉薦，顧我阻遊衍。", "宿昔峰頂心，依依不可卷。"]'),
('33cf667a-649b-4f76-9009-48b6172cf325','送穆寂赴舉','皎然','唐','唐诗','tang','','[]','天子錫玄纁，傾山禮隱淪。',96,'全唐诗/poet.tang.45000.json','["天子錫玄纁，傾山禮隱淪。", "君拋青霞去，榮資觀國賓。", "劒光既陸離，瓊彩何璘玢。", "夙駕別情遠，商弦秋意新。", "冥冥鴻鵠姿，數尺看蒼旻。", "殘寇近宋郊，西行惡飆塵。", "立身素耿介，處難思經綸。", "春府搜才日，高科得一人。"]'),
('2f59e15b-fd8d-48a8-a994-e478501e2d0e','送張彝歸長沙','皎然','唐','唐诗','tang','','[]','早聞凌雲彩，謂在鴛鷺儔。',96,'全唐诗/poet.tang.45000.json','["早聞凌雲彩，謂在鴛鷺儔。", "華髮始相遇，滄江仍旅遊。", "策名忘苟進，澹慮輕所求。", "常服遠遊誡，緬懷經世謀。", "片帆背風渚，萬里還湘洲。", "別望荆雲積，歸心漢水流。", "蘭苕行采采，桂櫂思悠悠。", "宿昔無機者，爲君動離憂。"]'),
('eacea3d6-d9cd-4f35-836d-8b27480a3fc2','秋日毘陵南寺送潘述之揚州','皎然','唐','唐诗','tang','','[]','孤客秋易傷，嘶蟬靜仍續。',84,'全唐诗/poet.tang.45000.json','["孤客秋易傷，嘶蟬靜仍續。", "佳晨亦已屢，歡會常不足。", "禪地非路岐，我心豈羈束。", "情生遠別時，坐恨清景促。", "望中千里隔，暮歸西山曲。", "蕭條月中道，彩蒨原上綠。", "不見同心人，幽懷增躑躅。"]'),
('50bd8261-d9b9-4f9b-9c4e-7520bfb16325','春日又送潘述之揚州','皎然','唐','唐诗','tang','','[]','別渚望邗城，岐路春日徧。',72,'全唐诗/poet.tang.45000.json','["別渚望邗城，岐路春日徧。", "柔風吹楊柳，芳景流郊甸。", "日日東林期，今夕異鄉縣。", "文房曠佳士，禪室阻清盼。", "離恨奪賞心，不得諧所願。", "莫憶山中人，碧雲遙可見。"]'),
('aca00475-41bd-4e9e-a4f6-5419b625d36d','新秋送盧判官','皎然','唐','唐诗','tang','','[]','故人念宿昔，欲別增遠情。',48,'全唐诗/poet.tang.45000.json','["故人念宿昔，欲別增遠情。", "入座炎氣屏，爲君秋景清。", "繇來空山客，不怨離弦聲。", "唯有暮蟬起，相思碧雲生。"]'),
('dd23f806-a8a0-4636-8a7c-03be30ef8f7d','奉送袁高使君詔徵赴行在效曹劉體','皎然','唐','唐诗','tang','','[]','皇心亭毒廣，蝥賊皆陶甄。',120,'全唐诗/poet.tang.45000.json','["皇心亭毒廣，蝥賊皆陶甄。", "未刈蚩尤旗，方同軒后年。", "天子幸漢中，轘轅阻氛煙。", "璽書召幕牧，名在列岳仙。", "國難倚長城，廟謀資大賢。", "清損休汝騎，仁留述職篇。", "遐路渺天末，繁笳思河邊。", "飾徒促遠期，祗命赴急宣。", "謏才豈足稱，深仁顧何偏。", "那堪臨流意，千里望旗旃。"]'),
('14d659d5-e351-4d2f-9bca-2918e6873fb4','奉送陸中丞長源詔徵入朝','皎然','唐','唐诗','tang','','[]','詔下酇侯幕，徵賢寵上勳。',72,'全唐诗/poet.tang.45000.json','["詔下酇侯幕，徵賢寵上勳。", "才當持漢典，道可至堯君。", "藩牧今榮餞，詩流此盛文。", "水從吳渚別，樹向楚門分。", "宿寺期嘉月，看山識故雲。", "歸心復何奈，怊悵在江濆。"]'),
('12bba4b4-3689-4142-9366-1334d7305fc8','奉送李中丞道昌入朝','皎然','唐','唐诗','tang','','[]','文憲中司盛，恩榮外鎮崇。',72,'全唐诗/poet.tang.45000.json','["文憲中司盛，恩榮外鎮崇。", "諸侯皆取則，八使獨推功。", "詔喜新銜鳳，車看舊飾熊。", "去思今武子，餘教昔文翁。", "清在如江水，仁留是國風。", "光徵二千石，掃第望司空。"]'),
('3cf59638-deea-4b7e-b6e6-e90266fe4a70','冬日送顏延之明府撫州覲叔父','皎然','唐','唐诗','tang','','[]','臨川千里別，惆悵上津橋。',72,'全唐诗/poet.tang.45000.json','["臨川千里別，惆悵上津橋。", "日暮人歸盡，山空雪未消。", "鄉雲心渺渺，楚水路遙遙。", "林下方歡會，山中獨寂寥。", "天寒驚斷鴈，江信望迴潮。", "歲晚流芳歇，思君在此宵。"]'),
('a15bf243-f953-4f89-b66f-9143b5e47645','送關小師還金陵','皎然','唐','唐诗','tang','','[]','如何有歸思，愛別欲忘難。',48,'全唐诗/poet.tang.45000.json','["如何有歸思，愛別欲忘難。", "白鷺沙洲晚，青龍水寺寒。", "蕉花鋪淨地，桂子落空壇。", "持此心爲境，應堪月夜看。"]'),
('78063f93-fa73-41bd-91fb-55554f27c210','峴山送裴秀才赴舉','皎然','唐','唐诗','tang','','[]','漢家招秀士，峴上送君行。',48,'全唐诗/poet.tang.45000.json','["漢家招秀士，峴上送君行。", "萬里見秋色，兩河傷遠情。", "王師出西鎬，虜寇避東平。", "天府登名後，迴看楚水清。"]'),
('1a759495-20b9-4da4-8905-bd32aa2be24c','酬別襄陽詩僧少微','皎然','唐','唐诗','tang','','[]','證心何有夢，示說夢歸頻。',48,'全唐诗/poet.tang.45000.json','["證心何有夢，示說夢歸頻。", "文字齎秦本，詩騷學楚人。", "蘭開衣上色，柳向手中春。", "別後須相見，浮雲是我身。"]'),
('dbad6d4f-0e8c-4418-acd9-c215f801476a','送契上人遊揚州','皎然','唐','唐诗','tang','','[]','西陵古江口，遠見東揚州。',48,'全唐诗/poet.tang.45000.json','["西陵古江口，遠見東揚州。", "淥水不同泛，春山應獨遊。", "尋僧白巖寺，望月謝家樓。", "宿昔心期在，人寰非久留。"]'),
('86bc6eb7-4e17-4174-9a17-877b3f6b8dbd','送德清衛明府赴選','皎然','唐','唐诗','tang','','[]','八使慎求能，東人獨薦君。',48,'全唐诗/poet.tang.45000.json','["八使慎求能，東人獨薦君。", "身猶千里限，名已九霄聞。", "遠路翻喜別，離言暫惜分。", "鳳門多士會，擁佩入卿雲。"]'),
('3571ccea-faa3-42ec-bb60-33cbb4d2f112','送鄭孝廉淮西覲省','皎然','唐','唐诗','tang','','[]','離袂翠華滿，晨羞欲早行。',48,'全唐诗/poet.tang.45000.json','["離袂翠華滿，晨羞欲早行。", "春風生楚樹，曉角發隋城。", "野靄濕衣彩，江鴻增客情。", "征途不用戒，坐見白波清。"]'),
('14619596-c358-46df-9d2e-73055d921797','送沈秀才之閩中','皎然','唐','唐诗','tang','','[]','越客不成歌，春風起淥波。',48,'全唐诗/poet.tang.45000.json','["越客不成歌，春風起淥波。", "嶺重寒不到，海近瘴偏多。", "野戍桄榔發，人家翡翠過。", "翻疑此中好，君問定如何。"]'),
('09aaf32b-3623-4c87-a46e-36a12b7a31d3','送清會上人遊京','皎然','唐','唐诗','tang','','[]','佳遊限衰疾，一笑向西風。',48,'全唐诗/poet.tang.45000.json','["佳遊限衰疾，一笑向西風。", "思見青門外，曾臨素滻東。", "峰明雲際寺，日出露寒宮。", "行道禪長在，香塵不染空。"]'),
('af62f9e2-faf7-410c-8315-5a1e186e475e','送沈居士還太原','皎然','唐','唐诗','tang','','[]','辭宮因世難，家族盛南朝。',48,'全唐诗/poet.tang.45000.json','["辭宮因世難，家族盛南朝。", "名重郊居賦，才高獨酌謠。", "浪花飄一葉，峰色向三條。", "高逸雖成性，弓旌肯忘招。"]'),
('31c51111-e82a-452f-bf20-7ba6be083999','同顏使君真卿峴山送李法曹陽冰西上獻書時會有詔徵赴京','皎然','唐','唐诗','tang','','[]','漢日中郎妙，周王太史才。',48,'全唐诗/poet.tang.45000.json','["漢日中郎妙，周王太史才。", "雲書捧日去，鶴版下天來。", "草見吳洲發，花思御苑開。", "羊公惜風景，欲別幾遲迴。"]'),
('5e20e345-189b-456a-b2ea-96e2bf078290','兵後送姚太祝赴選','皎然','唐','唐诗','tang','','[]','兩河兵已偃，處處見歸舟。',48,'全唐诗/poet.tang.45000.json','["兩河兵已偃，處處見歸舟。", "日夜故人散，江臯芳樹秋。", "楚雲傷遠思，秦月憶佳遊。", "名動春官籍，翩翩才少儔。"]'),
('786d2b48-9685-4b38-8d5d-01d29ad520ad','兵後送薛居士移家安吉','皎然','唐','唐诗','tang','','[]','舊遊經喪亂，道在復何人。',48,'全唐诗/poet.tang.45000.json','["舊遊經喪亂，道在復何人。", "寒草心易折，閑雲性常真。", "交情別後見，詩句比來新。", "向我桃州住，惜君東嶺春。"]'),
('98313de0-45fd-415a-8f3f-696c724b8b81','送鄥傪之洪州覲兄弟','皎然','唐','唐诗','tang','','[]','年少足詩情，西江楚月清。',48,'全唐诗/poet.tang.45000.json','["年少足詩情，西江楚月清。", "書囊山翠濕，琴匣雪花輕。", "久別經離亂，新正憶弟兄。", "贈君題樂府，爲是豫章行。"]'),
('38c3862f-78a6-4d3c-b1d6-27327b5eeeff','送乾封李成','皎然','唐','唐诗','tang','','[]','羽檄飛未息，離情遠近同。',48,'全唐诗/poet.tang.45000.json','["羽檄飛未息，離情遠近同。", "感君繇泛瑟，關我是征鴻。", "眇默歸人盡，疎蕪夜渡空。", "還期當歲晚，獨在路行中。"]'),
('dc1a9ede-8c1a-4380-9307-a5a5c23e7b01','送崔判官還揚子','皎然','唐','唐诗','tang','','[]','輕傳祗遠役，依依下姑亭。',36,'全唐诗/poet.tang.45000.json','["輕傳祗遠役，依依下姑亭。", "秋聲滿楊柳，暮色繞郊坰。", "煙水搖歸思，山當楚驛青。"]'),
('a0651c69-b3f0-46c1-a65c-b11b67e530a2','奉酬袁使君西樓餞秦山人與晝同赴李侍御招三韻','皎然','唐','唐诗','tang','','[]','秋風怨別情，江守上西城。',36,'全唐诗/poet.tang.45000.json','["秋風怨別情，江守上西城。", "竹暑寒流淺，琴窗宿雨晴。", "治書招遠意，知共楚狂行。"]'),
('de64380f-bcb1-48b3-b6af-1709de80b037','送清涼上人','皎然','唐','唐诗','tang','','[]','何意欲歸山，道高繇境勝。',36,'全唐诗/poet.tang.45000.json','["何意欲歸山，道高繇境勝。", "花空覺性了，月盡知心證。", "永夜出禪吟，清猨自相應。"]'),
('09758709-4129-4b11-a298-0cd001955934','送李丞使宣州','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','結駟何翩翩，落葉暗寒渚。',36,'全唐诗/poet.tang.45000.json','["結駟何翩翩，落葉暗寒渚。", "夢裏春穀泉，愁中洞庭雨。", "聊持剡山茗，以代宜城醑。"]'),
('47837c8d-2791-4ba9-bb56-3080ef8e8b43','送至洪沙彌遊越','皎然','唐','唐诗','tang','','[]','知爾學無生，不應傷此別。',36,'全唐诗/poet.tang.45000.json','["知爾學無生，不應傷此別。", "相逢宿我寺，獨往遊靈越。", "早晚花會中，經行剡山月。"]'),
('4f5dfe65-9c56-453b-a118-2787a226fe2e','送皇甫侍御曾還丹陽別業','皎然','唐','唐诗','tang','','[]','雲陽別夜憶春耕，花發菱湖問去程。',64,'全唐诗/poet.tang.45000.json','["雲陽別夜憶春耕，花發菱湖問去程。", "積水悠揚何處夢，亂山稠疊此時情。", "將離有月教弦斷，贈遠無蘭覺意輕。", "朝右要君持漢典，明年北墅可須營。"]'),
('39b92bbe-b7be-466c-a95a-8bda7783c6b3','白蘋洲送洛陽李丞使還','皎然','唐','唐诗','tang','','[]','蘋洲北望楚山重，千里迴軺止一封。',64,'全唐诗/poet.tang.45000.json','["蘋洲北望楚山重，千里迴軺止一封。", "臨水情來還共載，看花醉去更相從。", "罷宮風渚何時別，寄隱雲陽幾處逢。", "後會那應似疇昔，年年覺老雪山容。"]'),
('d956bc46-82d6-4c9b-9f8d-f936709f89f9','送履霜上人還金陵西山','皎然','唐','唐诗','tang','','[]','攜錫西山步綠莎，禪心未了奈情何。',32,'全唐诗/poet.tang.45000.json','["攜錫西山步綠莎，禪心未了奈情何。", "湘宮水寺清秋夜，月落風悲松柏多。"]'),
('276fd7e4-4cd7-4b9b-ad89-672baa15492f','送辨聰上人還廣陵','皎然','唐','唐诗','tang','','[]','莫學休公學遠公，了心須與我心同。',32,'全唐诗/poet.tang.45000.json','["莫學休公學遠公，了心須與我心同。", "隋家古柳數株在，看取人間萬事空。"]'),
('b892cd02-1217-41d7-ac42-c323c69650e4','送清勵上人遊福建','皎然','唐','唐诗','tang','','[]','禪子自矜禪性成，將來擬照建溪清。',32,'全唐诗/poet.tang.45000.json','["禪子自矜禪性成，將來擬照建溪清。", "南看閩樹花不落，更取何緣了妄情。"]'),
('7aff5d0b-5559-4355-a080-5054655f2f3c','送顧道士遊洞庭山','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','見說洞庭無上路，春遊亂踏五靈芝。',32,'全唐诗/poet.tang.45000.json','["見說洞庭無上路，春遊亂踏五靈芝。", "含桃風起花狼籍，正是仙翁碁散時。"]'),
('11b06602-4ba1-43f6-a5b9-46dc196f22bc','送邢台州濟','皎然','唐','唐诗','tang','','[]','海上仙山屬使君，石橋琪樹古來聞。',32,'全唐诗/poet.tang.45000.json','["海上仙山屬使君，石橋琪樹古來聞。", "他時畫出白團扇，乞取天台一片雲。"]'),
('ba9a88f0-988c-497b-bc44-1bf935190697','送柳察諫議叔','皎然','唐','唐诗','tang','','[]','東城南陌強經過，怨別無心亦放歌。',32,'全唐诗/poet.tang.45000.json','["東城南陌強經過，怨別無心亦放歌。", "明日院公應問我，閑雲常在石門多。"]'),
('68d1f205-0598-4395-94cf-34b1a0045cd1','送柳淡扶侍赴洪州','皎然','唐','唐诗','tang','','[]','中林許師友，忽阻夙心期。',72,'全唐诗/poet.tang.45000.json','["中林許師友，忽阻夙心期。", "自顧青緺好，來將黃鶴辭。", "少年輕遠涉，世道得無欺。", "煙雨孤舟上，晨昏千里時。", "離魂渺天末，相望在江湄。", "無限江南柳，春風卷亂絲。"]'),
('f8a801ae-24da-4893-bc08-9c0b357326cc','同李司直題武丘寺兼留諸公與陸羽之無錫','皎然','唐','唐诗','tang','','[]','陵寢成香阜，禪枝出白楊。',48,'全唐诗/poet.tang.45000.json','["陵寢成香阜，禪枝出白楊。", "劒池留故事，月樹即他方。", "應世緣須別，栖心趣不忘。", "還將陸居士，晨發泛歸航。"]'),
('9adfe182-8f7b-4fd7-bef7-78b34ca4c684','夏日題鄭谷江上納涼館','皎然','唐','唐诗','tang','','[]','迢遙山意外，清風又對君。',36,'全唐诗/poet.tang.45000.json','["迢遙山意外，清風又對君。", "若爲於此地，翻作路岐分。", "別館琴徒語，前洲鶴自羣。"]'),
('1439bee2-2d1c-48b2-82c3-b404a9fdacbc','太湖館送殷秀才赴舉','皎然','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','春風洞庭路，搖蕩暮天多。',48,'全唐诗/poet.tang.45000.json','["春風洞庭路，搖蕩暮天多。", "衰疾見芳草，別離傷遠波。", "詩名推首薦，賦甲擬前科。", "數日聞天府，山衣製芰荷。"]'),
('0dc1a905-638b-4ee0-b6cf-8b958bc3ea64','送重鈞上人遊天台','皎然','唐','唐诗','tang','','[]','漸看華頂出，幽賞意隨生。',48,'全唐诗/poet.tang.45000.json','["漸看華頂出，幽賞意隨生。", "十里行松色，千重過水聲。", "海容雲正盡，山色雨初晴。", "事事將心證，知君道可成。"]'),
('a7c5039b-ea20-46df-ae06-1e116034b1d3','早春送顏主簿遊越東兼謁元中丞','皎然','唐','唐诗','tang','','[]','輕舸趣不已，東風吹綠蘋。',48,'全唐诗/poet.tang.45000.json','["輕舸趣不已，東風吹綠蘋。", "欲看梅市雪，知賞柳家春。", "別意傾吳醑，芳聲動越人。", "山陰三月會，內史得嘉賓。"]'),
('5d0a92b4-67ac-47af-9d70-774548dda771','同顏使君清明日遊因送蕭主簿','皎然','唐','唐诗','tang','','[]','誰知賞嘉節，別異忽相和。',48,'全唐诗/poet.tang.45000.json','["誰知賞嘉節，別異忽相和。", "暮色汀洲徧，春情楊柳多。", "高城戀旌斾，極浦宿風波。", "惆悵支山月，今宵不再過。"]'),
('377688d7-b1be-44c4-b3fc-56d953d4f6d9','送道琚上人還金陵','皎然','唐','唐诗','tang','','[]','一與鍾山別，山中得信稀。',48,'全唐诗/poet.tang.45000.json','["一與鍾山別，山中得信稀。", "經年求法後，及夏問安歸。", "野實充甘膳，池花當綵衣。", "慈親莫返拜，外禮欲無爲。"]'),
('efc703bb-6916-4269-bf9c-01513fd90d14','送裴邕之上京','皎然','唐','唐诗','tang','','[]','辭山偶世清，挾策忽西行。',48,'全唐诗/poet.tang.45000.json','["辭山偶世清，挾策忽西行。", "帆過隨江疾，衣霑楚雪輕。", "尚文須獻賦，重道莫論兵。", "東觀今多事，應高白馬生。"]'),
('e059389c-abce-49e0-bba6-87e5e560defa','送珍上人還天竺兼寄廣通上人秦山人','皎然','唐','唐诗','tang','','[]','江寺名天竺，多居躡遠蹤。',48,'全唐诗/poet.tang.45000.json','["江寺名天竺，多居躡遠蹤。", "春帆依柳浦，輕履上蓮峰。", "禪子兼三隱，空書共一封。", "因君達山信，應向白雲逢。"]'),
('8284383b-63d9-4bad-b667-0cd6978c2612','送張孝廉赴舉','皎然','唐','唐诗','tang','','[]','名在諸生右，家經見素風。',48,'全唐诗/poet.tang.45000.json','["名在諸生右，家經見素風。", "春田休學稼，秋賦出儒宮。", "別路殘雲濕，離情晚桂叢。", "明年石渠署，應繼叔孫通。"]'),
('36cbe323-2fe4-47b1-a0d1-0bb272df2c02','送劉司法之越','皎然','唐','唐诗','tang','','[]','蕭蕭鳴夜角，驅馬背城濠。',48,'全唐诗/poet.tang.45000.json','["蕭蕭鳴夜角，驅馬背城濠。", "雨後寒流急，秋來朔吹高。", "三山期望海，八月欲觀濤。", "幾日西陵路，應逢謝法曹。"]'),
('1e2b9a51-a60d-4fc4-ba23-3406eae1408d','送簡栖上人之建州覲使君舅','皎然','唐','唐诗','tang','','[]','亂峰江上色，羨爾及秋行。',48,'全唐诗/poet.tang.45000.json','["亂峰江上色，羨爾及秋行。", "釋氏推真子，郗家許貴甥。", "氎花新雨淨，帆葉好風輕。", "千里依元舅，迴潮亦有情。"]'),
('df2fd6f1-6d5b-4373-92b9-2967698bc927','登開元寺樓送崔少府還平望驛','皎然','唐','唐诗','tang','','[]','登望思慮積，長亭樹連連。',36,'全唐诗/poet.tang.45000.json','["登望思慮積，長亭樹連連。", "悠揚下樓日，杳映傍帆煙。", "入夜四郊靜，南湖月待船。"]'),
('5a182ef9-a9de-4c03-a818-799a013d041a','送王居士遊越','皎然','唐','唐诗','tang','','[]','野性配雲泉，詩情屬風景。',36,'全唐诗/poet.tang.45000.json','["野性配雲泉，詩情屬風景。", "愛作爛熳遊，閑尋東路永。", "何山最好望，須上蕭然嶺。"]'),
('015123de-e5f5-4475-aecf-499c38f45d16','雜言重送皇甫侍御曾','皎然','唐','唐诗','tang','','[]','人獨歸，日將暮。',32,'全唐诗/poet.tang.45000.json','["人獨歸，日將暮。", "孤帆帶孤嶼，遠水連遠樹。", "難作別時心，還看別時路。"]'),
('210c23f4-db88-4ca0-bd10-b8c533055b38','送演上人之撫州覲使君叔','皎然','唐','唐诗','tang','','[]','臨川內史憐諸謝，爾在生緣比惠宗。',64,'全唐诗/poet.tang.45000.json','["臨川內史憐諸謝，爾在生緣比惠宗。", "遠別應將秦本去，幽尋定有楚僧逢。", "停船夜坐親孤月，把錫秋行入亂峰。", "便道須過大師寺，白蓮池上訪高蹤。"]'),
('5e5f47ff-0f41-439a-ae00-fbae21bd80c4','送大寶上人歸楚山','皎然','唐','唐诗','tang','','[]','厭上烏橋送別頻，湖光爛熳望行人。',64,'全唐诗/poet.tang.45000.json','["厭上烏橋送別頻，湖光爛熳望行人。", "欲將夜舸陪嘉月，肯住空林伴老身。", "獨鶴翩翻飛不定，歸雲蕭散會無因。", "從何得道懷惆悵，莫是人間屢見春。"]'),
('b6bfdacd-f332-425e-8612-db56bc69fbda','送侯秀才南遊','皎然','唐','唐诗','tang','','[]','芳草隨君自有情，不關山色與猨聲。',32,'全唐诗/poet.tang.45000.json','["芳草隨君自有情，不關山色與猨聲。", "爲看嚴子灘頭石，曾憶題詩不著名。"]'),
('e7808f40-425c-47f1-9d9b-61e5658bea45','別洞庭維諒上人','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','白雲關我不關他，此物留君情最多。',32,'全唐诗/poet.tang.45000.json','["白雲關我不關他，此物留君情最多。", "情著春風生橘樹，歸心不怕洞庭波。"]'),
('bcb6f927-4a3a-4d3a-971f-1367fde21539','康造錄事宅送太祝姪之虔吉訪兄弟','皎然','唐','唐诗','tang','','[]','阮咸別曲四座愁，賴是春風不是秋。',32,'全唐诗/poet.tang.45000.json','["阮咸別曲四座愁，賴是春風不是秋。", "漫漫江行訪兄弟，猨聲幾夜宿蘆洲。"]'),
('fcda5207-1ae4-4a31-bba0-da6f28c8bbf1','冬日梅溪送裴方舟宣州','皎然','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba", "\u9001\u522b", "\u4f24\u6000"]','平明匹馬上村橋，花發梅溪雪未消。',32,'全唐诗/poet.tang.45000.json','["平明匹馬上村橋，花發梅溪雪未消。", "日短天寒愁送客，楚山無限路遙遙。"]'),
('76f65785-3e98-4acc-a7f8-5c6cc6388ec9','送韋向睦州謁獨孤使君汜','皎然','唐','唐诗','tang','','[]','才子南看多遠情，閑舟蕩漾任春行。',32,'全唐诗/poet.tang.45000.json','["才子南看多遠情，閑舟蕩漾任春行。", "新安江色長如此，何似新安太守清。"]'),
('c7ca2bb2-4712-4f83-86ff-eeeb52518694','送至嚴山人歸山','皎然','唐','唐诗','tang','','[]','初到人間柳始陰，山書昨夜報春深。',32,'全唐诗/poet.tang.45000.json','["初到人間柳始陰，山書昨夜報春深。", "朝朝花落幾株樹，惱殺禪僧未證心。"]'),
('0ac60a5c-acf7-4c2b-95c0-2bdab8cf6e60','送僧遊揚州','皎然','唐','唐诗','tang','','[]','平明擇鉢向風輕，正及隋堤柳色行。',32,'全唐诗/poet.tang.45000.json','["平明擇鉢向風輕，正及隋堤柳色行。", "知爾禪心還似我，故宮春物肯傷情。"]'),
('7e38e013-8ee1-4e25-a76f-55e772083dcd','對陸迅飲天目山茶因寄元居士晟','皎然','唐','唐诗','tang','','[]','喜見幽人會，初開野客茶。',72,'全唐诗/poet.tang.45000.json','["喜見幽人會，初開野客茶。", "日成東井葉，露採北山芽。", "文火香偏勝，寒泉味轉嘉。", "投鐺湧作沫，著椀聚生花。", "稍與禪經近，聊將睡網賒。", "知君在天目，此意日無涯。"]'),
('9f260386-6918-4ec1-baa6-50b92076f515','渡前溪','皎然','唐','唐诗','tang','','[]','不意入前溪，愛溪從錯落。',24,'全唐诗/poet.tang.45000.json','["不意入前溪，愛溪從錯落。", "清清鑑不足，非是深難度。"]'),
('4b5edc93-e6c9-4e0e-8a09-3583554645a5','送靈澈','皎然','唐','唐诗','tang','','[]','我欲長生夢，無心解傷別。',24,'全唐诗/poet.tang.45000.json','["我欲長生夢，無心解傷別。", "千里萬里心，只似眼前月。"]'),
('eaeabc88-36d3-4e27-a3ac-9f63a4120216','寄路溫州','皎然','唐','唐诗','tang','','[]','欲問采靈藥，如何學無生。',24,'全唐诗/poet.tang.45000.json','["欲問采靈藥，如何學無生。", "愛鶴頗似君，且非求仙情。"]'),
('465dbedf-6abe-4394-9cb6-23532cbf8679','浣紗女','皎然','唐','唐诗','tang','','[]','清淺白沙灘，綠蒲尚堪把。',24,'全唐诗/poet.tang.45000.json','["清淺白沙灘，綠蒲尚堪把。", "家住水東西，浣紗明月下。"]'),
('e951a6ba-1dbc-40e5-ba83-45ca87bc7f76','待山月','皎然','唐','唐诗','tang','','[]','夜夜憶故人，長教山月待。',24,'全唐诗/poet.tang.45000.json','["夜夜憶故人，長教山月待。", "今宵故人至，山月知何在。"]'),
('4c920f1b-b029-4445-bcfe-461caf31fa7c','雜興','皎然','唐','唐诗','tang','','[]','人生分已定，富貴豈妄來。',24,'全唐诗/poet.tang.45000.json','["人生分已定，富貴豈妄來。", "不見海底泥，飛上成塵埃。"]'),
('2fb49477-b27a-4765-8627-9a4684b7a23f','舂陵登望','皎然','唐','唐诗','tang','','[]','西底空流水，東垣但聚雲。',24,'全唐诗/poet.tang.45000.json','["西底空流水，東垣但聚雲。", "最傷梅嶺望，花雪正紛紛。"]'),
('bbed233e-2aee-485e-ba31-d4a59b6671a5','投知己','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','若爲令憶洞庭春，上有閑雲可隱身。',32,'全唐诗/poet.tang.45000.json','["若爲令憶洞庭春，上有閑雲可隱身。", "無限白雲山要買，不知山價出何人。"]'),
('2d3ba142-1e93-4213-8400-17d45daff7f7','兵後餘不亭重送盧孟明遊江西','皎然','唐','唐诗','tang','','[]','攜手曾此分，怳如隔胡越。',144,'全唐诗/poet.tang.45000.json','["攜手曾此分，怳如隔胡越。", "倫侯古封邑，榮盛風雨歇。", "飢鼯號空亭，野草生故轍。", "如何此路岐，更作千年別。", "馮軾望遠道，春山無斷絕。", "朝行入郢樹，夜泊依楚月。", "佳士持操高，揚才日昭晰。", "離言何所贈，盈滿有虧缺。", "時節傷蟪蛄，芳菲忌鶗鴂。", "予思鹿門隱，心跡貴冥滅。", "頹顏反芝朮，昔貌成冰雪。", "歲晏期爾來，銷聲坐巖穴。"]'),
('e005974a-ab48-4e6c-a41a-67b352683ae0','別山詩','皎然','唐','唐诗','tang','','[]','山翁亦好禪，借我風溪樹。',96,'全唐诗/poet.tang.45000.json','["山翁亦好禪，借我風溪樹。", "採藥多近峰，汲泉有春渡。", "幽僧時相偶，仙子或與晤。", "自許戰勝心，彌高獨遊步。", "如何區中事，奪我林棲趣。", "辭山下復上，戀石行仍顧。", "宿昔情或乖，庶幾跡無誤。", "松聲莫相誚，此心冥去住。"]'),
('f3facf68-cd48-43d3-8e23-db28e701b9bd','同袁高使君送李判官使迴','皎然','唐','唐诗','tang','','[]','庾公歡此別，路遠意猶賒。',60,'全唐诗/poet.tang.45000.json','["庾公歡此別，路遠意猶賒。", "爲出塘邊柳，榮歸府中花。", "馳陽照古堞，遙思凝寒笳。", "延步下前渚，泝觴流淺沙。", "湖光引行色，輕舸傍殘霞。"]'),
('512e5fd2-e9ca-4ee1-999c-e3e1e0862758','陪顏使君餞宣諭蕭常侍','皎然','唐','唐诗','tang','','[]','江濤凋瘵後，遠使發天都。',120,'全唐诗/poet.tang.45000.json','["江濤凋瘵後，遠使發天都。", "昏墊宸心及，哀矜詔命敷。", "恤民驅急傳，訪舊枉征艫。", "外鎮藩條最，中朝顧問殊。", "文皆正風俗，名共溢寰區。", "已事方懷闕，歸期早戒塗。", "繁笳咽水閣，高蓋擁雲衢。", "暮色生千嶂，秋聲入五湖。", "離歌猶宛轉，歸馭已踟躇。", "今夕庾公意，西樓月亦孤。"]'),
('82f3eb80-91a3-4b42-93c4-e1a73fc51a94','奉陪顏使君修韻海畢東溪泛舟餞諸文士','皎然','唐','唐诗','tang','','[]','諸侯崇魯學，羔鴈日成羣。',72,'全唐诗/poet.tang.45000.json','["諸侯崇魯學，羔鴈日成羣。", "外史刊新韻，中郎定古文。", "菁華兼百氏，縑素備三墳。", "國語思開物，王言欲致君。", "研精業已就，懽宴惜應分。", "獨望西山去，將身寄白雲。"]'),
('7c60e0bd-891b-41da-8db2-3091534cd6b8','今上初登極歲送皇甫孝廉赴選','皎然','唐','唐诗','tang','','[]','行應會府春，欲勸及芳辰。',48,'全唐诗/poet.tang.45000.json','["行應會府春，欲勸及芳辰。", "北極天文正，東風漢律新。", "少年逢聖代，歡笑別情親。", "況是勳庸後，恩榮襲爾身。"]'),
('d9268c26-7928-4e10-b09b-8b24f7f1d2b3','同楊使君白蘋洲送陸侍御士佳入朝','皎然','唐','唐诗','tang','','[]','久愛吳興客，來依道德藩。',48,'全唐诗/poet.tang.45000.json','["久愛吳興客，來依道德藩。", "旋師聞杕杜，歸路憶轘轅。", "舊佩蒼玉在，新歌白芷繁。", "今朝天地靜，北望重飛翻。"]'),
('0012dca7-d278-450b-a531-c9636d0d774b','雪夜送海上人常州覲叔父上人殷仲文後','皎然','唐','唐诗','tang','','[]','繼世風流在，傳心向一燈。',48,'全唐诗/poet.tang.45000.json','["繼世風流在，傳心向一燈。", "望雲裁衲慣，翫雪步花能。", "交戰情忘久，銷魂別未曾。", "明朝阮家集，知有竹林僧。"]'),
('934abcb8-a86f-4831-a0f0-c3fc0155548e','送常清上人還舒州','皎然','唐','唐诗','tang','','[]','灊人思爾法，楚信有迴船。',48,'全唐诗/poet.tang.45000.json','["灊人思爾法，楚信有迴船。", "估客親宵語，閑鷗偶晝禪。", "經聲含石瀲，麈尾拂江煙。", "常說歸山意，誅茅廬霍前。"]'),
('019a61c7-f187-40a0-b282-fe86c6c98531','峴山送崔子向之宣州謁裴使君','皎然','唐','唐诗','tang','','[]','楚思入詩清，晨登峴山情。',48,'全唐诗/poet.tang.45000.json','["楚思入詩清，晨登峴山情。", "秋天水西寺，古木宛陵城。", "琴匣應將往，書車亦共行。", "吾知江太守，一顧重君名。"]'),
('af7c624d-780d-47a0-8eb0-0449c042c261','送嚴明府入關謁黎京兆','皎然','唐','唐诗','tang','','[]','春日異秋風，何爲怨別同。',48,'全唐诗/poet.tang.45000.json','["春日異秋風，何爲怨別同。", "潮迴芳渚沒，花落晝山空。", "旅候聞嘶馬，殘陽望斷鴻。", "應思右內史，相見直城中。"]'),
('4fb350ba-d5ef-4d2f-a497-c7d0e3fc8023','送丘秀才遊越','皎然','唐','唐诗','tang','','[]','山情與詩思，爛熳欲何從。',48,'全唐诗/poet.tang.45000.json','["山情與詩思，爛熳欲何從。", "夜舸誰相逐，空江月自逢。", "春期越草秀，晴憶剡雲濃。", "便擬將輕錫，攜居入亂峰。"]'),
('311e2f12-cb56-4e03-bc1c-b313e27be91b','送楊校書還濟源','皎然','唐','唐诗','tang','','[]','妖烽昨日靜，故里近嵩丘。',48,'全唐诗/poet.tang.45000.json','["妖烽昨日靜，故里近嵩丘。", "楚月搖歸夢，江楓見早秋。", "鄉心無遠道，北信減離憂。", "禪子還無事，辭君買沃州。"]'),
('284f2674-7f1d-437f-bb78-3a2a13fe71b5','送楊遂初赴選','皎然','唐','唐诗','tang','','[]','秋風吹別袂，客思在長安。',48,'全唐诗/poet.tang.45000.json','["秋風吹別袂，客思在長安。", "若得臨觴醉，何須減瑟彈。", "秉心凌竹柏，仗信越波瀾。", "春會文昌府，思君每北看。"]'),
('413da56f-7ee5-4dea-995b-9a713ded91f5','送贇上人還京','皎然','唐','唐诗','tang','','[]','久遊春草盡，還寄北船歸。',48,'全唐诗/poet.tang.45000.json','["久遊春草盡，還寄北船歸。", "沙鳥窺中食，江雲入淨衣。", "秦原山色近，楚寺磬聲微。", "見說翻經館，多聞似者稀。"]'),
('a60433a7-b5b1-4ef1-95b6-62b28dc2c19f','送廣通上人遊江西','皎然','唐','唐诗','tang','','[]','香爐七嶺秀，秋色九江清。',48,'全唐诗/poet.tang.45000.json','["香爐七嶺秀，秋色九江清。", "自古多禪隱，吾常愛此行。", "尋師經鄂渚，受請到青城。", "離別人間事，何關道者情。"]'),
('ccc82c46-f8e8-4870-8ec4-07c89144fa67','送羅判官還壽州幕','皎然','唐','唐诗','tang','','[]','君章才五色，知爾得家風。',48,'全唐诗/poet.tang.45000.json','["君章才五色，知爾得家風。", "故里旋歸駕，壽春思奉戎。", "天寒長蛇伏，飆烈文虎雄。", "定頌張征虜，桓桓戡難功。"]'),
('cd6dc609-00ed-4d26-9b1c-797f0d1c67d7','送李秀才赴婺州招','皎然','唐','唐诗','tang','','[]','山開江色上，孤賞去應遲。',48,'全唐诗/poet.tang.45000.json','["山開江色上，孤賞去應遲。", "綠水迎吳榜，秋風入楚詞。", "猨清獨宿處，木落遠行時。", "見說東陽守，登樓爲爾期。"]'),
('6163842c-cd07-4922-884f-b8ca285e40dd','送薛逢之宣州謁廢使','皎然','唐','唐诗','tang','','[]','六月鵬盡化，鴻飛獨冥冥。',48,'全唐诗/poet.tang.45000.json','["六月鵬盡化，鴻飛獨冥冥。", "秋烽家不定，險路客頻經。", "牛渚何時到，漁船幾處停。", "遙知詠史夜，謝守月中聽。"]'),
('20125a58-e28c-4901-9bbc-2ed9be1531b2','送德守二叔姪上人還國清寺覲師','皎然','唐','唐诗','tang','','[]','道賢齊二阮，俱向竹林歸。',48,'全唐诗/poet.tang.45000.json','["道賢齊二阮，俱向竹林歸。", "古偈穿花線，春裝卷葉衣。", "僧墟迴水寺，佛隴啓山扉。", "愛別吾何有，人心強有違。"]'),
('e7a61698-8744-4ba7-ad8e-6e8aae32456e','同明府章送沈秀才還石門山讀書','皎然','唐','唐诗','tang','','[]','身爲郢令客，心許楚山雲。',48,'全唐诗/poet.tang.45000.json','["身爲郢令客，心許楚山雲。", "文墨應經世，林泉漫誘君。", "欲隨樵子去，惜與道流分。", "肯謝申公輩，治詩事漢文。"]'),
('76464b7b-6cdb-42fb-9397-4e8d3d49c93e','送吉判官還京赴崔尹幕','皎然','唐','唐诗','tang','','[]','江南梅雨天，別思極春前。',48,'全唐诗/poet.tang.45000.json','["江南梅雨天，別思極春前。", "長路飛鳴鶴，離帆聚散煙。", "清晨趨九陌，秋色望三邊。", "見說王都尹，山陽辟一賢。"]'),
('71a68ed2-a27f-4015-9a26-9c5724c4af71','送裴判官赴商幕','皎然','唐','唐诗','tang','','[]','商洛近京師，才難赴幕時。',48,'全唐诗/poet.tang.45000.json','["商洛近京師，才難赴幕時。", "離歌紛白紵，候騎擁青絲。", "會喜疲人息，應逢猾虜衰。", "看君策高足，自此煙霄期。"]'),
('ce2d35e0-f4b0-4409-971e-f7c02826fb65','送李喻之處士洪州謁曹王','皎然','唐','唐诗','tang','','[]','獨思賢王府，遂作豫章行。',48,'全唐诗/poet.tang.45000.json','["獨思賢王府，遂作豫章行。", "雄鎮廬霍秀，高秋江漢清。", "見聞驚苦節，艱故傷遠情。", "西邸延嘉士，遺才得正平。"]'),
('af0a0f75-4479-4a74-8b39-22d17c99f0c6','送唐贊善遊越','皎然','唐','唐诗','tang','','[]','田園臨漢水，離亂寄隨關。',48,'全唐诗/poet.tang.45000.json','["田園臨漢水，離亂寄隨關。", "今日煙塵盡，東西又未還。", "長亭百越外，孤櫂五湖間。", "何處遊芳草，雲門千萬山。"]'),
('58425418-7cca-4d94-959e-0a9fdff1b95a','送韋秀才','皎然','唐','唐诗','tang','','[]','晨裝行墮葉，萬里望桑乾。',48,'全唐诗/poet.tang.45000.json','["晨裝行墮葉，萬里望桑乾。", "舊說涇關險，猶聞易水寒。", "黃雲戰後積，白草暮來看。", "近得君苗信，時教旅思寬。"]'),
('83140b82-3e31-4b2b-84de-197885e41511','送陳秀才赴舉','皎然','唐','唐诗','tang','','[]','諸侯懼削地，選士皆不羈。',48,'全唐诗/poet.tang.45000.json','["諸侯懼削地，選士皆不羈。", "休隱脫荷芰，將鳴矜羽儀。", "甲科爭玉片，詩句擬花枝。", "君實三楚秀，承家有清規。"]'),
('930f9898-6d9f-4812-b0f4-03a05b803b34','烏程李明府水堂同盧使君幼平送奘上人遊五臺','皎然','唐','唐诗','tang','','[]','身將劉令隱，經共謝公翻。',48,'全唐诗/poet.tang.45000.json','["身將劉令隱，經共謝公翻。", "有此宗師在，應知我法存。", "問心常寂樂，爲別豈傷魂。", "獨訪華泉去，秋風入雁門。"]'),
('c2a82c4d-8c7d-4c02-a5a8-3268bd1c085d','送李季良北歸','皎然','唐','唐诗','tang','','[]','風吹殘柳絲，孤客欲歸時。',48,'全唐诗/poet.tang.45000.json','["風吹殘柳絲，孤客欲歸時。", "掩抑楚弦絕，離披湘葉衰。", "前軍猶轉戰，故國杳難期。", "北望鴈門雪，空吟平子詩。"]'),
('f51d1cab-f27a-4c80-9ad2-38f00f169ec9','送淳于秀才蘭陵覲省','皎然','唐','唐诗','tang','','[]','歡言欲忘別，風信忽相驚。',48,'全唐诗/poet.tang.45000.json','["歡言欲忘別，風信忽相驚。", "柳浦歸人思，蘭陵春草生。", "擷芳心未及，視枕戀常盈。", "此去非長路，還如千里情。"]'),
('54229a02-6078-4090-a29b-54f58859bbb4','送至洪沙彌赴上元受戒','皎然','唐','唐诗','tang','','[]','不肯資章甫，勝衣被木蘭。',48,'全唐诗/poet.tang.45000.json','["不肯資章甫，勝衣被木蘭。", "今隨秣陵信，欲及蔡州壇。", "野寺鐘聲遠，春山戒足寒。", "歸來次第學，應見後心難。"]'),
('45f72bee-0bd1-4aaa-beb7-2e56674558d4','九日同盧使君幼平吳興郊外送李司倉赴選','皎然','唐','唐诗','tang','','[]','重陽千騎出，送客爲踟躕。',48,'全唐诗/poet.tang.45000.json','["重陽千騎出，送客爲踟躕。", "曠野多搖落，寒山滿路隅。", "晴空懸蒨斾，秋色起菱湖。", "幾日登司會，揚才盛五都。"]'),
('743b9ff6-ef74-4619-a1fb-8b677a3baa9d','送盧孟明還上都','皎然','唐','唐诗','tang','','[]','江臯北風至，歸客獨傷魂。',48,'全唐诗/poet.tang.45000.json','["江臯北風至，歸客獨傷魂。", "楚水逢鄉雁，平陵憶故園。", "征驂嘶別館，落日隱寒原。", "應及秦川望，春華滿國門。"]'),
('9acd6b1e-d9d2-4074-b391-695f47562b0d','送李少賓赴舉','皎然','唐','唐诗','tang','','[]','豈謂江南別，心如塞上行。',48,'全唐诗/poet.tang.45000.json','["豈謂江南別，心如塞上行。", "苦雲搖陣色，亂木攪秋聲。", "周谷雨未散，漢河流尚橫。", "春司遲爾策，方用靜妖兵。"]'),
('a2c15180-6f0d-4087-934d-79fd364e25b9','留別閻士和','皎然','唐','唐诗','tang','','[]','不慣人間別，多應忘別時。',24,'全唐诗/poet.tang.45000.json','["不慣人間別，多應忘別時。", "逢山又逢水，只畏却來遲。"]'),
('84ad0278-c239-4721-bf78-53385b0905f4','送李道士','皎然','唐','唐诗','tang','','[]','常隨山上下，忽限江南北。',24,'全唐诗/poet.tang.45000.json','["常隨山上下，忽限江南北。", "共是忘情人，何繇肯相憶。"]'),
('ecd7e63d-8c05-4af2-9018-05064797df28','送裴參軍還下邳舊居','皎然','唐','唐诗','tang','','[]','北望煙鋪驃騎營，虜烽無火楚天晴。',32,'全唐诗/poet.tang.45000.json','["北望煙鋪驃騎營，虜烽無火楚天晴。", "此時千里西歸客，泗上春風得及耕。"]'),
('cd9e26f7-052e-4c53-8746-6af2a42e9d72','送文會上人還富陽','皎然','唐','唐诗','tang','','[]','悠悠渺渺屬寒波，故寺思歸意若何。',32,'全唐诗/poet.tang.45000.json','["悠悠渺渺屬寒波，故寺思歸意若何。", "長憶孤洲二三月，春山偏愛富春多。"]'),
('6aa24cb9-01be-4fbb-bee5-3d54ba38ffeb','送維諒上人歸洞庭','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','從來湖上勝人間，遠愛浮雲獨自還。',32,'全唐诗/poet.tang.45000.json','["從來湖上勝人間，遠愛浮雲獨自還。", "孤月空天見心地，寥寥一水鏡中山。"]'),
('36a820f5-686d-4ce1-94d9-58e2edc15f00','九月八日送蕭少府歸洪州','皎然','唐','唐诗','tang','','[]','明日重陽今日歸，布帆絲雨望霏霏。',32,'全唐诗/poet.tang.45000.json','["明日重陽今日歸，布帆絲雨望霏霏。", "行過鶴渚知堪住，家在龍沙意有違。"]'),
('7f2da814-75d0-4dd9-a34f-1582f214b923','同顏魯公泛舟送皇甫侍御曾','皎然','唐','唐诗','tang','','[]','維舟若許暫從容，送過重江不厭重。',32,'全唐诗/poet.tang.45000.json','["維舟若許暫從容，送過重江不厭重。", "霜簡別來今始見，雪山歸去又難逢。"]'),
('d3ea160b-27f5-4da1-919d-776f3626a246','送孫侍御遊越','皎然','唐','唐诗','tang','','[]','不知持斧客，吟會是何情。',48,'全唐诗/poet.tang.45000.json','["不知持斧客，吟會是何情。", "丹陛恩猶在，滄洲賞暫行。", "江橈隨月泛，山策逐雪行。", "佳句傳零雨，詩流許盛名。"]'),
('76bc3b65-fb42-4452-9609-867bebe7fb03','送顏處士還長沙覲省','皎然','唐','唐诗','tang','','[]','西候風信起，三湘孤客心。',48,'全唐诗/poet.tang.45000.json','["西候風信起，三湘孤客心。", "天寒漢水廣，鄉遠楚雲深。", "服綵將侍膳，擷芳思滿襟。", "歸人忘艱阻，別恨獨何任。"]'),
('fcc20a02-5750-4224-98ff-908761c51854','送還本上人遊江西','皎然','唐','唐诗','tang','','[]','欲廣分何教，心將江漢期。',48,'全唐诗/poet.tang.45000.json','["欲廣分何教，心將江漢期。", "雲招望寺處，月待泝杯時。", "真侶誰傷別，降猨汝自悲。", "多應過廬阜，幽賞却來遲。"]'),
('86d12ea5-2998-4a34-bd94-c4497c385889','送路少府使京兼覲侍御兄','皎然','唐','唐诗','tang','','[]','國賦推能吏，今朝發貢湖。',48,'全唐诗/poet.tang.45000.json','["國賦推能吏，今朝發貢湖。", "佇瞻雙闕鳳，思見柏臺烏。", "樹向秦關遠，江分楚驛孤。", "榮君有兄弟，相繼騁長途。"]'),
('66692e37-82e5-42af-a89b-3a95b6a18bb5','於武原從送盧士舉','皎然','唐','唐诗','tang','','[]','落日獨歸客，空山匹馬嘶。',48,'全唐诗/poet.tang.45000.json','["落日獨歸客，空山匹馬嘶。", "蕭條古關外，岐路更東西。", "大澤雲寂寂，長亭雨淒淒。", "君還到湘水，寒夜滿猨啼。"]'),
('77de2bc3-e57f-4aa7-b682-6d1fd1e5a629','送烏程李明府得陟狀赴京','皎然','唐','唐诗','tang','','[]','驛吏滿江城，深仁見此情。',48,'全唐诗/poet.tang.45000.json','["驛吏滿江城，深仁見此情。", "士林推玉振，公府薦冰清。", "爲政移風久，承恩就日行。", "仲容綸綍貴，南巷有光榮。"]'),
('42b6ff28-fc0b-4301-858b-f9cfde4b7e95','送裴秀才往會稽山讀書','皎然','唐','唐诗','tang','','[]','一身齎萬卷，編室寄煙蘿。',48,'全唐诗/poet.tang.45000.json','["一身齎萬卷，編室寄煙蘿。", "硯滴穿池小，書衣種楮多。", "吟詩山響荅，泛瑟竹聲和。", "鶴板求儒術，深居意若何。"]'),
('6360624e-cef8-4329-a0b3-93f1bba833d6','送崔詹事論之上都','皎然','唐','唐诗','tang','','[]','金虎城池在，銅龍劒珮新。',48,'全唐诗/poet.tang.45000.json','["金虎城池在，銅龍劒珮新。", "重看前浦柳，猶憶舊洲蘋。", "遠思秦雲暮，歸心臘月春。", "青園昔遊處，惆悵別離人。"]'),
('39e5f0de-6788-4f52-ab8b-0bf7bac1d8e8','京口送盧孟明還揚州','皎然','唐','唐诗','tang','','[]','蕭蕭北風起，孤櫂下江濆。',48,'全唐诗/poet.tang.45000.json','["蕭蕭北風起，孤櫂下江濆。", "暮客去來盡，春流南北分。", "萋萋御亭草，渺渺蕪城雲。", "相送目千里，空山獨望君。"]'),
('803f49d8-542b-4f21-bdbc-2111b7c5916a','送沙彌大智遊五臺','皎然','唐','唐诗','tang','','[]','童年隨法侶，家世本儒流。',48,'全唐诗/poet.tang.45000.json','["童年隨法侶，家世本儒流。", "章句三生學，清涼萬里遊。", "雲歸龍沼暗，木落鴈門秋。", "長老應相問，傳予向祖州。"]'),
('9eb38dff-a8cc-4790-9e6f-810abaf53f82','送稟上人遊越','皎然','唐','唐诗','tang','','[]','雲泉誰不賞，獨見爾情高。',48,'全唐诗/poet.tang.45000.json','["雲泉誰不賞，獨見爾情高。", "投石輕龍窟，臨流笑鷺濤。", "折荷爲片席，灑水淨方袍。", "剡路逢禪侶，多應問我曹。"]'),
('596683bb-2f3e-41d2-9999-5bbdc0835442','送潘秀才之舒州','皎然','唐','唐诗','tang','','[]','楚水清風生，揚舲泛月行。',48,'全唐诗/poet.tang.45000.json','["楚水清風生，揚舲泛月行。", "荻洲寒露彩，雷岸曙潮聲。", "東道思才子，西人望客卿。", "從來金谷集，相繼有詩名。"]'),
('c276f673-4007-40ed-8fc4-a6dfec5a8266','送王山人遊廬山','皎然','唐','唐诗','tang','','["\u5e90\u5c71"]','千里訪靈奇，山資亦相隨。',48,'全唐诗/poet.tang.45000.json','["千里訪靈奇，山資亦相隨。", "葉舟過鶴市，花漏宿龍池。", "峰頂應閑散，人間足別離。", "白雲將世事，吾見爾心知。"]'),
('86facd49-87e1-43d5-b741-b14a0877bb74','送道契上人之越覲大夫叔','皎然','唐','唐诗','tang','','[]','楚僧推後輩，唐本學新經。',48,'全唐诗/poet.tang.45000.json','["楚僧推後輩，唐本學新經。", "外國傳香氎，何人施竹瓶。", "秋風別李寺，春日向柯亭。", "大阮今爲郡，看君眼最青。"]'),
('f148b8dd-998d-4959-989b-01c5fcf57fed','送沙彌長文遊京','皎然','唐','唐诗','tang','','[]','白版年猶小，黃花褐已通。',48,'全唐诗/poet.tang.45000.json','["白版年猶小，黃花褐已通。", "若爲詩思逸，早欲似休公。", "邁俗多真氣，傳家有素風。", "應須學心地，宗旨在關東。"]'),
('64cd7b89-72d8-476e-aa56-fcf28d28ce5c','秋日送擇高上人往江西謁曹王','皎然','唐','唐诗','tang','','[]','超然獨遊趣，無限別山情。',48,'全唐诗/poet.tang.45000.json','["超然獨遊趣，無限別山情。", "予病不同賞，雲閑應共行。", "齋容秋水照，香氎早風輕。", "曾被陳王識，遙知江上迎。"]'),
('7309e31f-5147-4cd7-a2b6-82ff85bb4977','送如獻上人遊長安','皎然','唐','唐诗','tang','','[]','關中四子教猶存，見說新經待爾翻。',64,'全唐诗/poet.tang.45000.json','["關中四子教猶存，見說新經待爾翻。", "爲法應過七祖寺，忘名不到五侯門。", "閑尋鄠杜看脩竹，獨上風涼望古原。", "高逸詩情無別怨，春遊從遣落花繁。"]'),
('12715327-00ab-42f0-938f-7ac575c4369c','日曜上人還潤州','皎然','唐','唐诗','tang','','[]','送君何處最堪思，孤月停空欲別時。',64,'全唐诗/poet.tang.45000.json','["送君何處最堪思，孤月停空欲別時。", "露茗猶芳邀重會，寒花落盡不成期。", "鶴令先去看山近，雲礙初飛到寺遲。", "莫倚禪功放心定，蕭家陵樹誤人悲。"]'),
('7efa5ff8-f211-4b7f-a230-83cef869fafc','寺院聽胡笳送李殷','皎然','唐','唐诗','tang','','[]','一奏胡笳客未停，野僧還欲廢禪聽。',32,'全唐诗/poet.tang.45000.json','["一奏胡笳客未停，野僧還欲廢禪聽。", "難將此意臨江別，無限春風葭菼青。"]'),
('dd17e316-87b9-4a64-bdc6-d5cb619bf5e4','送僧繹','皎然','唐','唐诗','tang','','[]','斜日搖揚在柳絲，孤亭寂寂水逶迤。',32,'全唐诗/poet.tang.45000.json','["斜日搖揚在柳絲，孤亭寂寂水逶迤。", "誰堪別後行人盡，唯有春風起路岐。"]'),
('bcca4847-f95e-4271-9aea-ea04f166f8dc','荅裴評事澄荻花間送梁肅拾遺','皎然','唐','唐诗','tang','','[]','波上荻花非雪花，風吹撩亂滿袈裟。',32,'全唐诗/poet.tang.45000.json','["波上荻花非雪花，風吹撩亂滿袈裟。", "如今歲晏無芳草，獨對離樽作物華。"]'),
('3d2875fd-05b7-4db6-b58d-fe69e2f1df9b','送勝雲小師','皎然','唐','唐诗','tang','','[]','昨日雪山記爾名，吾今坐石已三生。',32,'全唐诗/poet.tang.45000.json','["昨日雪山記爾名，吾今坐石已三生。", "少年道性易流動，莫遣秋風入別情。"]'),
('49b136e1-ba54-4338-9959-9aac45592250','誚士和別','皎然','唐','唐诗','tang','','[]','今日同，明日隔，何事悠悠久爲客。',32,'全唐诗/poet.tang.45000.json','["今日同，明日隔，何事悠悠久爲客。", "君憐溪上去來雲，我羨磷磷水中石。"]'),
('4a4243ce-d7ea-4524-b1bc-afdbccb75945','送吳馮遊京','皎然','唐','唐诗','tang','','[]','北期何意促，蕙草夜來繁。',48,'全唐诗/poet.tang.45000.json','["北期何意促，蕙草夜來繁。", "清月思淮水，春風望國門。", "此時休旋逸，萬里忽飛翻。", "若憶山陰會，孤琴爲我援。"]'),
('0c49dce5-ed9c-43dc-8375-bed3229dc819','送僧遊宣州','皎然','唐','唐诗','tang','','[]','楚山千里一僧行，念爾初緣道未成。',32,'全唐诗/poet.tang.45000.json','["楚山千里一僧行，念爾初緣道未成。", "莫向舒姑泉口泊，此中嗚咽爲傷情。"]'),
('aff696be-a91f-4e19-8ecd-6b09c57adb35','宿支硎寺上房','皎然','唐','唐诗','tang','','[]','上方精舍遠，共宿白雲端。',48,'全唐诗/poet.tang.45000.json','["上方精舍遠，共宿白雲端。", "寂寞千峰夜，蕭條萬木寒。", "山光霜下見，松色月中看。", "却與西林別，歸心即欲闌。"]'),
('e3373f5d-d110-4172-8558-4046a87b0f55','荅胡處士','皎然','唐','唐诗','tang','','[]','西山禪隱比來聞，長道唯應我與君。',32,'全唐诗/poet.tang.45000.json','["西山禪隱比來聞，長道唯應我與君。", "書上無名心忘却，人間聚散似浮雲。"]'),
('cfd73d42-2f25-42c4-9a56-8b325c82f841','荅張烏程','皎然','唐','唐诗','tang','','[]','莫道謫官無主人，秣陵才令日相親。',32,'全唐诗/poet.tang.45000.json','["莫道謫官無主人，秣陵才令日相親。", "前溪更有忘憂處，荷葉田田間白蘋。"]'),
('546f24ef-4889-4f0d-90b0-279554000dfb','酬張明府','皎然','唐','唐诗','tang','','[]','愛君詩思動禪心，使我休吟待鶴吟。',32,'全唐诗/poet.tang.45000.json','["愛君詩思動禪心，使我休吟待鶴吟。", "更說郡中黃霸在，朝朝無事許招尋。"]'),
('aed7d4ae-8389-4ede-bfd0-9fdb439b1d33','勞山居寄呈吳處士','皎然','唐','唐诗','tang','','[]','官居鼎鼐古今無，名士才臣獨一余。',32,'全唐诗/poet.tang.45000.json','["官居鼎鼐古今無，名士才臣獨一余。", "賢閣御題龍墨燦，詔歸補衮在須臾。"]'),
('97dd72e9-9042-4c92-943e-9632baf2097b','從軍行五首 一','皎然','唐','唐诗','tang','','[]','候騎出紛紛，元戎霍冠軍。',48,'全唐诗/poet.tang.45000.json','["候騎出紛紛，元戎霍冠軍。", "漢鞞秋聒地，羌火晝燒雲。", "萬里戈城合，三邊羽檄分。", "烏孫驅未盡，肯顧遼陽勳。"]'),
('9a5d1655-e201-4e9e-ac7a-ae583c563707','從軍行五首 二','皎然','唐','唐诗','tang','','[]','韓斾拂丹霄，漢軍新破遼。',48,'全唐诗/poet.tang.45000.json','["韓斾拂丹霄，漢軍新破遼。", "紅塵驅鹵簿，白羽擁嫖姚。", "戰苦軍猶樂，功高將不驕。", "至今丁零塞，朔吹空蕭蕭。"]'),
('191fa949-63bc-435b-8ed6-950484a6ac87','從軍行五首 三','皎然','唐','唐诗','tang','','[]','百萬逐呼韓，頻年不解鞍。',48,'全唐诗/poet.tang.45000.json','["百萬逐呼韓，頻年不解鞍。", "兵屯絕漠暗，馬飲濁河乾。", "破虜功未錄，勞師力已殫。", "須防肘腋下，飛禍出無端。"]'),
('37cec46c-16fe-40f9-8610-845d552c562f','從軍行五首 四','皎然','唐','唐诗','tang','','[]','飛將下天來，奇謀閫外裁。',48,'全唐诗/poet.tang.45000.json','["飛將下天來，奇謀閫外裁。", "水心龍劒動，地肺鴈山開。", "望氣燕師銳，當鋒虜陣摧。", "從今射鵰騎，不敢過雲堆。"]'),
('05b15565-3921-4c2a-b7c9-a1fb6ff8cd58','從軍行五首 五','皎然','唐','唐诗','tang','','[]','黃紙君王詔，青泥校尉書。',48,'全唐诗/poet.tang.45000.json','["黃紙君王詔，青泥校尉書。", "誓師張虎落，選將擐犀渠。", "霧暗津蒲失，天寒塞柳疎。", "橫行十萬騎，欲掃虜塵餘。"]'),
('5272bdd9-1aec-4937-b764-a6c1294b4205','隴頭水二首 一','皎然','唐','唐诗','tang','','[]','隴頭水欲絕，隴水不堪聞。',48,'全唐诗/poet.tang.45000.json','["隴頭水欲絕，隴水不堪聞。", "碎影搖槍壘，寒聲咽幔軍。", "素從鹽海積，綠帶柳城分。", "日落天邊望，逶迤入寒雲。"]'),
('83527647-593d-4e2e-94d4-fdc41689c95d','隴頭水二首 二','皎然','唐','唐诗','tang','','[]','秦隴逼氐羌，征人去未央。',48,'全唐诗/poet.tang.45000.json','["秦隴逼氐羌，征人去未央。", "如何幽咽水，併欲斷君腸。", "西注悲窮漠，東分憶故鄉。", "旅魂聲攪亂，無夢到咸陽。"]'),
('9439ec50-08ff-4eef-a2e4-7da211440b49','塞下曲二首 一','皎然','唐','唐诗','tang','','[]','寒塞無因見落梅，胡人吹入笛聲來。',32,'全唐诗/poet.tang.45000.json','["寒塞無因見落梅，胡人吹入笛聲來。", "勞勞亭上春應度，夜夜城南戰未迴。"]'),
('a59a6c0a-3019-4d54-9a34-f7fbed9e13bc','塞下曲二首 二','皎然','唐','唐诗','tang','','[]','都護今年破武威，胡沙萬里鳥空飛。',32,'全唐诗/poet.tang.45000.json','["都護今年破武威，胡沙萬里鳥空飛。", "旄竿瀚海掃雲出，氈騎天山蹋雪歸。"]'),
('0f885a40-7601-4ae1-b885-afa5562f07c5','覽史','皎然','唐','唐诗','tang','','[]','黃綺皆皓髮，秦時隱商山。',48,'全唐诗/poet.tang.45000.json','["黃綺皆皓髮，秦時隱商山。", "嘉謀匡帝道，高步遊天關。", "不愛珪組紲，却思林壑還。", "放歌長松下，日與孤雲閑。"]'),
('e7e99c18-4408-46a5-aaac-9875ef05cb68','詠史','皎然','唐','唐诗','tang','','[]','獨負高世資，冥冥寄浮俗。',60,'全唐诗/poet.tang.45000.json','["獨負高世資，冥冥寄浮俗。", "卞子去不歸，何人辯荆玉。", "鬻舂意不淺，汚迹身豈辱。", "鸞鎩樂迍邅，虬蟠甘窘束。", "五噫譎且正，可以見心曲。"]'),
('e9812eed-7e8d-4680-bfcd-187b20b1889f','詠史','皎然','唐','唐诗','tang','','[]','田氏門下客，馮公衆中賤。',56,'全唐诗/poet.tang.45000.json','["田氏門下客，馮公衆中賤。", "一朝市義還，百代名獨擅。", "始知下客不可輕，能使主人功業成。", "借問高車與珠履，何如卑賤一書生。"]'),
('4ff6d91f-2f0b-403e-be77-1763e842d62f','讀張曲江集','皎然','唐','唐诗','tang','','[]','相公乃天蓋，人文佐生成。',180,'全唐诗/poet.tang.45000.json','["相公乃天蓋，人文佐生成。", "立程正頹靡，繹思何縱橫。", "春杼弄緗綺，陽林敷玉英。", "飄然飛動姿，邈矣高簡情。", "後輩驚失步，前修敢爭衡。", "始欣耳目遠，再使機慮清。", "體正力已全，理精識何妙。", "昔年歌陽春，徒推郢中調。", "今朝聽鸞鳳，豈獨羨門嘯。", "帝命鎮雄州，待濟寄上流。", "才兼荆衡秀，氣助瀟湘秋。", "逸蕩子山匹，經奇文暢儔。", "沈吟未終卷，變態紛難數。", "曜耳代明璫，襲衣同芳杜。", "愔愔聞玉磬，寤寐在靈府。"]'),
('77ee5e3c-0aea-4164-b277-091b9534e0aa','奉酬陸使君見過各賦院中一物得江蘺','皎然','唐','唐诗','tang','','[]','江蘺生古砌，花每落禪床。',48,'全唐诗/poet.tang.45000.json','["江蘺生古砌，花每落禪床。", "嘉客未採掇，空門自馨香。", "名因詩目見，色對道心忘。", "不遇陸內史，誰知殊衆芳。"]'),
('d800b4ee-588c-43a4-a256-61c32096c664','賦得謝墅送王長史','皎然','唐','唐诗','tang','','[]','世業西山墅，移家長我身。',48,'全唐诗/poet.tang.45000.json','["世業西山墅，移家長我身。", "蕭疎遺樹老，寂寞廢田春。", "車巷傷前轍，籬溝憶舊隣。", "何堪再過日，更送北歸人。"]'),
('8cee75e7-ed9f-4d4e-b7a6-4686a2aa4806','夏日同崔使君論登城樓賦得遠山','皎然','唐','唐诗','tang','','[]','遠山湖上小，青翠望依稀。',48,'全唐诗/poet.tang.45000.json','["遠山湖上小，青翠望依稀。", "纔向窗中列，還從林表微。", "色濃春草在，峰起夏雲歸。", "不是蓬萊島，如何人去稀。"]'),
('cc22f815-b1f7-4503-8bef-4ca8376cfbc1','詠數探得七','皎然','唐','唐诗','tang','','[]','鄒子譚天歲，黃童對日年。',48,'全唐诗/poet.tang.45000.json','["鄒子譚天歲，黃童對日年。", "求真初作傳，鍊魄已成仙。", "鶴駕迎緱嶺，星橋下蜀川。", "逢君竹林客，相對弄清絃。"]'),
('87a7ee00-8b78-4550-8957-93f9d006b994','奉同顏使君真卿送李侍御萼賦得荻塘路','皎然','唐','唐诗','tang','','[]','落日車遙遙，客心在歸路。',48,'全唐诗/poet.tang.45000.json','["落日車遙遙，客心在歸路。", "細草暗回塘，春泉縈古渡。", "遺蹤歎蕪沒，遠道悲去住。", "寂寞荻花空，行人別無數。"]'),
('9a02583c-9b2a-4e41-a7fa-6524219e97eb','賦顏氏古今一事得晉仙傳送顏逸','皎然','唐','唐诗','tang','','[]','曾看顏氏傳，多記晉時仙。',48,'全唐诗/poet.tang.45000.json','["曾看顏氏傳，多記晉時仙。", "却憶桐君老，俱還桂父年。", "青春留鬢髮，白日向雲煙。", "遠別賷遺簡，囊中有幾篇。"]'),
('745f741a-151f-48c7-94c9-bb8a314c197e','賦得石梁泉送崔逵','皎然','唐','唐诗','tang','','[]','架石通霞壁，懸崖散碧沙。',48,'全唐诗/poet.tang.45000.json','["架石通霞壁，懸崖散碧沙。", "天晴虹影渡，風細練文斜。", "舉陟幽期阻，沿洄客意賒。", "河梁非此路，別恨亦無涯。"]'),
('a6dd43ba-4310-41c8-9583-27c6d53d28b6','賦得夜雨滴空堦送陸羽歸龍山','皎然','唐','唐诗','tang','','[]','閑堦夜雨滴，偏入別情中。',48,'全唐诗/poet.tang.45000.json','["閑堦夜雨滴，偏入別情中。", "斷續清猨應，淋漓候館空。", "氣令煩慮散，時與早秋同。", "歸客龍山道，東來雜好風。"]'),
('0a9f435e-e8c4-45c1-b7a2-e1244e002fa4','賦得燈心送李侍御萼','皎然','唐','唐诗','tang','','[]','燈心生衆草，因有始知芳。',48,'全唐诗/poet.tang.45000.json','["燈心生衆草，因有始知芳。", "綵妓窗偏麗，金桃動更香。", "花驚春未盡，焰喜夜初長。", "別後空離室，何人借末光。"]'),
('30bb80ff-ab37-4cce-ba84-6183bdd55787','賦得竹如意送詳師赴講','皎然','唐','唐诗','tang','','[]','縹竹湘南美，吾師尚毀形。',48,'全唐诗/poet.tang.45000.json','["縹竹湘南美，吾師尚毀形。", "仍留負霜節，不變在林青。", "每入楊枝手，因談貝葉經。", "誰期沃州講，持此別東亭。"]'),
('2fc5531b-5101-49ed-937b-19ec3037906e','聽素法師講法華經','皎然','唐','唐诗','tang','','[]','法子出西秦，名齊漆道人。',48,'全唐诗/poet.tang.45000.json','["法子出西秦，名齊漆道人。", "纔敷藥草義，便見雪山春。", "護講龍來遠，聞經鶴下頻。", "應機如一雨，誰不滌心塵。"]'),
('458df517-cfbb-4932-b3d9-2a9e0f9f1efd','詠敭上人座右畫松','皎然','唐','唐诗','tang','','[]','寫得長松意，千尋數尺中。',48,'全唐诗/poet.tang.45000.json','["寫得長松意，千尋數尺中。", "翠陰疑背日，寒色欲生風。", "真樹孤標在，高人立操同。", "一枝遙可折，吾欲問生公。"]'),
('c53cc0fc-164a-4d47-bd2d-3183e60716dc','夏日登觀農樓和崔使君','皎然','唐','唐诗','tang','','[]','片雨拂簷楹，煩襟四坐清。',48,'全唐诗/poet.tang.45000.json','["片雨拂簷楹，煩襟四坐清。", "霏微過麥隴，蕭散傍莎城。", "靜愛和花落，幽聞入竹聲。", "朝觀趣無限，高詠寄深情。"]'),
('70fd00a6-8f6b-45c5-9233-8df1c067af27','妙喜寺逵公院賦得夜磬送呂評事','皎然','唐','唐诗','tang','','[]','一磬寒山至，凝心轉清越。',60,'全唐诗/poet.tang.45000.json','["一磬寒山至，凝心轉清越。", "細和虛籟盡，疎繞懸泉發。", "在夜吟更長，停空韻難絕。", "幽僧悟深定，歸客忘遠別。", "寂歷無性中，真聲何起滅。"]'),
('c0e7fc56-c2c2-4369-9056-a8a2c2eb5b59','詠小瀑布','皎然','唐','唐诗','tang','','[]','瀑布小更奇，潺湲二三尺。',48,'全唐诗/poet.tang.45000.json','["瀑布小更奇，潺湲二三尺。", "細脉穿亂沙，叢聲咽危石。", "初因智者賞，果會幽人跡。", "不向定中聞，那知我心寂。"]'),
('e95ac284-a766-4f68-86cb-2d3c5ed2f343','僊女臺','皎然','唐','唐诗','tang','','[]','寂寂舊桑田，誰家女得僊。',48,'全唐诗/poet.tang.45000.json','["寂寂舊桑田，誰家女得僊。", "應無雞犬在，空有子孫傳。", "古木花猶發，荒臺路未遷。", "暮來雲一片，疑是欲歸年。"]'),
('0cdca8d5-33d5-42ee-9563-65705d230d25','靈澈上人何山寺七賢石詩','皎然','唐','唐诗','tang','','[]','七石配七賢，隱僧山上移。',72,'全唐诗/poet.tang.45000.json','["七石配七賢，隱僧山上移。", "石性殊磊落，君子又高奇。", "跂禪服宜壞，坐客冠可隳。", "夜倚月樹影，晝傾風竹枝。", "集質患追琢，表頑用磷緇。", "佚火玉亦害，塊然長在茲。"]'),
('620ec4d0-eaf2-420b-a6bd-6eff4dfa685e','潘丞孩子','皎然','唐','唐诗','tang','','[]','愛子性情奇，初生玉樹枝。',36,'全唐诗/poet.tang.45000.json','["愛子性情奇，初生玉樹枝。", "人曾天上見，名向月中知。", "我識嬰兒意，何須待佩觿。"]'),
('c3438d68-b266-4d5a-a52d-9640ecfa2f93','南池雜詠五首 水月','皎然','唐','唐诗','tang','','[]','夜夜池上觀，禪身坐月邊。',36,'全唐诗/poet.tang.45000.json','["夜夜池上觀，禪身坐月邊。", "虛無色可取，皎潔意難傳。", "若向空心了，長如影正圓。"]'),
('f1528b27-d4f2-458c-b755-c60c0e53a111','南池雜詠五首 溪雲','皎然','唐','唐诗','tang','','[]','舒卷意何窮，縈流復帶空。',36,'全唐诗/poet.tang.45000.json','["舒卷意何窮，縈流復帶空。", "有形不累物，無迹去隨風。", "莫怪長相逐，飄然與我同。"]'),
('3099b9b0-2454-4e75-8d51-947f01a3485f','南池雜詠五首 虛舟','皎然','唐','唐诗','tang','','[]','虛舟動又靜，忽似去逢時。',36,'全唐诗/poet.tang.45000.json','["虛舟動又靜，忽似去逢時。", "觸物知無迕，爲梁幸見遺。", "因風到此岸，非有濟川期。"]'),
('0bec7d92-c885-42f1-a4d4-31bd72bb5c03','南池雜詠五首 寒山','皎然','唐','唐诗','tang','','[]','侵空撩亂色，獨愛我中峰。',36,'全唐诗/poet.tang.45000.json','["侵空撩亂色，獨愛我中峰。", "無事負輕策，閑行躡幽踪。", "衆山搖落盡，寒翠更重重。"]'),
('129eea93-a072-40f8-82e4-ee1c7a10d040','南池雜詠五首 寒竹','皎然','唐','唐诗','tang','','[]','褭褭孤生竹，獨立山中雪。',36,'全唐诗/poet.tang.45000.json','["褭褭孤生竹，獨立山中雪。", "蒼翠搖動風，嬋娟帶寒月。", "狂花不相似，還共凌冬發。"]'),
('58c91a06-3e08-4d81-892e-7ae8afc5f409','望遠村','皎然','唐','唐诗','tang','','[]','林杪不可分，水步遙難辨。',24,'全唐诗/poet.tang.45000.json','["林杪不可分，水步遙難辨。", "一片山翠邊，依稀見村遠。"]'),
('18e7b894-4ed6-400a-aa0b-f59da5d838d6','惜暮景','皎然','唐','唐诗','tang','','[]','疎陰花不動，片景松梢度。',24,'全唐诗/poet.tang.45000.json','["疎陰花不動，片景松梢度。", "夏日舊來長，佳遊何易暮。"]'),
('cf14fe00-0553-4519-9482-37eceabce9d1','效古','皎然','唐','唐诗','tang','','[]','日出天地正，煌煌闢晨曦。',72,'全唐诗/poet.tang.45000.json','["日出天地正，煌煌闢晨曦。", "六龍驅羣動，古今無盡時。", "夸父亦何愚，競走先自疲。", "飲乾咸池水，折盡扶桑枝。", "渴死化爝火，嗟嗟徒爾爲。", "空留鄧林在，折盡令人嗤。"]'),
('3c40a679-b659-4773-8737-7b37a226dcc3','古別離','皎然','唐','唐诗','tang','','["\u592a\u6e56"]','太湖三山口，吳王在時道。',104,'全唐诗/poet.tang.45000.json','["太湖三山口，吳王在時道。", "寂寞千載心，無人見春草。", "誰識緘怨者，持此傷懷抱。", "孤舟畏狂風，一點宿煙島。", "望所思兮若何，月蕩漾兮空波。", "雲離離兮北斷，鴻眇眇兮南多。", "身去兮天畔，心折兮湖岸。", "春風胡爲兮塞路，使我歸夢兮撩亂。"]'),
('965c0cc3-6966-41d7-b599-eb83a6ee328d','擬長安春詞','皎然','唐','唐诗','tang','','[]','春信在河源，春風蕩妾魂。',48,'全唐诗/poet.tang.45000.json','["春信在河源，春風蕩妾魂。", "春歌雜鶗鴂，春夢繞轘轅。", "春絮愁偏滿，春絲悶更繁。", "春期不可定，春曲嬾新翻。"]'),
('0f7aa672-9a8a-4334-b044-48ade354289d','效古','皎然','唐','唐诗','tang','','[]','思君轉戰度交河，強弄胡琴不成曲。',48,'全唐诗/poet.tang.45000.json','["思君轉戰度交河，強弄胡琴不成曲。", "日落應愁隴底難，春來定夢江南數。", "萬丈游絲是妾心，惹蝶縈花亂相續。"]'),
('317b0c79-babb-40a4-986a-2a05ee5511b5','昭君怨','皎然','唐','唐诗','tang','','[]','自倚嬋娟望主恩，誰知美惡忽相翻。',32,'全唐诗/poet.tang.45000.json','["自倚嬋娟望主恩，誰知美惡忽相翻。", "黃金不買漢宮貌，青塚空埋胡地魂。"]'),
('a6df100f-c72d-43ce-ab45-c264abb61961','銅雀妓','皎然','唐','唐诗','tang','','[]','強開尊酒向陵看，憶得君王舊日懽。',32,'全唐诗/poet.tang.45000.json','["強開尊酒向陵看，憶得君王舊日懽。", "不覺餘歌悲自斷，非關豔曲轉聲難。"]'),
('5511ce66-c137-479b-b99f-b0a1df5c479d','長門怨','皎然','唐','唐诗','tang','','[]','春風日日閉長門，搖蕩春心似夢魂。',32,'全唐诗/poet.tang.45000.json','["春風日日閉長門，搖蕩春心似夢魂。", "誰遣花開只笑妾，不如桃李正無言。"]'),
('cf69e622-5338-4418-8989-d15d34df68a7','哭吳縣房聳明府','皎然','唐','唐诗','tang','','[]','仁人邁厚德，可謂名實全。',288,'全唐诗/poet.tang.45000.json','["仁人邁厚德，可謂名實全。", "撫迹若疎曠，會心極精研。", "履危節詎屈，著論識不偏。", "恨以榮級淺，嘉猷未及宣。", "伊人期遠大，志業難比肩。", "昭世既合幷，吾君藉陶甄。", "奈何明明理，與善徒空詮。", "徵教或稽聖，窮源反問天。", "一官自吳邑，六翮委江壖。", "始是牽絲日，翻成撤瑟年。", "金膏果不就，玉珮長此捐。", "倚伏信冥昧，夭修驚後先。", "安知忘情子，愛網素已褰。", "爲有深仁感，遂令真性遷。", "心悲空林下，淚灑秋景前。", "夫子寡兄弟，撫孤傷藐然。", "傾雲爲慘結，弔鶴共聯翩。", "割念命歸駕，訣詞向空筵。", "樹桃陰始合，愛客位常懸。", "幡然遠行時，崇望歸朝旋。", "悟茲懽宴隔，哀被歲月延。", "書帶變芳草，履痕移綠錢。", "冥期儻可逢，生盡會無緣。", "幸願示因業，代君運精專。"]'),
('5db6676b-b9f6-40e8-805a-6b41df421081','哭覺上人','皎然','唐','唐诗','tang','','[]','憶君南適越，不作買山期。',48,'全唐诗/poet.tang.45000.json','["憶君南適越，不作買山期。", "昨得耶溪信，翻爲逝水悲。", "神交如可見，生盡杳難思。", "白日東林下，空懷步影時。"]'),
('6159289b-17fb-4d40-91eb-2a78ab7836ef','題餘不溪廢寺','皎然','唐','唐诗','tang','','[]','武原離亂後，真界積塵埃。',48,'全唐诗/poet.tang.45000.json','["武原離亂後，真界積塵埃。", "殘月生秋水，悲風起故臺。", "居人今已盡，棲鴿暝還來。", "不到無生理，應堪賦七哀。"]'),
('6a081af9-da14-448e-90b1-7768a2b7ba88','同李洗馬入餘不溪經辛將軍故城','皎然','唐','唐诗','tang','','[]','慘慘寒城望，將軍下世時。',48,'全唐诗/poet.tang.45000.json','["慘慘寒城望，將軍下世時。", "高墉暮草遍，大樹野風悲。", "壁壘今惟在，勳庸近可思。", "蒼然古溪上，川逝共悽其。"]'),
('ac2ef3d8-c8f1-48d7-a74c-cca3dc21e258','憶天台','皎然','唐','唐诗','tang','','[]','箬溪朝雨散，雲色似天台。',48,'全唐诗/poet.tang.45000.json','["箬溪朝雨散，雲色似天台。", "應是東風便，吹從海上來。", "靈山遊汗漫，仙石過莓苔。", "誤到人間世，經年不早迴。"]'),
('cf875959-7cd6-466b-b8ce-1b7489a678b6','萬回寺','皎然','唐','唐诗','tang','','[]','萬里稱逆化，愚惷性亦全。',48,'全唐诗/poet.tang.45000.json','["萬里稱逆化，愚惷性亦全。", "紫紱拖身上，妖姬安膝前。", "見他拘坐寂，故我是眠禪。", "吾知至人心，杳若青冥天。"]'),
('8ac50c7c-8aae-43ac-a75c-ffcc573f3e18','禪詩','皎然','唐','唐诗','tang','','[]','萬法出無門，紛紛使智昏。',48,'全唐诗/poet.tang.45000.json','["萬法出無門，紛紛使智昏。", "徒稱誰氏子，獨立天地元。", "實際且何有，物先安可存。", "須知不動念，照山萬重源。"]'),
('a630a4e0-d48a-4c21-9b16-d04a15f7a68e','哀教','皎然','唐','唐诗','tang','','[]','本師不得已，強爲我著書。',48,'全唐诗/poet.tang.45000.json','["本師不得已，強爲我著書。", "知盡百慮遣，名存萬象拘。", "如何工言子，終日論虛無。", "伊人獨冥冥，時人以爲愚。"]'),
('ad05f3da-4b0a-47f7-8521-9ccb311f94ae','聞鐘','皎然','唐','唐诗','tang','','[]','古寺寒山上，遠鐘揚好風。',36,'全唐诗/poet.tang.45000.json','["古寺寒山上，遠鐘揚好風。", "聲餘月樹動，響盡霜天空。", "永夜一禪子，泠然心境中。"]'),
('386d0201-97d3-491c-8c69-2ffa31bacd83','溪上月','皎然','唐','唐诗','tang','','[]','秋水月娟娟，初生色界天。',36,'全唐诗/poet.tang.45000.json','["秋水月娟娟，初生色界天。", "蟾光散浦溆，素影動淪漣。", "何事無心見，虧盈向夜禪。"]'),
('2d90ebdd-324e-40ef-9365-70b499cea039','山雪','皎然','唐','唐诗','tang','','[]','夕陽在西峰，疊翠縈殘雪。',36,'全唐诗/poet.tang.45000.json','["夕陽在西峰，疊翠縈殘雪。", "狂風卷絮迴，驚猨攀玉折。", "何意山中人，誤報山花發。"]'),
('92cc0e07-5194-4e9f-950c-2f9ed7a62ab0','江上風','皎然','唐','唐诗','tang','','[]','江風西復東，飄暴忽何窮。',56,'全唐诗/poet.tang.45000.json','["江風西復東，飄暴忽何窮。", "初生虛無際，稍起蕩漾中。", "應吹夏口檣竿折，定蹙湓城浪花咽。", "今朝莫怪沙岸明，昨夜聲狂卷成雪。"]'),
('f50085c3-cb5a-4c1f-8b96-31fde4920e2c','山雨','皎然','唐','唐诗','tang','','[]','一片雨，山半晴。',52,'全唐诗/poet.tang.45000.json','["一片雨，山半晴。", "長風吹落西山上，滿樹蕭蕭心耳清。", "雲鶴驚亂下，水香凝不然。", "風迴雨定芭蕉濕，一滴時時入晝禪。"]'),
('9f0efffd-61e5-412c-9804-789f66959bbc','問遙山禪老','皎然','唐','唐诗','tang','','[]','天與松子壽，獨飲日月精。',84,'全唐诗/poet.tang.45000.json','["天與松子壽，獨飲日月精。", "復令顏子賢，胡爲夭其生。", "吾將尋河源，上天問天何不平。", "我將詰仙老，大道無私誰強名。", "仙老難逢天不近，世人何人解應盡。", "明朝欲向翅頭山，問取禪公此義還。"]'),
('91d5e4e6-c84a-438d-b8e1-21b9fd7ef71d','禪思','皎然','唐','唐诗','tang','','[]','真我性無主，誰爲塵識昏。',96,'全唐诗/poet.tang.45000.json','["真我性無主，誰爲塵識昏。", "奈何求其本，若拔大木根。", "妄以一念動，勢如千波翻。", "傷哉子桑扈，蟲臂徒虛言。", "神威興外論，宗邪生異源。", "空何妨色在，妙豈廢身存。", "寂滅本非寂，諠譁曾未諠。", "嗟嗟世上禪，不共智者論。"]'),
('491b93f3-1668-4472-ab79-9c71145eefd1','支公詩','皎然','唐','唐诗','tang','','[]','支公養馬復養鶴，率性無機多脫畧。',80,'全唐诗/poet.tang.45000.json','["支公養馬復養鶴，率性無機多脫畧。", "天生支公與凡異，凡情不到支公地。", "得道繇來天上仙，爲僧却下人間寺。", "道家諸子論自然，此公唯許逍遙篇。", "山陰詩友喧四座，佳句縱橫不廢禪。"]'),
('882a0ebe-aac5-43ee-8624-0c3cf9e0a00d','述夢','皎然','唐','唐诗','tang','','[]','夢中歸見西陵雪，渺渺茫茫行路絕。',48,'全唐诗/poet.tang.45000.json','["夢中歸見西陵雪，渺渺茫茫行路絕。", "覺來還在剡東峰，鄉心繚繞愁夜鐘。", "寺北禪岡猶記得，夢歸長見山重重。"]'),
('8b882bbc-71d0-4c8a-b54a-5c6ac07663bf','赤松','皎然','唐','唐诗','tang','','[]','緣岸蒙籠出見天，晴沙瀝瀝水濺濺。',32,'全唐诗/poet.tang.45000.json','["緣岸蒙籠出見天，晴沙瀝瀝水濺濺。", "何處羽人長洗藥，殘花無數逐流泉。"]'),
('7ea657a9-5995-425b-803d-06ac1e9ae43e','戲題松樹','皎然','唐','唐诗','tang','','[]','爲愛松聲聽不足，每逢松樹遂忘還。',32,'全唐诗/poet.tang.45000.json','["爲愛松聲聽不足，每逢松樹遂忘還。", "翛然此外更何事，笑向閑雲似我閑。"]'),
('99f504d7-10b6-413d-ae97-7a1661073a0b','戲題二首 一','皎然','唐','唐诗','tang','','[]','看飲逢歌日屢曛，我身何似繫浮雲。',32,'全唐诗/poet.tang.45000.json','["看飲逢歌日屢曛，我身何似繫浮雲。", "時人不解野僧意，歸去溪頭作鳥羣。"]'),
('6043558f-9f5b-4088-8b8c-745cc729a923','戲題二首 二','皎然','唐','唐诗','tang','','[]','喧喧共在是非間，終日誰知我自閑。',32,'全唐诗/poet.tang.45000.json','["喧喧共在是非間，終日誰知我自閑。", "偶客狂歌何所爲，欲於人事強相關。"]'),
('63d517da-12c9-4384-a682-2036be0a8f55','雜寓興','皎然','唐','唐诗','tang','','[]','嗟嗟號呶子，世稱謫僊儔。',120,'全唐诗/poet.tang.45000.json','["嗟嗟號呶子，世稱謫僊儔。", "媚俗被鮫綃，欺天薦昫脩。", "奔景謂可致，馳齡言易流。", "燕昭昧往事，嬴政亡前籌。", "三山果不見，九僊忽悠悠。", "君看牛山樂，君見麋浦遊。", "昨日千金子，聯綿成古丘。", "吾將攬明月，照爾生死流。", "至樂享爰居，慙貽達者尤。", "冥冥光塵內，機喪成海漚。"]'),
('d7afccab-7a02-4075-813c-d8dce3eb01e2','雜興六首 一','皎然','唐','唐诗','tang','','[]','吾觀談天客，工言喪其精。',60,'全唐诗/poet.tang.45000.json','["吾觀談天客，工言喪其精。", "萬物資廣庇，此中何有情。", "若爲昧顏跖，修短怨太清。", "高論讓鄒子，放詞徵屈生。", "請從象外推，至論尤明明。"]'),
('f9471382-2f72-4409-b7b5-7e10909b5019','雜興六首 二','皎然','唐','唐诗','tang','','[]','短齡役長世，擾擾悟不早。',76,'全唐诗/poet.tang.45000.json','["短齡役長世，擾擾悟不早。", "嬪女身後空，歡娛夢中好。", "從教西陵樹，千載傷懷抱。", "鶴駕何冥冥，鼇洲去浩浩。", "柔顏感三花，凋發悲蔓草。", "月中伐桂人是誰，翻使年年不衰老。"]'),
('c320b71e-2a0e-4b3b-bd6b-c9843bc7ee05','雜興六首 三','皎然','唐','唐诗','tang','','[]','誰高齊公子，泣聽雍門琴。',24,'全唐诗/poet.tang.45000.json','["誰高齊公子，泣聽雍門琴。", "死且何足傷，殊非達人心。"]'),
('ee47c307-2b14-4a7f-b10b-3ec948ad6c32','雜興六首 四','皎然','唐','唐诗','tang','','[]','獨高庭中鶴，意遠貴氛埃。',24,'全唐诗/poet.tang.45000.json','["獨高庭中鶴，意遠貴氛埃。", "有時青冥遊，顧我還下來。"]'),
('782de211-6463-4a98-81cb-0736555c285b','雜興六首 五','皎然','唐','唐诗','tang','','[]','白雲琅玕色，一片生虛無。',24,'全唐诗/poet.tang.45000.json','["白雲琅玕色，一片生虛無。", "此物若無心，若何卷還舒。"]'),
('47edc7e9-a2c5-4de2-aaaf-d21d57740345','雜興六首 六','皎然','唐','唐诗','tang','','[]','疎散遂吾性，栖山更無機。',36,'全唐诗/poet.tang.45000.json','["疎散遂吾性，栖山更無機。", "寥寥高松下，獨有閑雲歸。", "精意不可道，冥然還掩扉。"]'),
('5a1757d3-f95c-47b3-9951-523538ecd61e','偶然五首 一','皎然','唐','唐诗','tang','','[]','樂禪心似蕩，吾道不相妨。',24,'全唐诗/poet.tang.45000.json','["樂禪心似蕩，吾道不相妨。", "獨悟歌還笑，誰言老更狂。"]'),
('3879732f-c0c2-47a0-9fa3-b0a206bdbc89','偶然五首 二','皎然','唐','唐诗','tang','','[]','偶然寂無喧，吾了心性源。',24,'全唐诗/poet.tang.45000.json','["偶然寂無喧，吾了心性源。", "可嫌蟲食木，不笑鳥能言。"]'),
('02acfec5-03e9-49af-b5e4-c152825dd52f','偶然五首 三','皎然','唐','唐诗','tang','','[]','隱心不隱跡，却欲住人寰。',36,'全唐诗/poet.tang.45000.json','["隱心不隱跡，却欲住人寰。", "欠樹移春樹，無山看畫山。", "居喧我未錯，真意在其間。"]'),
('f29f9b32-c701-48c3-8e06-9407d2cc25f5','偶然五首 四','皎然','唐','唐诗','tang','','[]','虜語嫌不學，胡音從不翻。',24,'全唐诗/poet.tang.45000.json','["虜語嫌不學，胡音從不翻。", "說禪顛倒是，樂殺金王孫。"]'),
('f7dd7349-0416-4fc8-b53d-0852f0203054','偶然五首 五','皎然','唐','唐诗','tang','','[]','真隱須無矯，忘名要似愚。',24,'全唐诗/poet.tang.45000.json','["真隱須無矯，忘名要似愚。", "只將兩條事，空却漢潛夫。"]'),
('3bcd1f4a-bc89-4a92-8d79-ef19bd749b88','問天','皎然','唐','唐诗','tang','','[]','天公何時有，談者皆不經。',24,'全唐诗/poet.tang.45000.json','["天公何時有，談者皆不經。", "誰道賢人死，今爲傅說星。"]'),
('16981157-528b-44dd-99cc-19ce8bcd0aea','寓言','皎然','唐','唐诗','tang','','[]','吾道本無我，未曾嫌世人。',24,'全唐诗/poet.tang.45000.json','["吾道本無我，未曾嫌世人。", "如今到城市，彌覺此心真。"]'),
('51b8187d-90ba-42e9-8dfc-ad713c764a6c','前溪作','皎然','唐','唐诗','tang','','[]','春歌已寂寂，古水自涓涓。',24,'全唐诗/poet.tang.45000.json','["春歌已寂寂，古水自涓涓。", "徒誤時人輩，傷心作逝川。"]'),
('d995d252-549e-40f9-9c51-2bb792ed9354','戲作','皎然','唐','唐诗','tang','','[]','乞我百萬金，封我異姓王。',24,'全唐诗/poet.tang.45000.json','["乞我百萬金，封我異姓王。", "不如獨悟時，大笑放清狂。"]'),
('c6513f4d-5abd-4043-80cb-7b9567995dab','浮雲三章 一','皎然','唐','唐诗','tang','','[]','浮雲浮雲，集於扶桑。',40,'全唐诗/poet.tang.45000.json','["浮雲浮雲，集於扶桑。", "扶桑茫茫，日暮之光。", "匪日之暮，浮雲之汙。", "嗟我懷人，憂心如蠹。"]'),
('c988c1d2-dc41-441e-ac83-39bf1441b663','浮雲三章 二','皎然','唐','唐诗','tang','','[]','浮雲浮雲，集於咸池。',40,'全唐诗/poet.tang.45000.json','["浮雲浮雲，集於咸池。", "咸池微微，日昃之時。", "匪日之昃，浮雲之惑。", "嗟我懷人，憂心如織。"]'),
('71677a05-d3f4-4e2c-82a1-6d2212d84729','浮雲三章 三','皎然','唐','唐诗','tang','','[]','浮雲浮雲，集於高舂。',42,'全唐诗/poet.tang.45000.json','["浮雲浮雲，集於高舂。", "高舂濛濛，日夕之容。", "匪日之夕，浮雲之積。", "嗟我懷人，憂心如[惄]。"]'),
('7ff78979-1ada-457d-906b-d0aa39930a5d','寓言','皎然','唐','唐诗','tang','','[]','人生百年我過半，天生才定不可換。',32,'全唐诗/poet.tang.45000.json','["人生百年我過半，天生才定不可換。", "東海釣鼇鼇不食，南山坐石石欲爛。"]'),
('4fb18e55-2551-4e0c-a120-3b2f469fd78b','若邪春興','皎然','唐','唐诗','tang','','[]','春生若邪水，雨後漫流通。',48,'全唐诗/poet.tang.45000.json','["春生若邪水，雨後漫流通。", "芳草行無盡，清源去不窮。", "野煙迷極浦，斜日起微風。", "數處乘流望，依稀似剡中。"]'),
('8ccb3c7e-54b1-4d83-aae8-cc761e4354c7','晨登樂遊原望終南積雪','皎然','唐','唐诗','tang','','[]','凌晨擁弊裘，徑上古原頭。',72,'全唐诗/poet.tang.45000.json','["凌晨擁弊裘，徑上古原頭。", "雪霽山疑近，天高思若浮。", "瓊峰埋積翠，玉嶂掩飛流。", "曜彩含朝日，搖光奪寸眸。", "寒空標瑞色，爽氣襲皇州。", "清眺何人得，終當獨再遊。"]'),
('d95317f6-6e5d-4942-b589-01c5468f332f','送商季臯','皎然','唐','唐诗','tang','','[]','比來知爾有詩名，莫恨東歸學未成。',32,'全唐诗/poet.tang.45000.json','["比來知爾有詩名，莫恨東歸學未成。", "新豐有酒爲我飲，消取故園傷別情。"]'),
('91e038db-986c-4ca4-93bb-f9455fa6250b','弔靈均詞','皎然','唐','唐诗','tang','','[]','昧天道兮有無，聽汨渚兮躊躇。',154,'全唐诗/poet.tang.45000.json','["昧天道兮有無，聽汨渚兮躊躇。", "期靈均兮若存，問神理兮何如。", "願君精兮爲月，出孤影兮示予。", "天獨何兮有君，君在萬兮不羣。", "既冰心兮皎潔，上問天兮胡不聞。", "天不聞，神莫覩。", "若雲冥冥兮雷霆怒，蕭條杳眇兮餘草莽。", "古山春兮爲誰，今猨哀兮何思。", "風激烈兮楚竹死，國殤人悲兮雨颸颸，雨颸颸兮望君时。", "光芒蕩漾兮化爲水，萬古忠貞兮徒爾爲。"]'),
('3fc4419e-d44c-457c-93bc-4f5850e012ed','步虛詞','皎然','唐','唐诗','tang','','[]','予因覽真訣，遂感西城君。',72,'全唐诗/poet.tang.45000.json','["予因覽真訣，遂感西城君。", "玉笙下青冥，人間未曾聞。", "日華鍊精魄，皎皎無垢氛。", "謂我有僊骨，且令餌氤氳。", "俯仰媿靈顏，願隨鸞鵠羣。", "俄然動風馭，縹渺歸青雲。"]'),
('61be085b-5ba1-4a7c-bfe8-9a37c6d608b5','奉應顏尚書真卿觀玄真子置酒張樂舞破陣畫洞庭三山歌','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','道流迹異人共驚，寄向畫中觀道情。',192,'全唐诗/poet.tang.45000.json','["道流迹異人共驚，寄向畫中觀道情。", "如何萬象自心出，而心澹然無所營。", "手援毫，足蹈節，披縑灑墨稱麗絕。", "石文亂點急管催，雲態徐揮慢歌發。", "樂縱酒酣狂更好，攢峰若雨縱橫埽。", "尺波澶漫意無涯，片嶺崚嶒勢將倒。", "盻睞方知造境難，象忘神遇非筆端。", "昨日幽奇湖上見，今朝舒卷手中看。", "興餘輕拂遠天色，曾向峰東海邊識。", "秋空暮景颯颯容，翻疑是真畫不得。", "顏公素高山水意，常恨三山不可至。", "賞君狂畫忘遠遊，不出軒墀坐蒼翠。"]'),
('15f50b8f-3352-47f1-9cb8-265edb790477','荅韋山人隱起龍文藥瓢歌','皎然','唐','唐诗','tang','','[]','野人藥瓢天下絕，全如渾金割如月。',176,'全唐诗/poet.tang.45000.json','["野人藥瓢天下絕，全如渾金割如月。", "彪炳文章智使然，生成在我不在天。", "若言有物不繇物，何意中虛道性全。", "韋生能詩兼好異，獲此靈瓢遠相遺。", "仙侯玉帖人漫傳，若士青囊世何秘。", "一捧一開如見君，藥盛五色香氛氳。", "背上驪龍蟠不睡，張鱗擺頷生風雲。", "世人強知金丹道，默僊不成穢僊老。", "年少紛如陌上塵，不見吾瓢盡枯槁。", "聊將繫肘步何輕，便有三山孤鶴情。", "東方小兒乏此物，遂令僊籍獨無名。"]'),
('50704141-b942-45c4-9e93-45716a788740','桃花石枕歌贈康從事','皎然','唐','唐诗','tang','','[]','卞山幽石產奇璞，荆人至死採不著。',192,'全唐诗/poet.tang.45000.json','["卞山幽石產奇璞，荆人至死採不著。", "何人琢枕持贈君，片片桃花開未落。", "劒工見兮可爲劒，玉工辨兮知非石。", "至寶繇來覽者稀，今君獨鑒應欲惜。", "何辭售與章天真，幸得提攜近玉人。", "可中棄置君不顧，天生秀色徒璘玢。", "四座喧喧爭目悅，巧過造化稱一絕。", "莫言昨日因錯磨，看取從來無點缺。", "六月江南暑未闌，一尺花冰試枕看。", "高窗正午風颯變，室中不減春天寒。", "主人所重重枕德，文章外飾徒相惑。", "更有堅貞不易心，與君天下爲士則。"]'),
('7e93144a-6b85-4f1e-b619-9b6776d1a2ff','張伯英草書歌','皎然','唐','唐诗','tang','','[]','伯英死後生怕高，朝看手把山中毫。',176,'全唐诗/poet.tang.45000.json','["伯英死後生怕高，朝看手把山中毫。", "先賢草律我草狂，風雲陣發愁鍾王。", "須臾變態皆自我，象形類物無不可。", "閬風遊雲千萬朵，驚龍蹴踏飛欲墮。", "更覩鄧林花落朝，狂風亂攪何飄飄。", "有時凝然筆空握，情在寥天獨飛鶴。", "有時取勢氣更高，憶得春江千里濤。", "張生奇絕難再遇，草罷臨風展輕素。", "陰慘陽舒如有道，鬼狀魑容若可懼。", "黃公酒壚興偏入，阮籍不嗔嵇亦顧。", "長安酒牓醉後書，此日騁君千里步。"]'),
('853e4d9d-d1e5-4a68-8432-33048877cc31','寒栖子歌','皎然','唐','唐诗','tang','','["\u5e90\u5c71"]','君在廬山不知羣，有疑是鶴又是雲。',208,'全唐诗/poet.tang.45000.json','["君在廬山不知羣，有疑是鶴又是雲。", "生死塵埃汙不得，眼前榮利徒紛紛。", "今日惠然來訪我，酒榼書囊肩背荷。", "拂除衣上餌煙霞，昨夜胥門宿蔡家。", "天然不飲亦不食，拋名換姓覓不得。", "且向人間作酒僊，不肯將身生羽翼。", "停形爲餌天地根，世人皆死我獨存。", "洗慮因吞清明籙，世人皆貪我常足。", "栖子妙今道已成，手把玄樞心運冥。", "能令鬼哭神效靈，身如飄風不可絆。", "朝遊崆峒夕汗漫，向來坐客猶未散。", "忽憶羅浮欲去時，遙指孤雲作路岐。", "海上仙遊不可見，人間日落空桑枝。"]'),
('8151068a-111c-4566-8baf-ec3d41d23356','翔隼歌送王端公','皎然','唐','唐诗','tang','','[]','古人賞神駿，如何秋隼擊。',124,'全唐诗/poet.tang.45000.json','["古人賞神駿，如何秋隼擊。", "獨立高標望霜翮，應看天宇如咫尺。", "低迴拂地凌風翔，鵬雛敢下鴈斷行。", "晴空四顧忽不見，有時獨出青霞傍。", "窮陰萬里落寒日，氣殺草枯增奮逸。", "雲塞斜飛攪葉迷，雪天直上穿花疾。", "見君高情有所屬，贈別因歌翔隼曲。", "離亭慘慘客散時，歌盡路長意不足。"]'),
('42ee203b-9152-4f47-8101-51104acab4d5','白雲歌寄陸中丞使君長源','皎然','唐','唐诗','tang','','[]','一見西山雲，使人情意遠。',232,'全唐诗/poet.tang.45000.json','["一見西山雲，使人情意遠。", "憑高發詠何超遙，道妙如君有舒卷。", "縈空疊景多麗容，衆峰峰上自爲峰。", "潔白不繇陰雨積，高明肯共雜煙重。", "萬物有形皆有著，白雲有形無繫縛。", "黃金被爍玉亦瑕，一片飄然汙不著。", "或逢天上或人間，人自營營雲自閑。", "忽爾飛來暫爲侶，忽然飛去莫能攀。", "逸民對雲效高致，禪子逢雲增道意。", "白雲遇物無偏頗，自是人心見同異。", "閶闔天門宜曙看，爲纓作蓋擁千官。", "從龍合沓臨清暑，就日逶迤繞露寒。", "誰憐西山雲，亭亭處幽絕。", "坐石長看非我羈，手中欲攬待君說。", "貞白先生那得知，只向空山自怡悅。"]'),
('e53dd574-3be2-45ff-b260-c379d2defc6a','裴端公使君清席賦得青桂歌送徐長史','皎然','唐','唐诗','tang','','[]','昔年攀桂爲留人，今朝攀桂送歸客。',96,'全唐诗/poet.tang.45000.json','["昔年攀桂爲留人，今朝攀桂送歸客。", "秋風桃李搖落盡，爲君青青伴松柏。", "謝公南樓送客還，高歌桂樹凌寒山。", "應憐獨秀空林上，空賞敷華積雪間。", "昨夜一枝生在月，嬋娟可望不可折。", "若爲天上堪贈行，徒使亭亭照離別。"]'),
('3ca0bb55-8e8a-4a81-ba9c-f678c7f51760','周長史昉畫毗沙門天王歌','皎然','唐','唐诗','tang','','[]','長史畫神獨感神，高步區中無兩人。',160,'全唐诗/poet.tang.45000.json','["長史畫神獨感神，高步區中無兩人。", "雅而逸，高且真，形生虛無忽可親。", "降魔大戟縮在手，倚天長劒橫諸紳。", "慈威示物雖凜凜，在德無秋唯有春。", "吾知真象本非色，此中妙用君心得。", "苟能下筆合神造，誤點一點亦爲道。", "寫出霜縑可舒卷，何人應識此情遠。", "秋齋清寂無外物，盥手焚香聊自展。", "憶昔胡兵圍未解，感得此神天上下。", "至今雲旗圖我形，爲君一顧煙塵清。"]'),
('d1631d0a-1ab3-49e4-9b18-b77d538961a5','奉和顏魯公真卿落玄真子舴艋舟歌','皎然','唐','唐诗','tang','','[]','滄浪子後玄真子，冥冥釣隱江之汜。',141,'全唐诗/poet.tang.45000.json','["滄浪子後玄真子，冥冥釣隱江之汜。", "刳木新成舴艋舟，諸侯落舟自茲始。", "得道身不繫，無機舟亦閑。", "從水遠逝兮任風還，朝五湖兮夕三山。", "停綸乍入芙蓉浦，擊汰時過明月灣。", "太公取璜我不取，龍伯釣鼇我不釣。", "竹竿嫋嫋魚簁簁，此中自得還自笑。", "汗漫一遊何可期，後來誰遇冰雪姿。", "上古初聞出堯世，今朝還見在堯時。"]'),
('d0e20fd2-4917-4eeb-9bb1-27f12313ea48','鄭容全成蛟形木机歌','皎然','唐','唐诗','tang','','[]','萬物貴天然，天然不可得。',148,'全唐诗/poet.tang.45000.json','["萬物貴天然，天然不可得。", "渾樸無勞剞劂工，幽姿自可蛟龍質。", "欲騰未去何翩翩，揚袂爭前誰敢拂。", "可中風雨一朝至，還應不是池中物。", "蒼山萬重採一枝，形如器車生意奇。", "風號雨噴心不折，衆木千叢君獨知。", "高人心，多越格。", "有時就月吟春風，持來座右驚神客。", "愛君開閤江之濱，白雲黃鶴長相親。", "南郭子綦我不識，非君獨是是何人。"]'),
('4f9eba2b-be41-4cb3-ad59-c90b2cdba294','奉同顏使君真卿清風樓賦得洞庭歌送吳鍊師歸林屋洞','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','名山洞府到金庭，三十六洞稱最靈。',192,'全唐诗/poet.tang.45000.json','["名山洞府到金庭，三十六洞稱最靈。", "不有古仙啓其秘，今日安知靈寶經。", "中山鍊師栖白雲，道成仙秩號元君。", "三千甲子朝玉帝，世上如今名始聞。", "吐納青牙養肌髮，花冠玉舃何高潔。", "不聞天上來謫仙，自是人間授真訣。", "吳興太守道家流，仙師遠放清風樓。", "應將內景還飛去，且從分風當此留。", "湖之山兮樓上見，山冥冥兮水悠悠。", "世人不到君自到，縹緲仙都誰與儔。", "黃鶴孤雲天上物，物外飄然自天匹。", "一別千年未可期，仙家不數人間日。"]'),
('0830d6a3-d41e-4e82-9dee-73d31e69b61f','戛銅椀爲龍吟歌','皎然','唐','唐诗','tang','','[]','逸僧戛椀爲龍吟，世上未曾聞此音。',206,'全唐诗/poet.tang.45000.json','["逸僧戛椀爲龍吟，世上未曾聞此音。", "一從太尉房公賞，遂使秦人傳至今。", "初戛徐徐聲漸顯，樂音不管何人[辨]。", "似出龍泉萬丈底，乍怪聲來近而遠。", "未必全繇戛者功，真生虛無非椀中。", "寥亮掩清笛，縈迴凌細風。", "遙聞不斷在煙杪，萬籟無聲天境空。", "乍向天台宿華頂，秋宵一吟更清迥。", "能令聽者易常性，憂人忘憂躁人靜。", "今日鏗鍠江上聞，蛟螭奔飛如得羣。", "聲過陰嶺恐成雨，響駐晴天將起雲。", "坐來吟盡空江碧，却尋向者聽無迹。", "人生萬事將此同，暮賤朝榮動還寂。"]'),
('41fca742-a88c-4a20-8dfe-a48d2d6f7d43','飲茶歌誚崔石使君','皎然','唐','唐诗','tang','','[]','越人遺我剡溪茗，採得金牙爨金鼎。',138,'全唐诗/poet.tang.45000.json','["越人遺我剡溪茗，採得金牙爨金鼎。", "素瓷雪色縹沫香，何似諸仙瓊蘂漿。", "一飲滌昏寐，情來朗爽滿天地。", "再飲清我神，忽如飛雨灑輕塵。", "三飲便得道，何須苦心破煩惱。", "此物清高世莫知，世人飲酒多自欺。", "愁看畢卓甕間夜，笑向陶潛籬下時。", "崔侯啜之意不已，狂歌一曲驚人耳。", "孰知茶道全爾真，唯有丹丘得如此。"]'),
('43cac04d-45ad-4a67-a715-f2d310cd6faa','買藥歌送楊山人','皎然','唐','唐诗','tang','','[]','華陰少年何所希，欲餌丹砂化骨飛。',128,'全唐诗/poet.tang.45000.json','["華陰少年何所希，欲餌丹砂化骨飛。", "江南藥少淮南有，暫別胥門上京口。", "京口斜通江水流，斐回應上青山頭。", "夜驚潮沒鸕鶿堰，朝看日出芙蓉樓。", "搖蕩春風亂帆影，片雲無數是揚州。", "揚州喧喧賣藥市，浮俗無由識仙子。", "河間姹女直千金，紫陽夫人服不死。", "吾於此道復何如，昨朝新得蓬萊書。"]'),
('a43169e8-7e6e-4b18-850d-09f64232409a','薛卿教長行歌','皎然','唐','唐诗','tang','','[]','桂陽仙柳道家說，昔傳蘇君今是薛。',192,'全唐诗/poet.tang.45000.json','["桂陽仙柳道家說，昔傳蘇君今是薛。", "聊將握槊偶時人，便被人間稱冠絕。", "黃楊文局龜螭蟠，琢成骰子雙琅玕。", "初疑月破雲中墮，復怪星移指下攢。", "誰識兵奇勢可保，坐看將軍上一道。", "有時彩王非所希，笑擊單于出重圍。", "鳧驚隼擊疾若飛，左顧右盻生光輝。", "家本聯姻漢戚里，身是長安貴公子。", "名高藝絕何翩翩，幾迴決勝君王前。", "扈遊長樂與祈年，人望青雲白日邊。", "謫宦江南歲陰晚，還將此道聊自遣。", "繇來君子行最長，予亦知君寄心遠。"]'),
('efea89d2-59ff-4599-af6d-a2801c8ff62e','桃花石枕歌送安吉康丞','皎然','唐','唐诗','tang','','[]','君吏桃州尚奇跡，桃州採得桃花石。',128,'全唐诗/poet.tang.45000.json','["君吏桃州尚奇跡，桃州採得桃花石。", "爛疑朝日照已舒，含似春風吹未坼。", "珪璋特達世所珍，吾知此物亦其倫。", "應羨花開不凋悴，應嘉玉片無緇磷。", "立性堅剛平若砥，君子偏將交道比。", "何人亦秉堅剛姿，吾見君心得如此。", "君心所好我獨知，別多見少長相思。", "從來賞翫安左右，萬里提攜君莫辭。"]'),
('21cd5872-8790-43cb-b694-390d4bee7f25','賦得吳王送女潮歌送李判官之河中府','皎然','唐','唐诗','tang','','[]','見說吳王送女時，行宮直到荆溪口。',160,'全唐诗/poet.tang.45000.json','["見說吳王送女時，行宮直到荆溪口。", "溪上千年送女潮，爲感吳王至今有。", "乃知昔人繇志誠，流水無情翻有情。", "平波忽起二三尺，此上疑與神仙宅。", "今人猶望荆之湄，長令望者增所思。", "吳王已歿女不返，潮水無情那有期。", "溪草何草號帝女，溪竹何竹號湘妃。", "靈濤旦暮自堪傷，的爍嬋娟又爭發。", "客歸千里自茲始，覽古高歌感行子。", "不知別後相見期，君意何如此潮水。"]'),
('b1670ba6-08bd-4517-9ed4-8ae750204488','觀李中丞洪二美人唱歌軋箏歌','皎然','唐','唐诗','tang','','[]','君家雙美姬，善歌工箏人莫知。',260,'全唐诗/poet.tang.45000.json','["君家雙美姬，善歌工箏人莫知。", "軋用蜀竹弦楚絲，清哇宛轉聲相隨。", "夜靜酒闌佳月前，高張水引何淵淵。", "美人矜名曲不誤，蹙響時時如迸泉。", "趙琴素所[嘉]，齊謳世稱絕。", "箏歌一動凡音輟，凝弦且莫停金罍。", "淫聲已闋雅聲來，遊魚噞喁鶴裴回，主人高情始爲開。", "高情放浪出常格，偶世有名道無跡。", "勳業先登上將科，文章已冠諸人籍。", "每笑石崇無道情，輕身重色禍亦成。", "君有佳人當禪伴，於中不廢學無生。", "愛君天然性寡欲，家貧祿薄常知足。", "謫官無慍如古人，交道忘言比前躅。", "不意全家萬里來，湖中再見春山綠。", "吳興公舍幽且閑，何妨寄隱在其間。", "時議名齊謝太傅，更看攜妓似東山。"]'),
('d82ba80c-aea7-4745-8113-a3632baf5248','陳氏童子草書歌','皎然','唐','唐诗','tang','','[]','書家孺子有奇名，天然大草令人驚。',160,'全唐诗/poet.tang.45000.json','["書家孺子有奇名，天然大草令人驚。", "僧虔老時把筆法，孺子如今皆暗合。", "飆揮電灑眼不及，但覺毫端鳴颯颯。", "有時作點險且能，太行片石看欲崩。", "偶然長掣濃入燥，少室枯松欹不倒。", "夏室炎炎少人歡，山軒日色在闌干。", "桐花飛盡子規思，主人高歌興不至。", "濁醪不飲嫌昏沈，欲翫草書開我襟。", "龍爪狀奇鼠鬚銳，水牋白皙越人惠。", "王家小令草最狂，爲予灑出驚騰勢。"]'),
('7c4471c4-9b26-4c3c-88c0-9c4bdfaab437','飲茶歌送鄭容','皎然','唐','唐诗','tang','','[]','丹丘羽人輕玉食，採茶飲之生羽翼。',100,'全唐诗/poet.tang.45000.json','["丹丘羽人輕玉食，採茶飲之生羽翼。", "名藏仙府世空知，骨化雲宮人不識。", "雲山童子調金鐺，楚人茶經虛得名。", "霜天半夜芳草折，爛漫緗花啜又生。", "賞君此茶祛我疾，使人胸中蕩憂慄。", "日上香罏情未畢，醉踏虎溪雲，高歌送君出。"]'),
('a209fb14-de5a-42d6-8555-33f71a0cab7f','花石長枕歌荅章居士贈','皎然','唐','唐诗','tang','','[]','楚山有石郢人琢，琢成長枕知是玉。',152,'全唐诗/poet.tang.45000.json','["楚山有石郢人琢，琢成長枕知是玉。", "全疑冰片坐恐銷，間發花藂驚不足。", "贈予比之金琅玕，瓊花爛熳浮席端。", "吾師道吾不執寶，今日感君因執看。", "試叩鏗然應清律，纖塵不留蠅敢拂。", "萬物皆因造化資，如何獨負清貞質。", "南山有雲鵠在空，長松爲我生涼風。", "高友朗詠樂其中，行住四儀皆道意。", "不學小乘一曲士，唯將此物安座隅，取次閑眠有禪味。"]'),
('4517e291-ba61-49b1-b490-1753020ca5c3','觀王右丞維滄洲圖歌','皎然','唐','唐诗','tang','','[]','滄洲誤是真，萋萋忽盈視。',104,'全唐诗/poet.tang.45000.json','["滄洲誤是真，萋萋忽盈視。", "便有春渚情，褰裳掇芳芷。", "颯然風至草不動，始悟丹青得如此。", "丹青變化不可尋，翻空作有移人心。", "猶言雨色斜拂座，乍似水涼來入襟。", "滄洲說近三湘口，誰知卷得在君手。", "披圖擁褐臨水時，翛然不異滄洲臾。"]'),
('b7cb0165-deb9-45a5-b298-988984481f33','洞庭山維諒上人院階前孤生橘樹歌','皎然','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭仙山但生橘，不生凡木與梨栗。',152,'全唐诗/poet.tang.45000.json','["洞庭仙山但生橘，不生凡木與梨栗。", "真子無私自不栽，感得一株階下出。", "細葉繁枝委露新，四時常綠不關春。", "若言此物無道性，何意孤生來就人。", "二月三月山初暖，最愛低簷數枝短。", "白花不用烏銜來，自有風吹手中滿，九月十月爭破顏。", "金實離離色殷殷，一夜天晴香滿山。", "天生珍木異於俗，俗士來逢不敢觸。", "清陰獨步禪起時，徙倚前看看不足。"]'),
('52031657-fa7f-46a3-81e9-690298f6995d','春夜賦得漉水囊歌送鄭明府','皎然','唐','唐诗','tang','','[]','吳縑楚練何白皙，居士持來遺禪客。',128,'全唐诗/poet.tang.45000.json','["吳縑楚練何白皙，居士持來遺禪客。", "禪客能裁漉水囊，不用衣工秉刀尺。", "先師遺我式無缺，一濾一翻心敢賒。", "夕望東峰思漱盥，曨曨斜月懸燈紗。", "徙倚花前漏初斷，白猨爭嘯驚禪伴。", "玉瓶徐瀉賞涓涓，濺著蓮衣水珠滿。", "因識仁人爲宦情，還如漉水愛蒼生。", "聊歌一曲與君別，莫忘寒泉見底清。"]'),
('6ae4a38c-eda3-43c6-a303-a231c1afa9db','湛處士枸杞架歌','皎然','唐','唐诗','tang','','[]','天生靈草生靈地，誤生人間人不貴。',160,'全唐诗/poet.tang.45000.json','["天生靈草生靈地，誤生人間人不貴。", "獨君井上有一根，始覺人間衆芳草。", "拖線垂絲宜曙看，裴回滿架何珊珊。", "春風亦解愛此物，褭褭時來傍香實。", "濕雲綴葉擺不去，翠羽銜花驚畏失。", "肯羨孤松不凋色，皇天正氣肅不得。", "我獨全生異此輩，順時榮落不相背。", "孤松自被斧斤傷，獨我柔枝保無害。", "黃油酒囊石棊局，吾羨湛生心出俗。", "擷芳生影風灑懷，其致翛然此中足。"]'),
('53c20649-82fb-4e0b-94b1-0b1e9425b7b8','觀裴秀才松石障歌','皎然','唐','唐诗','tang','','[]','誰工此松唯拂墨，巧思丹青營不得。',144,'全唐诗/poet.tang.45000.json','["誰工此松唯拂墨，巧思丹青營不得。", "初寫松梢風正生，此中勢與真松爭。", "高柯細葉動颯颯，乍聽幽飀如有聲。", "左右雙松更奇絕，龍鱗麈尾仍半折。", "經春寒色聚不散，逼座陰陰將下雪。", "荆門石狀凌璵璠，蹙成數片倚松根。", "何年蒨蒨苔黏跡，幾夜潺潺水擊痕。", "裴生詩家後來客，爲我開圖翫松石。", "對之自有高世心，何事勞君上山屐。"]'),
('db20c6f2-4d08-4acf-a055-5fe1a4ff4af8','送顧處士歌','皎然','唐','唐诗','tang','','[]','吳門顧子予早聞，風貌真古誰似君。',160,'全唐诗/poet.tang.45000.json','["吳門顧子予早聞，風貌真古誰似君。", "人中黃憲與顏子，物表孤高將片雲。", "性背時人高且逸，平生好古無儔匹。", "醉書在篋稱絕倫，神畫開廚怕飛出。", "謝氏檀郎亦可儔，道情還似我家流。", "安貧日日讀書坐，不見將名干五侯。", "知君別業長洲外，欲行秋田循畎澮。", "門前便取觳觫乘，腰上還將鹿盧佩。", "禪子有情非世情，御荈貢餘聊贈行。", "滿道喧喧遇君別，爭窺玉潤與冰清。"]'),
('69debd7f-bf3f-4ef1-a64e-8906aad836e3','水精數珠歌','皎然','唐','唐诗','tang','','[]','西方真人爲行密，臂上記珠皎如日。',48,'全唐诗/poet.tang.45000.json','["西方真人爲行密，臂上記珠皎如日。", "佛名無著心亦空，珠去珠來體常一。", "誰道佛身千萬身，重重只向心中出。"]'),
('435cea06-ac01-4ca7-a132-bcc81d56427f','兵後西日溪行','皎然','唐','唐诗','tang','','["\u9ec4\u6cb3"]','一從清氣上爲天，仙叟何年見乾海。',132,'全唐诗/poet.tang.45000.json','["一從清氣上爲天，仙叟何年見乾海。", "黃河幾度濁復清，此水如今未曾改。", "西尋仙人渚，誤入桃花穴。", "風吹花片使我迷，時時問山驚踏雪。", "石梁丹竈意更奇，春草不生多故轍。", "我來隱道非隱身，如今世上無風塵。", "路是武陵路，人非秦代人。", "飯松得高侶，濯足偶清津。", "數片昔賢磬石在，幾迴竝坐戴綸巾。"]'),
('db95391f-b0af-4027-addd-6e970841188e','姑蘇行','皎然','唐','唐诗','tang','','[]','古臺不見秋草衰，却憶吳王全盛時。',80,'全唐诗/poet.tang.45000.json','["古臺不見秋草衰，却憶吳王全盛時。", "千年月照秋草上，吳王在時幾迴望。", "至今月出君不還，世人空對姑蘇山。", "山中精靈安可覩，轍跡人蹤麋鹿聚。", "嬋娟西子傾國容，化作寒陵一堆土。"]'),
('cbd2adb6-8bae-4f5c-bcc2-24ceb75895b5','短歌行','皎然','唐','唐诗','tang','','[]','古人若不死，吾亦何所悲。',100,'全唐诗/poet.tang.45000.json','["古人若不死，吾亦何所悲。", "蕭蕭煙雨九原上，白楊青松葬者誰。", "貴賤同一塵，死生同一指。", "人生在世共如此，何異浮雲與流水。", "短歌行，短歌無窮日已傾。", "鄴宮梁苑徒有名，春草秋風傷我情。", "何爲不學金仙侶，一悟空王無死生。"]'),
('b0cbc1c9-1684-43e8-9277-df5ef2354ffe','山月行','皎然','唐','唐诗','tang','','[]','家家望秋月，不及秋山望。',92,'全唐诗/poet.tang.45000.json','["家家望秋月，不及秋山望。", "山中萬境長寂寥，夜夜孤明我山上。", "海人皆言生海東，山人自謂出山中。", "憂虞歡樂皆占月，月本無心同不同。", "自從有月山不改，古人望盡今人在。", "不知萬世今夜時，孤月將□誰更待。"]'),
('a8ee3623-7412-4f9a-a181-96f798c2b512','顧渚行寄裴方舟','皎然','唐','唐诗','tang','','[]','我有雲泉隣渚山，山中茶事頗相關。',208,'全唐诗/poet.tang.45000.json','["我有雲泉隣渚山，山中茶事頗相關。", "鶗鴂鳴時芳草死，山家漸欲收茶子。", "伯勞飛日芳草滋，山僧又是採茶時。", "繇來慣採無近遠，陰嶺長兮陽崖淺。", "大寒山下葉未生，小寒山中葉初卷。", "吳婉攜籠上翠微，蒙蒙香刺罥春衣。", "迷山乍被落花亂，度水時驚啼鳥飛。", "家園不遠乘露摘，歸時露彩猶滴瀝。", "初看怕出欺玉英，更取煎來勝金液。", "昨夜西峰雨色過，朝尋新茗復如何。", "女宮露澀青芽老，堯市人稀紫筍多。", "紫筍青芽誰得識，日暮採之長太息。", "清泠真人待子元，貯此芳香思何極。"]'),
('af62b125-aa6a-477f-9f7e-f40569724899','武源行贈丘卿岑','皎然','唐','唐诗','tang','','[]','昔年羣盜阻江東，吳山動搖楚澤空。',256,'全唐诗/poet.tang.45000.json','["昔年羣盜阻江東，吳山動搖楚澤空。", "齊人亦戴蜂蠆毒，美稷化爲荆棘藂。", "洶洶四顧多窟穴，浮雲白波名不同。", "萬人死地當虎口，一旦生涯懸彀中。", "昨日將軍徇死節，悉向生民陷成血。", "胸中豹略張陣雲，握內虵矛揮白雪。", "長洲南去接孤城，居人散盡鼓譟驚。", "三春不見芳草色，四面唯聞刁斗聲。", "此時狂寇紛如市，君當要衝固深壘。", "縱橫計出皆獲全，士卒身先每輕死。", "埽平氛祲望吳門，人間歲美桑柘繁。", "比屋生全受君賜，連營罷戰賴君恩。", "如何棄置功不錄，通籍無名滯江曲。", "灞亭不重李將軍，漢爵猶輕蘇屬國。", "荒營寂寂隱山椒，春意空驚故柳條。", "野戰攻城盡如此，即今誰是霍嫖姚。"]'),
('f70d54e7-a999-4359-8355-c1917796cdb2','長安少年行','皎然','唐','唐诗','tang','','[]','翠樓春酒蝦蟇陵，長安少年皆共矜。',32,'全唐诗/poet.tang.45000.json','["翠樓春酒蝦蟇陵，長安少年皆共矜。", "紛紛半醉綠槐道，躞蹀花驄驕不勝。"]'),
('fd8db3ba-96ed-4396-94bf-a52fddf5e125','風入松','皎然','唐','唐诗','tang','','[]','西嶺松聲落日秋，千枝萬葉風飀飀。',111,'全唐诗/poet.tang.45000.json','["西嶺松聲落日秋，千枝萬葉風飀飀。", "美人援琴弄成曲，寫得松間聲斷續。", "聲斷續，清我魂，流波壞陵安足論。", "美人夜坐月明裏，含少商兮點清徵。", "風何淒兮飄飄，攪寒松兮又夜起。", "夜未央，曲何長，金徽更促聲泱泱。", "何人此時不得意，意苦弦悲聞客堂。"]'),
('6383bc37-f778-4a0e-ba86-453a1c847052','陪盧中丞閑遊山寺','皎然','唐','唐诗','tang','','[]','野寺出人境，捨舟登遠峰。',48,'全唐诗/poet.tang.45000.json','["野寺出人境，捨舟登遠峰。", "林開明見月，萬壑靜聞鐘。", "擁燭明山翠，交麾動水容。", "如何股肱守，塵外得相逢。"]'),
('e3f70416-ea7e-4968-8668-117d15499d1b','湖南草堂讀書招李少府','皎然','唐','唐诗','tang','','[]','削去僧家事，南池便隱居。',48,'全唐诗/poet.tang.45000.json','["削去僧家事，南池便隱居。", "爲憐松子壽，還卜道家書。", "藥院常無客，茶樽獨對余。", "有時招逸史，來飯野中蔬。"]'),
('18dd38a4-0ad4-4ae9-ad90-4e1a2572b486','荅李季蘭','皎然','唐','唐诗','tang','','[]','天女來相試，將花欲染衣。',24,'全唐诗/poet.tang.45000.json','["天女來相試，將花欲染衣。", "禪心竟不起，還捧舊花歸。"]'),
('81b94247-0fba-45d6-93cb-50069332c076','酬鄭判官湖上見贈','皎然','唐','唐诗','tang','','[]','歲歲湖南隱已成，如何星使忽知名。',32,'全唐诗/poet.tang.45000.json','["歲歲湖南隱已成，如何星使忽知名。", "沙鷗慣識無心客，今日逢君不解驚。"]'),
('3b059853-57c0-434e-a748-879d646fb580','送旻上人遊天台','皎然','唐','唐诗','tang','','[]','真心不廢別，試看越溪清。',48,'全唐诗/poet.tang.45000.json','["真心不廢別，試看越溪清。", "知汝機忘盡，春山自有情。", "月思華頂宿，雲愛石門行。", "海近應須汎，無令鷗鷺驚。"]'),
('eecf361b-0425-492e-8ee8-b3c65b626636','送別','皎然','唐','唐诗','tang','','[]','聞說情人怨別情，霜天淅瀝在寒城。',32,'全唐诗/poet.tang.45000.json','["聞說情人怨別情，霜天淅瀝在寒城。", "長宵漫漫角聲發，禪子無心恨亦生。"]'),
('dd542e66-4935-4424-a967-44b0c712f9fa','與昂上人兩字繼合四句初字日','皎然','唐','唐诗','tang','','[]','有一鳥雛，凌寒獨宿。',20,'全唐诗/poet.tang.45000.json','["有一鳥雛，凌寒獨宿。", "若逢雲雨，兩兩相逐。"]'),
('6fb5985f-b3a7-4815-ae19-f7ab098c1e5c','次日','皎然','唐','唐诗','tang','','[]','野外有一人，獨立無四隣。',24,'全唐诗/poet.tang.45000.json','["野外有一人，獨立無四隣。", "彼見是我身，我見是彼身。"]'),
('d8f1dfe9-2f17-42bb-99df-879459d09dc8','皇太子頻賜存問幷索唱和新詩因有陳謝','廣宣','唐','唐诗','tang','','[]','望苑招延後，禪扉訪道餘。',96,'全唐诗/poet.tang.45000.json','["望苑招延後，禪扉訪道餘。", "祗言俟文雅，何意及庸虛。", "率性多非學，緣情偶自書。", "清風聞寺響，白日見心初。", "重道逢軒后，崇儒過魏儲。", "青宮列芳梓，玄圃積瓊琚。", "鄭鼠寧容者，齊竽久舍諸。", "龍懷受恩感，含思幾躊躇。"]'),
('4dd4ed1a-be62-4feb-ad45-67023f70aedf','禁中法會應制','廣宣','唐','唐诗','tang','','[]','天上萬年枝，人間不可窺。',72,'全唐诗/poet.tang.45000.json','["天上萬年枝，人間不可窺。", "道場三教會，心地百王期。", "侍讀霑恩早，傳香駐日遲。", "在筵還向道，通籍許言詩。", "空媿陪仙列，何階答聖慈。", "從今精至理，長願契無爲。"]'),
('21cc13eb-a312-48f6-b334-e28b334b45bf','降誕日內庭獻壽應制','廣宣','唐','唐诗','tang','','[]','慶壽千齡遠，敷仁萬國通。',72,'全唐诗/poet.tang.45000.json','["慶壽千齡遠，敷仁萬國通。", "登霄欣有路，捧日媿無功。", "仙駕三山上，龍生二月中。", "修齋長樂殿，講道大明宮。", "此地人難到，諸天事不同。", "法筵花散後，空界滿香風。"]'),
('921324d6-b166-4273-b2b8-58fdc567303d','寺中柿樹一蒂四顆詠應制','廣宣','唐','唐诗','tang','','[]','珍木生奇畝，低枝拂梵宮。',48,'全唐诗/poet.tang.45000.json','["珍木生奇畝，低枝拂梵宮。", "因開四界分，本自百花中。", "當夏陰涵綠，臨秋色變紅。", "君看藥草喻，何減太陽功。"]'),
('629673bf-1627-4277-8933-9d286026b661','早秋降誕日獻壽二首應制 一','廣宣','唐','唐诗','tang','','[]','秋蓂開六葉，元聖誕千年。',48,'全唐诗/poet.tang.45000.json','["秋蓂開六葉，元聖誕千年。", "繞殿祥風起，當空瑞日懸。", "道光中國主，人識大羅仙。", "敢贊無疆壽，香花上法筵。"]'),
('5362025b-04dc-4e24-87cd-9d6ab303628e','早秋降誕日獻壽二首應制 二','廣宣','唐','唐诗','tang','','[]','萬方瞻聖日，九土仰清光。',48,'全唐诗/poet.tang.45000.json','["萬方瞻聖日，九土仰清光。", "磬地山河壯，彌天福壽長。", "瑞煙薰法界，真偈啓仁王。", "看獻千秋樂，千秋樂未央。"]'),
('81046667-7eb1-4e93-9482-a165c3cdb153','駕幸天長寺應制','廣宣','唐','唐诗','tang','','[]','天界宜春賞，禪門不掩關。',48,'全唐诗/poet.tang.45000.json','["天界宜春賞，禪門不掩關。", "宸遊雙闕外，僧引百花間。", "車馬喧長路，煙雲淨遠山。", "觀空復觀俗，皇鑒此中閑。"]'),
('f69b1eec-7a95-469d-bc42-a4f5af76f71d','九月菊花詠應制','廣宣','唐','唐诗','tang','','[]','可訝東籬菊，能知節候芳。',48,'全唐诗/poet.tang.45000.json','["可訝東籬菊，能知節候芳。", "細枝青玉潤，繁蘂碎金香。", "爽氣浮朝露，濃姿帶夜霜。", "泛杯傳壽酒，應共樂時康。"]'),
('6ccbaef5-6d1e-456c-8a04-204bf22852e0','駕幸聖容院應制','廣宣','唐','唐诗','tang','','[]','大唐國裏千年聖，王舍城中百億身。',64,'全唐诗/poet.tang.45000.json','["大唐國裏千年聖，王舍城中百億身。", "却指容顏非我相，自言空色是吾真。", "深殿虔心隨寶輦，廣庭徐步引金輪。", "古來貴重緣親近，狂客慙爲侍從臣。"]'),
('f8312d3c-714f-429a-9a7a-c915224748de','聖恩顧問獨遊月磴閣直書其事應制','廣宣','唐','唐诗','tang','','[]','禪居河畔無多地，來往尋春物正華。',64,'全唐诗/poet.tang.45000.json','["禪居河畔無多地，來往尋春物正華。", "磴道上盤千畝竹，欄干低壓萬人家。", "簷前施飯來飛鳥，林下行香踏落花。", "自解剎那知佛性，不勞更喻幾塵沙。"]'),
('76be28ad-f2ca-4efc-b6f1-a0a8660ce410','安國寺隨駕幸興唐觀應制','廣宣','唐','唐诗','tang','','[]','東林何殿是西鄰，禪客垣牆接羽人。',64,'全唐诗/poet.tang.45000.json','["東林何殿是西鄰，禪客垣牆接羽人。", "萬乘遊仙宗有道，三車引路本無塵。", "初傳寶訣長生術，已證金剛不壞身。", "兩地盡修天上事，共瞻鑾駕重來巡。"]'),
('2d051af0-83ac-4799-ae24-b0486d3aaf22','賀王起','廣宣','唐','唐诗','tang','','[]','從辭鳳閣掌絲綸，便向青雲領貢賓。',64,'全唐诗/poet.tang.45000.json','["從辭鳳閣掌絲綸，便向青雲領貢賓。", "再闢文場無枉路，兩開金榜絕冤人。", "眼看龍化門前水，手放鶯飛谷口春。", "明日定歸台席去，鶺鴒原上共陶鈞。"]'),
('067d10ee-d8f8-4161-904f-c413c8cd801a','賀幸普濟寺應制','廣宣','唐','唐诗','tang','','[]','南方寶界幾由旬，八部同瞻一佛身。',64,'全唐诗/poet.tang.45000.json','["南方寶界幾由旬，八部同瞻一佛身。", "寺壓山河天宇靜，樓懸日月鏡光新。", "重城柳暗東風曙，複道花明上苑春。", "向晚鑾輿歸鳳闕，曲江池上動青蘋。"]'),
('536f7f15-1020-4b20-9c23-910e2c64cc84','紅樓院應制','廣宣','唐','唐诗','tang','','[]','紅樓疑見白毫光，寺逼宸居福盛唐。',64,'全唐诗/poet.tang.45000.json','["紅樓疑見白毫光，寺逼宸居福盛唐。", "支遁愛山情謾切，曇摩泛海路空長。", "經聲夜息聞天語，鑪氣晨飄接御香。", "誰道此中難可到，自憐深院得徊翔。"]'),
('ad79561a-2047-4894-b9cc-b0d0db7e384d','再入道場紀事應制','廣宣','唐','唐诗','tang','','[]','南方歸去再生天，內殿今年異昔年。',64,'全唐诗/poet.tang.45000.json','["南方歸去再生天，內殿今年異昔年。", "見闢乾坤新定位，看題日月更高懸。", "行隨車輦登仙路，坐近爐煙講法筵。", "自喜恩深陪侍從，兩朝長在聖人前。"]'),
('3e9cf2f9-ea87-4d05-8742-ef85f4015b51','寺中賞花應制','廣宣','唐','唐诗','tang','','[]','東風萬里送香來，上界千花向日開。',32,'全唐诗/poet.tang.45000.json','["東風萬里送香來，上界千花向日開。", "却笑霞樓紫芝侶，桃源仙洞訪仙才。"]'),
('88c76a49-0ceb-4adf-abf5-903635a98441','九月十五日夜宿鄭尚書絪東亭望月寄杜給事','廣宣','唐','唐诗','tang','','[]','霜天晴夜宿東齋，松竹交陰愜素懷。',64,'全唐诗/poet.tang.45000.json','["霜天晴夜宿東齋，松竹交陰愜素懷。", "迥出風塵心得地，可憐三五月當階。", "清光滿院恩情見，寒色臨門笑語諧。", "霄漢路殊從道合，往來人事不相乖。"]'),
('7a11467a-8bf2-45dc-9f86-e3a0b1fdff30','酬盧仝見訪不遇題壁','含曦','唐','唐诗','tang','','[]','長壽寺石壁，盧公一首詩。',52,'全唐诗/poet.tang.45000.json','["長壽寺石壁，盧公一首詩。", "渴讀即不渴，飢讀即不飢。", "鯨吞海水盡，露出珊瑚枝。", "海神知貴不知價，留向人間光照夜。"]'),
('997cd3bd-760b-41f1-af84-40b153b838dc','旅中荅喻軍事問客情','善生','唐','唐诗','tang','','[]','一自游他國，相逢少故人。',48,'全唐诗/poet.tang.45000.json','["一自游他國，相逢少故人。", "縱然爲客樂，爭似在家貧。", "畜恨霜侵鬢，搜詩病入神。", "若非憐片善，誰肯問風塵。"]'),
('1c578582-d531-48e3-949c-76758c155a0b','贈盧逸人','善生','唐','唐诗','tang','','[]','高眠巖野間，至藝敵應難。',48,'全唐诗/poet.tang.45000.json','["高眠巖野間，至藝敵應難。", "詩苦無多首，藥靈惟一丸。", "引泉魚落釜，攀果露沾冠。", "已得嵇康趣，逢迎事每闌。"]'),
('2c3f998e-32dc-4be9-bcc5-ec77185c7e4b','送玉禪師','善生','唐','唐诗','tang','','[]','飄然無定迹，迥與律乘違。',48,'全唐诗/poet.tang.45000.json','["飄然無定迹，迥與律乘違。", "入郭隨緣住，思山破夏歸。", "盂擎數家飯，衲乞幾人衣。", "洞了曹溪旨，寧輸俗者機。"]'),
('8fef71c0-a42f-49c8-bd26-df58bfb7f8e7','送智光之南值雨','善生','唐','唐诗','tang','','[]','結束衣囊了，炎州定去游。',48,'全唐诗/poet.tang.45000.json','["結束衣囊了，炎州定去游。", "草堂方惜別，山雨爲相留。", "又得一宵話，免生千里愁。", "莫辭重卜日，後會必經秋。"]'),
('d337e5a0-0265-4747-972f-d41a99d83489','謝白樂天招','韜光','唐','唐诗','tang','','[]','山僧野性好林泉，每向巖阿倚石眠。',64,'全唐诗/poet.tang.45000.json','["山僧野性好林泉，每向巖阿倚石眠。", "不解栽松陪玉勒，惟能引水種金蓮。", "白雲乍可來青嶂，明月難教下碧天。", "城市不能飛錫去，恐妨鶯囀翠樓前。"]'),
('43acca77-47dc-4735-9ac0-e79bd3c0973a','五歲詠花','知玄','唐','唐诗','tang','','[]','花開滿樹紅，花落萬枝空。',24,'全唐诗/poet.tang.45000.json','["花開滿樹紅，花落萬枝空。", "唯餘一孕在，明日定隨風。"]'),
('fb6ac873-ad3a-4f6f-881c-38fdc072d624','祝堯詩','知玄','唐','唐诗','tang','','[]','生天本自生天業，未必求仙便得仙。',32,'全唐诗/poet.tang.45000.json','["生天本自生天業，未必求仙便得仙。", "鶴背傾危龍背滑，君王且住一千年。"]'),
('26806e16-f95a-4ea8-9162-15b848082b8e','荅僧澈','知玄','唐','唐诗','tang','','[]','觀君法苑思沖虛，使我真乘刃有餘。',96,'全唐诗/poet.tang.45000.json','["觀君法苑思沖虛，使我真乘刃有餘。", "若使龍光時可待，應憐僧肇論成初。", "五車外典知誰敵，九趣多才恐不如。", "蕭寺講軒橫淡蕩，帝鄉雲樹正扶疎。", "幾生曾得闍瑜意，今日堪將貝葉書。", "一振微言冠千古，何人執卷問吾廬。"]'),
('e9c101d4-3425-442b-bce2-dbd80d9f958e','月夜懷劉秀才','元孚','唐','唐诗','tang','','[]','獨夜相思但自勞，阮生吟罷夢雲濤。',32,'全唐诗/poet.tang.45000.json','["獨夜相思但自勞，阮生吟罷夢雲濤。", "此時小定未禪寂，古塔月中松磬高。"]'),
('3c2c3b54-7289-4df9-987b-f84f63191fbb','送李四校書','元孚','唐','唐诗','tang','','[]','朱絲寫別鶴泠泠，詩滿紅箋月滿庭。',32,'全唐诗/poet.tang.45000.json','["朱絲寫別鶴泠泠，詩滿紅箋月滿庭。", "莫學楚狂隳姓字，知音還有子期聽。"]'),
('88e303bb-2186-46d7-90fc-f33fc26b8530','邊思','栖白','唐','唐诗','tang','','[]','西北黃雲暮，聲聲畫角愁。',48,'全唐诗/poet.tang.45000.json','["西北黃雲暮，聲聲畫角愁。", "陰山一夜雨，白草四郊秋。", "亂雁鳴寒渡，飛沙入廢樓。", "何時番色盡，此地見芳洲。"]'),
('6b5e17d8-03a9-40bd-a99d-baf6b994a05d','八月十五夜翫月','栖白','唐','唐诗','tang','','["\u8282\u65e5", "\u6708\u4eae"]','尋常三五夜，不是不嬋娟。',48,'全唐诗/poet.tang.45000.json','["尋常三五夜，不是不嬋娟。", "及至中秋滿，還勝別夜圓。", "清光凝有露，皓魄爽無煙。", "自古人皆望，年來又一年。"]'),
('48e2260b-6d78-4713-bf1b-2df974a97f80','尋山僧真勝上人不遇','栖白','唐','唐诗','tang','','[]','松下禪栖所，苔滋徑莫分。',48,'全唐诗/poet.tang.45000.json','["松下禪栖所，苔滋徑莫分。", "青山春暮見，流水夜深聞。", "不坐看心石，應隨出定雲。", "猨猱非可問，巖谷自空曛。"]'),
('57015630-19e4-4820-8f3e-3a83e481e5fd','贈李溟秀才','栖白','唐','唐诗','tang','','[]','南居古廟深，高樹宿山禽。',48,'全唐诗/poet.tang.45000.json','["南居古廟深，高樹宿山禽。", "明月上清漢，騷人動楚吟。", "數篇正始韻，一片補亡心。", "孤悄欺何謝，雲波不可尋。"]'),
('c175f8ef-afbe-4fb6-bedd-7144eaea7433','送石秀才','栖白','唐','唐诗','tang','','[]','正是歎羈游，知音拜楚侯。',48,'全唐诗/poet.tang.45000.json','["正是歎羈游，知音拜楚侯。", "何須辭遠道，自可樂扁舟。", "倚棹江洲雨，聞猨島岫秋。", "謝家山水興，終日待詩流。"]'),
('b0d76d62-cd8f-419b-863d-bdbadf291422','送造微上人游五臺及禮本師','栖白','唐','唐诗','tang','','[]','寒空金錫響，欲過渭陽津。',48,'全唐诗/poet.tang.45000.json','["寒空金錫響，欲過渭陽津。", "極目多來鴈，孤城少故人。", "與師雖別久，於法本相親。", "又對清涼月，中宵語宿因。"]'),
('38171e7f-158a-43d6-bf6e-be26927a569b','送禪師宗極歸玉峰','栖白','唐','唐诗','tang','','[]','背郭去歸宿，頭陀意頗濃。',36,'全唐诗/poet.tang.45000.json','["背郭去歸宿，頭陀意頗濃。", "鶴爭栖遠樹，猨鬬上孤峰。", "夜戍經霜月，秋城過雨鐘。"]'),
('ee6b0053-2a16-4352-b943-0013e2dae934','送僧歸舊山','栖白','唐','唐诗','tang','','[]','談空與破邪，獻壽復榮家。',48,'全唐诗/poet.tang.45000.json','["談空與破邪，獻壽復榮家。", "白日得何偈，青天落幾花。", "傳燈皆有分，化俗獨無涯。", "却入中峯寺，還知有聚沙。"]'),
('6fd9c5e0-d17c-4f1b-96a3-f1d858f26bcd','送圓仁三藏歸本國','栖白','唐','唐诗','tang','','[]','家山臨晚日，海路信歸橈。',48,'全唐诗/poet.tang.45000.json','["家山臨晚日，海路信歸橈。", "樹滅渾無岸，風生只有潮。", "歲窮程未盡，天末國仍遙。", "已入閩王夢，香花境外邀。"]'),
('89978b38-400f-42f6-a73a-02f326571044','送王鍊師歸嵩嶽','栖白','唐','唐诗','tang','','[]','飄然綠毛節，杳去洛城端。',48,'全唐诗/poet.tang.45000.json','["飄然綠毛節，杳去洛城端。", "隔水見秋嶽，兼霜掃石壇。", "一溪松色古，半夜鶴聲寒。", "迥與人寰別，勞生不可觀。"]'),
('6d2c9460-ed93-442d-a6ce-1c19d0dd3d37','壽昌節賦得紅雲表夏日','栖白','唐','唐诗','tang','','[]','景候融融陰氣潛，如峰雲共火相兼。',64,'全唐诗/poet.tang.45000.json','["景候融融陰氣潛，如峰雲共火相兼。", "霞光捧日登天上，丹彩乘風入殿簷。", "行逐赤龍千歲出，明當朱夏萬方瞻。", "微臣多幸逢佳節，得賦殊祥近御簾。"]'),
('23c54fa5-704e-4205-bc80-57b12a0a7679','經廢宮','栖白','唐','唐诗','tang','','[]','終日河聲咽暮空，煙愁此地晝濛濛。',64,'全唐诗/poet.tang.45000.json','["終日河聲咽暮空，煙愁此地晝濛濛。", "錦帆東去沙侵苑，玉輦西來樹滿宮。", "魯客望津天欲雪，朔鴻離岸葦生風。", "那堪獨立思前事，回首殘陽雉堞紅。"]'),
('9917ad6d-e7f7-419f-a007-0ecdd72a859a','贈識古法師','栖白','唐','唐诗','tang','','[]','重城深寺講初休，却憶家山訪舊游。',64,'全唐诗/poet.tang.45000.json','["重城深寺講初休，却憶家山訪舊游。", "對月與君相送夜，聞蛩教我獨驚秋。", "雲心杳杳難爲別，鶴性蕭蕭不可留。", "遙想孤舟清渭上，飄然帆影起離愁。"]'),
('da259365-e96a-44e9-a3eb-894785a24947','月夜懷劉秀才','栖白','唐','唐诗','tang','','[]','獨夜相思但自勞，阮生吟罷夢雲濤。',32,'全唐诗/poet.tang.45000.json','["獨夜相思但自勞，阮生吟罷夢雲濤。", "此時小定未禪寂，古塔月中松磐高。"]'),
('6e01ff71-35a2-46a5-9437-c6c629a024c4','寄南山景禪師','栖白','唐','唐诗','tang','','[]','一度林前見遠公，靜聞真語世情空。',32,'全唐诗/poet.tang.45000.json','["一度林前見遠公，靜聞真語世情空。", "至今寂寞禪心在，任起桃花柳絮風。"]'),
('2842a2fa-b7e9-4e20-9019-4e5087e8ebb3','哭劉得仁','栖白','唐','唐诗','tang','','[]','爲愛詩名吟至死，風魂雪魄去難招。',32,'全唐诗/poet.tang.45000.json','["爲愛詩名吟至死，風魂雪魄去難招。", "直須桂子落墳上，生得一枝冤始消。"]'),
('74c36382-c6b5-4065-add5-5c05840f118d','龍潭','應物','唐','唐诗','tang','','[]','石激懸流雪滿灣，五龍潛處野雲閑。',64,'全唐诗/poet.tang.45000.json','["石激懸流雪滿灣，五龍潛處野雲閑。", "暫收雷電九峰下，且飲溪潭一水間。", "浪引浮槎依北岸，波分曉日浸東山。", "回瞻四面如看畫，須信游人不欲還。"]'),
('aee480d4-8058-4cfa-8a2a-639b70a39deb','題化城寺','應物','唐','唐诗','tang','','[]','平高選處創蓮宮，一水縈流處處通。',64,'全唐诗/poet.tang.45000.json','["平高選處創蓮宮，一水縈流處處通。", "畫閣晝開遲日畔，禪房夜掩碧雲中。", "平川不見龍行雨，幽谷遙聞虎嘯風。", "偶與遊人論法要，真元浩浩理無窮。"]'),
('73c8a0af-0b29-4e04-b22e-9b2d71da6e34','戴雲山吟','智亮','唐','唐诗','tang','','[]','人間謾說上天梯，上萬千迴總是迷。',32,'全唐诗/poet.tang.45000.json','["人間謾說上天梯，上萬千迴總是迷。", "曾似老人巖上坐，清風明月與心齊。"]'),
('39fcc78f-7ebe-4de5-8e49-76928167f97a','又戴雲山吟','智亮','唐','唐诗','tang','','[]','戴雲山頂白雲齊，登頂方知世界低。',32,'全唐诗/poet.tang.45000.json','["戴雲山頂白雲齊，登頂方知世界低。", "異草奇花人不識，一池分作九條溪。"]'),
('bb3a71a3-2c27-40d6-a58a-a0753f145b75','荅盧鄴','良乂','唐','唐诗','tang','','[]','風泉秪向夢中聞，身外無餘可寄君。',32,'全唐诗/poet.tang.45000.json','["風泉秪向夢中聞，身外無餘可寄君。", "當戶一輪惟曉月，掛簷數片是秋雲。"]'),
('82af10b7-6438-40e8-b432-fe943c87a576','山居八詠 一','常達','唐','唐诗','tang','','[]','身閑依祖寺，志僻性多慵。',48,'全唐诗/poet.tang.45000.json','["身閑依祖寺，志僻性多慵。", "少室遺真旨，層樓起暮鐘。", "啜茶思好水，對月數諸峰。", "有問山中趣，庭前是古松。"]'),
('6a6228ce-2dcc-4e4d-acc3-652b3a417bfa','山居八詠 二','常達','唐','唐诗','tang','','[]','晚望虛庭物，心心見祖情。',48,'全唐诗/poet.tang.45000.json','["晚望虛庭物，心心見祖情。", "煙開分嶽色，雨霧減泉聲。", "遠樹猨長嘯，層巖日乍明。", "更堪論的意，林下筍新生。"]'),
('d035016e-a397-40d8-8243-b6774dd6c4f3','山居八詠 三','常達','唐','唐诗','tang','','[]','一室塵埃外，翛然祗麽常。',48,'全唐诗/poet.tang.45000.json','["一室塵埃外，翛然祗麽常。", "睡來開寢帳，鐘動下禪牀。", "溪浸山光冷，秋凋木葉黃。", "時提祖師意，欹石看斜陽。"]'),
('a33da39c-8c21-4279-9865-3ed9936c25f6','山居八詠 四','常達','唐','唐诗','tang','','[]','西來真祖意，祗在見聞中。',48,'全唐诗/poet.tang.45000.json','["西來真祖意，祗在見聞中。", "寒雁一聲過，疎林幾葉空。", "心閑憐水石，身老怯霜風。", "爲報參玄者，山山月色同。"]'),
('1af19b68-1a4b-443d-bb19-b6a5bde4dd78','山居八詠 五','常達','唐','唐诗','tang','','[]','真性寂無機，塵塵祖佛師。',48,'全唐诗/poet.tang.45000.json','["真性寂無機，塵塵祖佛師。", "日明庭砌暖，霜苦藥苗衰。", "汲水和煙酌，栽松帶雪移。", "好聽玄旨處，猨嘯嶺南枝。"]'),
('1bb5c14d-2f3c-4f4c-b66f-819ff4b2d23a','山居八詠 六','常達','唐','唐诗','tang','','[]','古寺憑欄危，時聞舉妙機。',48,'全唐诗/poet.tang.45000.json','["古寺憑欄危，時聞舉妙機。", "庭空月色淨，夜迥磬聲移。", "漏轉寒更急，燈殘冷焰微。", "太虛同萬象，相謂話玄微。"]'),
('a2d85651-174e-4928-be49-1b426e7f324a','山居八詠 七','常達','唐','唐诗','tang','','[]','胡僧論的旨，物物唱圓成。',48,'全唐诗/poet.tang.45000.json','["胡僧論的旨，物物唱圓成。", "疎柳春來翠，幽窗日漸明。", "禪心清石室，蝶翅覆花英。", "好聽談玄處，喬松鶴數聲。"]'),
('cf25e8c0-10fb-4379-b9ed-6e91f43267c2','山居八詠 八','常達','唐','唐诗','tang','','[]','祖祖唯心旨，春融日正長。',48,'全唐诗/poet.tang.45000.json','["祖祖唯心旨，春融日正長。", "霜輕莎草綠，風細藥苗香。", "月滿真如淨，花開覺樹芳。", "庭前鶯囀處，時聽語圓常。"]'),
('015bfef1-49e4-4499-83a4-fe6b8cf37c0b','苦熱行','僧鸞','唐','唐诗','tang','','[]','燭龍銜火飛天地，平陸無風海波沸。',240,'全唐诗/poet.tang.45000.json','["燭龍銜火飛天地，平陸無風海波沸。", "彤雲疊疊聳奇峰，焰焰流光熱凝翠。", "煙島摶鵬嚲雙翅，羲和赫怒強總轡。", "飲流夸父斃長途，如見當中印王字。", "明明夜西朝又東，古來有道仍再中。", "扶桑老葉蔽不得，輝華直欲凌蒼空。", "行人揮汗翻成雨，口燥喉乾嗌塵土。", "西郊雲色晝冥冥，如何不救生靈苦。", "何山怪木藏蛟龍，縮鱗卷鬣爲乖慵。", "不發滂澤注天下，欲使風雷何所從。", "旱苗原上枯成焰，嶽靈徒祝無神驗。", "豪家簾外喚清風，水紋明角鋪長簟。", "玉扇畫堂凝夜秋，歌豔繞梁催莫愁。", "陽烏落盡酒不醒，扶上西園當月樓。", "廢田暍死非吾屬，庫有黃金倉有粟。"]'),
('b2b2a314-64b6-4677-8048-d1a60c724884','贈李粲秀才','僧鸞','唐','唐诗','tang','','["\u957f\u6c5f"]','隴西輝用真才子，搜奇探險無倫比。',384,'全唐诗/poet.tang.45000.json','["隴西輝用真才子，搜奇探險無倫比。", "筆下銛磨巨闕鋒，胸中靜灩西江水。", "哀弦古樂清人耳，月露激寒哭秋鬼。", "苔地無塵到曉吟，杉松老葉風乾起。", "十軸示余三百篇，金碧爛光燒蜀牋。", "雄芒逸氣測不得，使我躑躅成狂顛。", "大郊遠闊空無邊，凝明淡綠收餘煙。", "曠懷相對景何限，落日亂峰青倚天。", "又驚大舶帆高懸，行濤劈浪凌飛仙。", "回首瞥見五千仞，撲下香爐瀑布泉。", "何事古人誇八斗，焉敢今朝定妍醜。", "颯風驅雷暫不停，始向塲中稱大手。", "駿如健鶻鶚與鵰，拏雲獵野翻重霄。", "狐狸竄伏不敢動，却下雙鳴當迅飆。", "愁如湘靈哭湘浦，咽咽哀音隔雲霧。", "九嶷深翠轉巍峨，仙骨寒消不知處。", "清同野客敲越甌，丁當急響涵清秋。", "鸞雛相引叫未定，霜結夜闌仍在樓。", "高若太空露雲物，片白激青皆彷彿。", "仙鶴閑從淨碧飛，巨鼇頭戴蓬萊出。", "前輩歌詩惟翰林，神仙老格何高深。", "鞭馳造化繞筆轉，燦爛不爲酸苦吟。", "夢乘明月清沈沈，飛到天台天姥岑。", "傾湖湧海數百字，字字不朽長摐金。"]'),
('a6ceb4b9-5559-43fa-8c86-f3e5dffcc54f','和王季文題九華山','神穎','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','衆岳雄分野，九華鎮南朝。',120,'全唐诗/poet.tang.45000.json','["衆岳雄分野，九華鎮南朝。", "彩筆凝空遠，崔嵬寄青霄。", "龍潭古仙府，靈藥今不凋。", "瑩爲滄海鏡，煙霞作荒標。", "造化心數奇，性狀精氣饒。", "玉樹鬱玲瓏，天籟韻蕭寥。", "寂寂尋乳竇，兢兢行石橋。", "通泉漱雲母，藉草縈香苕。", "我住幽且深，君賞昏復朝。", "稀逢發清唱，片片霜凌飆。"]'),
('21f3296c-bfbd-471c-bd8b-1b2316ea19e2','宿嚴陵釣臺','神穎','唐','唐诗','tang','','[]','寒谷荒臺七里洲，賢人永逐水東流。',32,'全唐诗/poet.tang.45000.json','["寒谷荒臺七里洲，賢人永逐水東流。", "獨猿叫斷青天月，千古冥冥潭樹秋。"]'),
('08921503-b709-494b-add8-12bafedf141c','效古','澹交','唐','唐诗','tang','','[]','榮辱又榮辱，一何翻與覆。',48,'全唐诗/poet.tang.45000.json','["榮辱又榮辱，一何翻與覆。", "人生百歲中，孰肯死前足。", "玄鬢忽如絲，青叢不再綠。", "自古爭名徒，黃金是誰祿。"]'),
('99c53029-b8af-449e-9b67-630053e36683','病後作','澹交','唐','唐诗','tang','','[]','未得忘身法，此身終未安。',48,'全唐诗/poet.tang.45000.json','["未得忘身法，此身終未安。", "病腸猶可洗，瘦骨不禁寒。", "藥少心情餌，經無氣力看。", "悠悠片雲質，獨對夕陽殘。"]'),
('4c16c60c-2206-4dcc-af22-a82767c13be2','寫真','澹交','唐','唐诗','tang','','[]','圖形期自見，自見却傷神。',48,'全唐诗/poet.tang.45000.json','["圖形期自見，自見却傷神。", "已是夢中夢，更逢身外身。", "水花凝幻質，墨彩染空塵。", "堪笑予兼爾，俱爲未了人。"]'),
('8094770c-24e2-4c91-af3f-32bae8ba718b','端午','文秀','唐','唐诗','tang','','["\u6292\u6000", "\u7aef\u5348\u8282"]','節分端午自誰言，萬古傳聞爲屈原。',32,'全唐诗/poet.tang.45000.json','["節分端午自誰言，萬古傳聞爲屈原。", "堪笑楚江空渺渺，不能洗得直臣冤。"]'),
('69404663-532a-4c1b-b80c-105738fb2db9','謝友人見訪留詩','懷楚','唐','唐诗','tang','','[]','軒車誰肯到，泉石自相親。',48,'全唐诗/poet.tang.45000.json','["軒車誰肯到，泉石自相親。", "暮雨凋殘寺，秋風悵望人。", "庭新一片葉，衣故十年塵。", "賴有瑤華贈，清吟愈病身。"]'),
('f8f13fd8-83e3-45e6-94e6-d419f36ddbfe','送新平故人','懷楚','唐','唐诗','tang','','[]','常聽倉庚思舊友，又因蝴蝶夢生涯。',64,'全唐诗/poet.tang.45000.json','["常聽倉庚思舊友，又因蝴蝶夢生涯。", "一千餘里河連郭，三十六峰寒到家。", "陰島直分東虢雁，晴樓高入上陽鴉。", "姜嫄廟北與君別，應笑薄寒悲落花。"]'),
('8c6a02f7-5c85-4314-8f6a-478f7d965b7a','辭南平鍾王召','躭章','唐','唐诗','tang','','[]','摧殘枯木倚寒林，幾度逢春不變心。',32,'全唐诗/poet.tang.45000.json','["摧殘枯木倚寒林，幾度逢春不變心。", "樵客見之猶不採，郢人何事苦搜尋。"]'),
('b48a8a83-7991-49f4-94b2-ecff5584984f','短歌行','子蘭','唐','唐诗','tang','','[]','日月何忙忙，出沒住不得。',60,'全唐诗/poet.tang.45000.json','["日月何忙忙，出沒住不得。", "使我勇壯心，少年如頃刻。", "人生石火光，通時少於塞。", "四季倏往來，寒暑變爲賊。", "偷人面上花，奪人頭上黑。"]'),
('679a5329-7e1c-49e8-b550-d3765379af24','飲馬長城窟','子蘭','唐','唐诗','tang','','[]','游客長城下，飲馬長城窟。',72,'全唐诗/poet.tang.45000.json','["游客長城下，飲馬長城窟。", "馬嘶聞水腥，爲浸征人骨。", "豈不是流泉，終不成潺湲。", "洗盡骨上土，不洗骨中冤。", "骨若比流水，四海有還魂。", "空流嗚咽聲，聲中疑是言。"]'),
('68dcd1e9-0321-4e45-8ac4-fee2694683a7','夜直','子蘭','唐','唐诗','tang','','[]','大內隔重牆，多聞樂未央。',96,'全唐诗/poet.tang.45000.json','["大內隔重牆，多聞樂未央。", "燈明宮樹色，茶煮禁泉香。", "鳳輦通門靜，雞歌入漏長。", "宴榮陪御席，話密近龍章。", "吟步彤庭月，眠分玉暑涼。", "欲粘朱紱重，頻草白麻忙。", "筆力將羣吏，人情在致唐。", "萬方瞻仰處，晨夕面吾皇。"]'),
('9d68bae3-b35e-47fe-8835-b782c42cdc80','贈行脚僧','子蘭','唐','唐诗','tang','','[]','世界曾行遍，全無行可修。',48,'全唐诗/poet.tang.45000.json','["世界曾行遍，全無行可修。", "炎涼三衲共，生死一身休。", "片斷雲隨體，稀疎雪滿頭。", "此門無所著，不肯暫淹留。"]'),
('0ed628a5-78b1-4eec-a10a-a31c84d8e927','秋日思舊山','子蘭','唐','唐诗','tang','','["\u5c71", "\u6292\u6000", "\u5199\u666f"]','咸言上國繁華，豈謂帝城羈旅。',56,'全唐诗/poet.tang.45000.json','["咸言上國繁華，豈謂帝城羈旅。", "十點五點殘螢，千聲萬聲秋雨。", "白雲江上故鄉，月下風前吟處。", "欲去不去遲遲，未展平生所佇。"]'),
('f515b8a4-cdd6-485b-ac04-0a897e4e8db4','寄乾陵楊侍郎','子蘭','唐','唐诗','tang','','[]','冷落官資不畏貧，司曹且共內官分。',64,'全唐诗/poet.tang.45000.json','["冷落官資不畏貧，司曹且共內官分。", "步量野色成公案，點檢樵聲入奏聞。", "陵廟路因朝去掃，御爐香每夜來焚。", "碑寒樹古神門上，管得無窮空白雲。"]'),
('1380ea34-986c-4410-82b1-165f7a07a7e5','登樓憶友','子蘭','唐','唐诗','tang','','[]','物象遠濛濛，周迴極望中。',48,'全唐诗/poet.tang.45000.json','["物象遠濛濛，周迴極望中。", "帶煙千井樹，和磬一樓風。", "月色寒沈地，波聲夜颺空。", "登臨無限趣，恨不與君同。"]'),
('7d6a784c-319a-4d75-aab7-0b7e6a68f7f9','華嚴寺望樊川','子蘭','唐','唐诗','tang','','[]','萬木葉初紅，人家樹色中。',48,'全唐诗/poet.tang.45000.json','["萬木葉初紅，人家樹色中。", "疎鐘搖雨脚，秋水浸雲容。", "雪磧回寒鴈，村燈促夜舂。", "舊山歸未得，生計欲何從。"]'),
('3c7190c2-955c-4209-9734-5e6bd610663a','與道侶同於水陸寺會宿','子蘭','唐','唐诗','tang','','[]','論道窮心少有朋，此時清話昔年曾。',64,'全唐诗/poet.tang.45000.json','["論道窮心少有朋，此時清話昔年曾。", "柿凋紅葉鋪寒井，鵠墜霜毛著定僧。", "風遰遠聲秋澗水，竹穿深色夜房燈。", "出門盡是勞生者，只此長閑幾箇能。"]'),
('045ed0b0-35b8-45ee-9275-b4fa51659c8b','城上吟','子蘭','唐','唐诗','tang','','[]','古塚密於草，新墳侵官道。',24,'全唐诗/poet.tang.45000.json','["古塚密於草，新墳侵官道。", "城外無閑地，城中人又老。"]'),
('b68b9b6b-5e96-411e-8804-8943f8d2ae10','襄陽曲','子蘭','唐','唐诗','tang','','[]','爲憶南遊人，移家大堤住。',24,'全唐诗/poet.tang.45000.json','["爲憶南遊人，移家大堤住。", "千帆萬帆來，盡過門前去。"]'),
('5a4daf63-3283-4120-b40d-bcd25d7bd807','誡貪','子蘭','唐','唐诗','tang','','[]','多求待心足，未足旋傾覆。',24,'全唐诗/poet.tang.45000.json','["多求待心足，未足旋傾覆。", "明知貪者心，求榮不求辱。"]'),
('5e95281a-83b7-4762-9c68-d751e0befd79','蟬二首 一','子蘭','唐','唐诗','tang','','[]','獨蟬初唱古槐枝，委曲悲涼斷續遲。',32,'全唐诗/poet.tang.45000.json','["獨蟬初唱古槐枝，委曲悲涼斷續遲。", "雨後忽聞誰最苦，異鄉孤館憶家時。"]'),
('86bedc7f-6c4e-4e01-ad9b-0da991b9d29d','蟬二首 二','子蘭','唐','唐诗','tang','','[]','衰柳蟬吟旁濁河，正當殘日角聲和。',32,'全唐诗/poet.tang.45000.json','["衰柳蟬吟旁濁河，正當殘日角聲和。", "尋常不足少愁思，此際聞時愁更多。"]'),
('12d0306e-9266-438c-af72-21161bea05fb','太平坊尋裴郎中故宅','子蘭','唐','唐诗','tang','','[]','不語淒涼無限情，荒堦行盡又重行。',32,'全唐诗/poet.tang.45000.json','["不語淒涼無限情，荒堦行盡又重行。", "昔年住此何人在，滿地槐花秋草生。"]'),
('3a315b5f-69f5-488e-a13d-ba2fd0b9e18d','登樓','子蘭','唐','唐诗','tang','','[]','邊邑鴻聲一例秋，大波平日遶山流。',32,'全唐诗/poet.tang.45000.json','["邊邑鴻聲一例秋，大波平日遶山流。", "故人千里同明月，盡夕無言空倚樓。"]'),
('777d125c-03a2-4a15-9ae2-7f9754a267e1','長安早秋','子蘭','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','風舞槐花落御溝，終南山色入城秋。',32,'全唐诗/poet.tang.45000.json','["風舞槐花落御溝，終南山色入城秋。", "門門走馬徵兵急，公子笙歌醉玉樓。"]'),
('ff9cdef1-31fa-45ac-951f-07f62af10800','對雪','子蘭','唐','唐诗','tang','','[]','密密無聲墜碧空，霏霏有韻舞微風。',32,'全唐诗/poet.tang.45000.json','["密密無聲墜碧空，霏霏有韻舞微風。", "幽人吟望搜辭處，飄入窗來落硯中。"]'),
('4a11a829-508c-41c4-8486-820e78ea4b7a','鸚鵡','子蘭','唐','唐诗','tang','','[]','翠毛丹觜乍教時，終日無寥似憶歸。',32,'全唐诗/poet.tang.45000.json','["翠毛丹觜乍教時，終日無寥似憶歸。", "近來偷解人言語，亂向金籠說是非。"]'),
('1a86d2a6-234b-465a-b109-c96b6c837e5a','晚景','子蘭','唐','唐诗','tang','','[]','池荷衰颯菊芬芳，策杖吟詩上草堂。',32,'全唐诗/poet.tang.45000.json','["池荷衰颯菊芬芳，策杖吟詩上草堂。", "滿目暮雲風卷盡，郡樓寒角數聲長。"]'),
('a7313897-306c-41dc-97e8-21e00f9f2453','長安傷春','子蘭','唐','唐诗','tang','','[]','霜隕中春花半無，狂遊恣飲盡兇徒。',32,'全唐诗/poet.tang.45000.json','["霜隕中春花半無，狂遊恣飲盡兇徒。", "年年賞翫公卿輩，今委溝塍骨漸枯。"]'),
('588ebca2-06d2-4477-9a92-2191593a4abd','河梁晚望二首 一','子蘭','唐','唐诗','tang','','[]','水勢滔滔不可量，漁舟容易泛滄浪。',32,'全唐诗/poet.tang.45000.json','["水勢滔滔不可量，漁舟容易泛滄浪。", "連山翠靄籠沙溆，白鳥翩翩下夕陽。"]'),
('abc03614-423e-45b0-80a0-499d2ce6cca9','河梁晚望二首 二','子蘭','唐','唐诗','tang','','[]','雨添一夜秋濤闊，極目茫茫似接天。',32,'全唐诗/poet.tang.45000.json','["雨添一夜秋濤闊，極目茫茫似接天。", "不知龍物潛何處，魚躍蛙鳴滿檻前。"]'),
('91d45b28-57c9-469e-8e93-ddc41b21638f','悲長安','子蘭','唐','唐诗','tang','','[]','何事天時禍未回，生靈愁悴苦寒灰。',32,'全唐诗/poet.tang.45000.json','["何事天時禍未回，生靈愁悴苦寒灰。", "豈知萬傾繁華地，強半今爲瓦礫堆。"]'),
('31fe5c69-8234-4aaa-95b8-7bf4cc573f59','千葉石榴花','子蘭','唐','唐诗','tang','','[]','一朵花開千葉紅，開時又不藉春風。',32,'全唐诗/poet.tang.45000.json','["一朵花開千葉紅，開時又不藉春風。", "若教移在香閨畔，定與佳人豔態同。"]'),
('07a74718-94be-41f9-a43a-5c30490492f1','觀碁','子蘭','唐','唐诗','tang','','[]','拂局盡消時，能因長路遲。',48,'全唐诗/poet.tang.45000.json','["拂局盡消時，能因長路遲。", "點頭初得計，格手待無疑。", "寂默親遺景，凝神入過思。", "共藏多少意，不語兩相知。"]'),
('794a36dc-408d-4cb2-9ee9-410252190a87','山居','可止','唐','唐诗','tang','','[]','雪消春力展，花漫洞門垂。',48,'全唐诗/poet.tang.45000.json','["雪消春力展，花漫洞門垂。", "果長纖枝曲，巖崩直道移。", "重猿圍淺井，鬬鼠下疎籬。", "寒食微燈在，高風勢徹陂。"]'),
('831233b2-5900-4cf5-a7e3-7bdb5913f9f4','贈樊川長老','可止','唐','唐诗','tang','','[]','瘦顏顴骨見，滿面雪毫垂。',48,'全唐诗/poet.tang.45000.json','["瘦顏顴骨見，滿面雪毫垂。", "坐石鳥疑死，出門人謂癡。", "照身潭入楚，浸影檜生隋。", "太白曾經夏，清風涼四肢。"]'),
('c822084a-85dc-480d-913e-bd07cb3d1fab','寄積麥山會如長老','可止','唐','唐诗','tang','','[]','默然如大道，塵世不相關。',48,'全唐诗/poet.tang.45000.json','["默然如大道，塵世不相關。", "青檜行時靜，白雲禪處閑。", "貧高一生行，病長十年顏。", "夏滿期游寺，尋山又下山。"]'),
('fc170b63-78c7-413b-b7d1-83179175a4a1','送僧','可止','唐','唐诗','tang','','[]','四海無拘繫，行心興自濃。',48,'全唐诗/poet.tang.45000.json','["四海無拘繫，行心興自濃。", "百年三事衲，萬里一枝筇。", "夜減當晴影，春消過雪蹤。", "白雲深處去，知宿在何峰。"]'),
('c1eca9f1-86ca-4c2f-b641-02069a104bb3','哭賈島','可止','唐','唐诗','tang','','[]','燕生松雪地，蜀死葬山根。',48,'全唐诗/poet.tang.45000.json','["燕生松雪地，蜀死葬山根。", "詩僻降今古，官卑悞子孫。", "塚欄寒月色，人哭苦吟魂。", "墓雨滴碑字，年年添蘚痕。"]'),
('b04cf4c7-c3ca-4857-b268-9e2fb2391dff','雪十二韻','可止','唐','唐诗','tang','','[]','落處咸過尺，翛然物象淒。',144,'全唐诗/poet.tang.45000.json','["落處咸過尺，翛然物象淒。", "瑞凝金殿上，寒甚玉關西。", "潤比江河普，明將日月齊。", "凌雲花頂膩，鎖徑竹梢低。", "出谷樵童怯，歸林野鳥迷。", "煮茶融破練，磨墨染成黳。", "陷兔埋平澤，和魚凍合溪。", "入樓消酒力，當檻寫詩題。", "道路依憑馬，朝昏委託雞。", "洞深猿作族，松亞鶴移棲。", "及夏清巖穴，經春溜石梯。", "豐年兼泰國，天道育黔黎。"]'),
('5e32dfd5-c43d-4e56-8328-e102a0290bb8','精舍遇雨','可止','唐','唐诗','tang','','[]','空門寂寂淡吾身，溪雨微微洗客塵。',32,'全唐诗/poet.tang.45000.json','["空門寂寂淡吾身，溪雨微微洗客塵。", "臥向白雲情未盡，任他黃鳥醉芳春。"]'),
('c40e1b88-3fed-40e0-a447-5d78cf8cc53e','小雪','可止','唐','唐诗','tang','','[]','落雪臨風不厭看，更多還恐蔽林巒。',32,'全唐诗/poet.tang.45000.json','["落雪臨風不厭看，更多還恐蔽林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('f8a4158c-053c-4017-9202-797c61f525c9','送婆羅門僧','可止','唐','唐诗','tang','','["\u9001\u522b"]','雪嶺金河獨向東，吳山楚澤意無窮。',32,'全唐诗/poet.tang.45000.json','["雪嶺金河獨向東，吳山楚澤意無窮。", "如今白首鄉心盡，萬里歸程在夢中。"]'),
('52697b5a-c4dd-4dd1-b262-cb7472e8f4e4','句','可止','唐','唐诗','tang','','[]','不知誰會喃喃語，必向王前報太平。',16,'全唐诗/poet.tang.45000.json','["不知誰會喃喃語，必向王前報太平。"]'),
('5bfdf075-5a65-4b2b-8839-3d919df4049e','寒食日','雲表','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u4eba\u751f", "\u611f\u53f9"]','寒食悲看郭外春，野田無處不傷神。',32,'全唐诗/poet.tang.45000.json','["寒食悲看郭外春，野田無處不傷神。", "平原纍纍添新塚，半是去年來哭人。"]'),
('6064a784-aff3-455e-aa4d-b95dcbfccfcd','自遣','歸仁','唐','唐诗','tang','','[]','日日爲詩苦，誰論春與秋。',48,'全唐诗/poet.tang.45000.json','["日日爲詩苦，誰論春與秋。", "一聯如得意，萬事總忘憂。", "雨墮花臨砌，風吹竹近樓。", "不吟頭也白，任白此生頭。"]'),
('54e63514-fd37-4d2c-bc84-cdd9bdf10efe','酬沈先輩卷','歸仁','唐','唐诗','tang','','[]','一百八十首，清泠韻可敲。',48,'全唐诗/poet.tang.45000.json','["一百八十首，清泠韻可敲。", "任從人不愛，終是我難拋。", "桂魄吟來滿，蒲團坐得凹。", "先生聲價在，寰宇幾人抄。"]'),
('e59aed37-0336-4982-96bd-a1bd468312ed','題賈島吟詩臺','歸仁','唐','唐诗','tang','','[]','此臺如可廢，此恨有誰平。',48,'全唐诗/poet.tang.45000.json','["此臺如可廢，此恨有誰平。", "縱使迷青草，終難沒舊名。", "天悲朝雨色，嶽哭夜猨聲。", "不是心偏苦，應關自古情。"]'),
('b2276a29-70ae-4179-9325-8a8c3a7d2052','悼羅隱','歸仁','唐','唐诗','tang','','[]','一著讒書未快心，幾抽胸臆縱狂吟。',64,'全唐诗/poet.tang.45000.json','["一著讒書未快心，幾抽胸臆縱狂吟。", "管中窺豹我猶在，海上釣鼇君也沈。", "歲月盡能消憤懣，寰區那更有知音。", "長安冠蓋皆塗地，仍喜先生葬碧岑。"]'),
('b886bb24-4cb6-4caa-8d4a-bbee62c48944','題楚廟','歸仁','唐','唐诗','tang','','[]','羞容難更返江東，誰問從來百戰功。',64,'全唐诗/poet.tang.45000.json','["羞容難更返江東，誰問從來百戰功。", "天地有心歸道德，山河無力爲英雄。", "蘆花尚認霜戈白，海日猶思火陣紅。", "也是男兒成敗事，不須惆悵對西風。"]'),
('85ecba7c-69b7-40ae-862e-10df1182e9ec','牡丹','歸仁','唐','唐诗','tang','','[]','三春堪惜牡丹奇，半倚朱欄欲綻時。',64,'全唐诗/poet.tang.45000.json','["三春堪惜牡丹奇，半倚朱欄欲綻時。", "天上更無花勝此，人間偏得貴相宜。", "偷香黑蟻斜穿葉，覷蕋黃蜂倒挂枝。", "除却解禪心不動，算應狂殺五陵兒。"]'),
('e55f3f89-6ae3-400c-8f90-5288a425c01e','舊國里','卿雲','唐','唐诗','tang','','[]','舊居梨嶺下，風景近炎方。',48,'全唐诗/poet.tang.45000.json','["舊居梨嶺下，風景近炎方。", "地暖生春早，家貧覺歲長。", "石房雲過濕，杉徑雨餘香。", "日夕竟無事，詩書聊自強。"]'),
('2b492836-6c41-44e0-bdcd-4688fd62e9f1','秋日江居閑詠','卿雲','唐','唐诗','tang','','[]','寄居江島邊，閑詠見秋殘。',48,'全唐诗/poet.tang.45000.json','["寄居江島邊，閑詠見秋殘。", "草白牛羊瘦，風高猨鳥寒。", "檢方醫故疾，挑薺備中餐。", "時復停書卷，鉏莎種木蘭。"]'),
('f49ed0f5-5a9d-443c-9c23-3ec93a8b126b','長安言懷寄沈彬侍郎','卿雲','唐','唐诗','tang','','[]','故園梨嶺下，歸路接天涯。',48,'全唐诗/poet.tang.45000.json','["故園梨嶺下，歸路接天涯。", "生作長安草，勝爲邊地花。", "雁南飛不到，書北寄來賒。", "堪羨神仙客，青雲早致家。"]'),
('ca192c09-7183-4004-a9e7-a2c8a91637ac','送人游塞','卿雲','唐','唐诗','tang','','[]','去去玉關路，省君曾未行。',48,'全唐诗/poet.tang.45000.json','["去去玉關路，省君曾未行。", "塞深多伏寇，時靜亦屯兵。", "雪每先秋降，花嘗近夏生。", "閑陪射鵰將，應到受降城。"]'),
('ba9b0630-2932-4e64-afad-366367d9201f','逢老人','隱巒','唐','唐诗','tang','','[]','路逢一老翁，兩鬢白如雪。',24,'全唐诗/poet.tang.45000.json','["路逢一老翁，兩鬢白如雪。", "一里二里行，四回五回歇。"]'),
('99cf0dd4-56f4-48f9-979b-05558e97b4ee','牧童','隱巒','唐','唐诗','tang','','[]','牧童見人俱不識，盡着芒鞋戴篛笠。',88,'全唐诗/poet.tang.45000.json','["牧童見人俱不識，盡着芒鞋戴篛笠。", "朝陽未出衆山晴，露滴蓑衣猶半濕。", "二月三月時，平原草初綠。", "三箇五箇騎羸牛，前村後村來放牧。", "笛聲纔一舉，衆稚齊歌舞。", "看看白日向西斜，各自騎牛又歸去。"]'),
('172df690-65db-4eda-ae51-400f32781388','蜀中送人游廬山','隱巒','唐','唐诗','tang','','["\u5e90\u5c71"]','居游正值芳春月，蜀道千山皆秀發。',64,'全唐诗/poet.tang.45000.json','["居游正值芳春月，蜀道千山皆秀發。", "溪邊十里五里花，雲外三峯兩峰雪。", "君上匡山我舊居，松蘿拋擲十年餘。", "君行試到山前問，山鳥只今相憶無。"]'),
('a4b755be-7e12-4d78-adb2-c321d591ba37','琴','隱巒','唐','唐诗','tang','','[]','七條絲上寄深意，澗水松風生十指。',32,'全唐诗/poet.tang.45000.json','["七條絲上寄深意，澗水松風生十指。", "自乃知音猶尚稀，欲教更入何人耳。"]'),
('7ae4da07-3bcd-4a8d-b64d-bb1f3c05e6f7','浮橋','隱巒','唐','唐诗','tang','','[]','橫壓驚波防沒溺，當初元剏是軍機。',32,'全唐诗/poet.tang.45000.json','["橫壓驚波防沒溺，當初元剏是軍機。", "行人到此全無滯，一片江雲踏欲飛。"]'),
('2f55c11b-e673-49e6-a099-8c374336da3a','宿九華化成寺莊','泠然','唐','唐诗','tang','','[]','佛寺孤莊千嶂間，我來詩境強相關。',64,'全唐诗/poet.tang.45000.json','["佛寺孤莊千嶂間，我來詩境強相關。", "巖邊樹動猿下澗，雲裏錫鳴僧上山。", "松月影寒生碧落，石泉聲亂噴潺湲。", "明朝更躡層霄去，誓共煙霞到老閑。"]'),
('9b0ec11d-6088-4069-af03-8e2c153fe9ec','乞荆浩畫','大愚','唐','唐诗','tang','','[]','六幅故牢健，知君恣筆蹤。',48,'全唐诗/poet.tang.45000.json','["六幅故牢健，知君恣筆蹤。", "不求千澗水，止要兩株松。", "樹下留盤石，天邊縱遠峰。", "近巖幽濕處，惟藉墨煙濃。"]'),
('c591cbbd-4b6d-4284-a265-d29ffb1db9b4','上歸州刺史代通狀二首 一','懷濬','唐','唐诗','tang','','[]','家在閩山西復西，其中歲歲有鶯啼。',32,'全唐诗/poet.tang.45000.json','["家在閩山西復西，其中歲歲有鶯啼。", "如今不在鶯啼處，鶯在舊時啼處啼。"]'),
('92c3cd1a-2451-49f5-8361-0d2be7c68086','上歸州刺史代通狀二首 二','懷濬','唐','唐诗','tang','','[]','家在閩山東復東，其中歲歲有花紅。',32,'全唐诗/poet.tang.45000.json','["家在閩山東復東，其中歲歲有花紅。", "而今不在花紅處，花在舊時紅處紅。"]'),
('5b0c92d7-03f5-4547-9770-f7026d3cdfd7','辭郡守李公恩命','恆超','唐','唐诗','tang','','[]','虛著褐衣老，浮杯道不成。',48,'全唐诗/poet.tang.45000.json','["虛著褐衣老，浮杯道不成。", "誓傳經論死，不染利名生。", "厭樹遮山色，憐窗向月明。", "他時隨范蠡，一棹五湖清。"]'),
('215b4a08-7fe4-4c10-b855-17342878dd52','題廣愛寺楞伽山','淨顯','唐','唐诗','tang','','[]','靈異不能棲鳥雀，幽奇終不着猿猱。',48,'全唐诗/poet.tang.45000.json','["靈異不能棲鳥雀，幽奇終不着猿猱。", "爲經巢賊應無損，縱使秦驅也謾勞。", "珍重昔賢留像迹，陵遷谷變自堅牢。"]'),
('6dd9e156-d253-4450-832b-3a03672563e6','聞誦法華經歌','修雅','唐','唐诗','tang','','[]','山色沈沈，松煙羃羃。',336,'全唐诗/poet.tang.45000.json','["山色沈沈，松煙羃羃。", "空林之下，盤陀之石。", "石上有僧，結跏橫膝。", "誦白蓮經，從旦至夕。", "左之右之，虎跡狼跡。", "十片五片，異花狼籍。", "偶然相見，未深相識。", "知是古之人，今之人？是曇彥，是曇翼？", "我聞此經有深旨，覺帝稱之有妙義。", "合目冥心子細聽，醍醐滴入焦腸裏。", "佛之意兮祖之髓，我之心兮經之旨。", "可憐彈指及舉手，不達目前今正是。", "大矣哉！甚奇特。", "空王要使羣生得，光輝一萬八千土。", "土土皆作黃金色，四生六道一光中。", "狂夫猶自問彌勒，我亦當年學空寂。", "一得無心便休息，今日親聞誦此經。", "始覺驢乘匪端的，我亦當年不出戶。", "不欲紅塵沾步武，今日親聞誦此經。", "始覺行行皆寶所，我亦當年愛吟詠。", "將謂冥搜亂神定，今日親聞誦此經。", "何妨筆硯資真性，我亦當年狎兒戲。", "將謂光陰半虛棄，今日親聞誦此經。", "始覺聚沙非小事，我昔曾游山與水。"]'),
('3c0acdd4-79dd-4f19-93ab-513eb1147024','歌','元寂','唐','唐诗','tang','','[]','酒禿酒禿，何榮何辱。',26,'全唐诗/poet.tang.45000.json','["酒禿酒禿，何榮何辱。", "但見衣冠成古丘，不見江河變陵谷。"]'),
('90776a02-e72a-479e-910c-e1f942e1e546','懷廬山舊隱','若虛','唐','唐诗','tang','','["\u5e90\u5c71"]','九疊嵯峨倚着天，悔隨寒瀑下巖煙。',66,'全唐诗/poet.tang.45000.json','["九疊嵯峨倚着天，悔隨寒瀑下巖煙。", "深秋猨鳥來心上，夜靜松杉到眼前。", "書架想遭苔蘚[裹]，石窗應被薜蘿纏。", "一枝筇竹游江北，不見爐峰二十年。"]'),
('21ef5b32-b69e-4e24-a287-a2b4eca01ec9','樂仙觀','若虛','唐','唐诗','tang','','[]','樂氏騎龍上碧天，東吳遺宅尚依然。',64,'全唐诗/poet.tang.45000.json','["樂氏騎龍上碧天，東吳遺宅尚依然。", "悟來大道無多事，真後丹元不值錢。", "老樹夜風蟲咬葉，古垣春雨蘚生甎。", "松傾鶴死桑田變，華表歸鄉未有年。"]'),
('84e24966-b11c-4fbc-90ef-668d93bb0941','古鏡','若虛','唐','唐诗','tang','','[]','軒后紅爐獨鑄成，蘚痕磨落月輪呈。',64,'全唐诗/poet.tang.45000.json','["軒后紅爐獨鑄成，蘚痕磨落月輪呈。", "萬般物象皆能鑒，一箇人心不可明。", "匣內乍開鸞鳳活，臺前高挂鬼神驚。", "百年肝膽堪將比，祗怕看頻素髮生。"]'),
('9a7757e0-0967-4fd6-b6bb-ff98f4724b3e','覩木平和尚','文益','唐','唐诗','tang','','[]','木平山裏人，貌古年復少。',48,'全唐诗/poet.tang.45000.json','["木平山裏人，貌古年復少。", "相看陌路同，論心秋月皎。", "懷衲線非蠶，助歌聲有鳥。", "城闕今日來，一謳曾已曉。"]'),
('085b5c16-f6f9-4495-8b0c-c404dda4d477','鷺鷥','无則','唐','唐诗','tang','','[]','白蘋紅蓼碧江涯，日暖雙雙立睡時。',32,'全唐诗/poet.tang.45000.json','["白蘋紅蓼碧江涯，日暖雙雙立睡時。", "願揭金籠放歸去，却隨沙鶴鬬輕絲。"]'),
('af717420-b906-41ab-9bac-9837855b5a21','百舌鳥二首 一','无則','唐','唐诗','tang','','[]','千愁萬恨過花時，似向春風怨別離。',32,'全唐诗/poet.tang.45000.json','["千愁萬恨過花時，似向春風怨別離。", "若使衆禽俱解語，一生懷抱有誰知。"]'),
('46fa6fc6-61d8-478a-ae84-429cf9a4871a','百舌鳥二首 二','无則','唐','唐诗','tang','','[]','長截隣雞叫五更，數般名字百般聲。',32,'全唐诗/poet.tang.45000.json','["長截隣雞叫五更，數般名字百般聲。", "饒伊搖舌先知曉，也待青天明即鳴。"]'),
('37fc7daa-d7c5-4df1-b273-24422a525b47','賞牡丹應教','謙光','唐','唐诗','tang','','[]','擁衲對芳叢，由來事不同。',48,'全唐诗/poet.tang.45000.json','["擁衲對芳叢，由來事不同。", "鬢從今日白，花似去年紅。", "豔異隨朝露，馨香逐曉風。", "何須對零落，然後始知空。"]'),
('9a7d5078-a898-4787-85d7-35afd4e4a650','善哉行','貫休','唐','唐诗','tang','','["\u6000\u4eba", "\u5973\u5b50", "\u5199\u9e1f", "\u9e1f"]','有美一人兮，婉如青揚。',67,'全唐诗/poet.tang.45000.json','["有美一人兮，婉如青揚。", "識曲別音兮，令姿煌煌。", "繡袂捧琴兮，登君子堂。", "如彼萱草兮，使我憂忘。", "欲贈之以紫玉尺，白銀鐺，久不見之兮，湘水茫茫。"]'),
('2fa627ae-9d13-495c-a5f5-82822db1d81c','讀離騷經','貫休','唐','唐诗','tang','','[]','湘江濱，湘江濱，蘭紅芷白波如銀，終須一去呼湘君。',120,'全唐诗/poet.tang.45000.json','["湘江濱，湘江濱，蘭紅芷白波如銀，終須一去呼湘君。", "問湘神，雲中君，不知何以交靈均。", "我恐湘江之魚兮，死後盡爲人。", "曾食靈均之肉兮，箇箇爲忠臣。", "又想靈均之骨兮終不曲，千年波底色如玉。", "誰能入水少取得，香沐函題貢上國。", "貢上國，即全勝和璞懸瓈，垂棘結綠。"]'),
('4032c0aa-68d2-4b62-b842-a92ae3fec730','陽春曲','貫休','唐','唐诗','tang','','[]','爲口莫學阮嗣宗，不言是非非至公。',92,'全唐诗/poet.tang.45000.json','["爲口莫學阮嗣宗，不言是非非至公。", "爲手須似朱雲輩，折檻英風至今在。", "男兒結髮事君親，須斅前賢多慷慨。", "歷數雍熙房與杜，魏公姚公宋開府。", "盡向天上仙宮閑處坐，何不却辭上帝下下土？", "忍見蒼生苦苦苦。"]'),
('e6c811cb-96d9-457c-98ec-4f68ef2eb3a1','白雪曲','貫休','唐','唐诗','tang','','[]','列鼎佩金章，淚眼看風枝。',72,'全唐诗/poet.tang.45000.json','["列鼎佩金章，淚眼看風枝。", "却思食藜藿，身作屠沽兒。", "負米無遠近，所希升斗歸。", "爲人無貴賤，莫學雞狗肥。", "斯言如不忘，別更無光輝。", "斯言如或忘，即安用人爲。"]'),
('9751674d-2434-4234-8179-d1119fe16e52','上留田','貫休','唐','唐诗','tang','','[]','父不父，兄不兄。',68,'全唐诗/poet.tang.45000.json','["父不父，兄不兄。", "上留田，蝥賊生。", "徒陟岡，淚崢嶸。", "我欲使諸凡鳥雀，盡變爲鶺鴒。", "我欲使諸凡草木，盡變爲田荆。", "鄰人歌，鄰人歌。", "古風清，清風生。"]'),
('c8374980-3b6d-420c-9afd-1fa79cf5af51','胡無人','貫休','唐','唐诗','tang','','[]','霍嫖姚，趙充國，天子將之平朔漠。',109,'全唐诗/poet.tang.45000.json','["霍嫖姚，趙充國，天子將之平朔漠。", "肉胡之肉，燼胡帳幄。", "千里萬里，唯留胡之空殼。", "邊風蕭蕭，榆葉初落。", "殺氣晝赤，枯骨夜哭。", "將軍既立殊勳，遂有胡無人曲。", "我聞之，天子富有四海。", "德被無垠，但令一物得所。", "八表來賓，亦何必令彼胡無人。"]'),
('342bf50e-e7b2-453f-8b63-69adf2491ce0','苦寒行','貫休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','北風北風，職何嚴毒。',78,'全唐诗/poet.tang.45000.json','["北風北風，職何嚴毒。", "摧壯士心，縮金烏足。", "凍雲囂囂，礙雪一片下不得。", "聲遶枯桑，根在沙塞。", "黃河徹底，頑直到海。", "一氣摶束，萬物無態。", "唯有吾庭前杉松樹枝，枝枝健在。"]'),
('934195d8-7c49-4757-8b7e-20835be1de86','蒿里','貫休','唐','唐诗','tang','','[]','兔不遲，烏更急，但恐穆王八駿，著鞭不及。',95,'全唐诗/poet.tang.45000.json','["兔不遲，烏更急，但恐穆王八駿，著鞭不及。", "所以蒿里，墳出蕺蕺。", "氣凌雲天，龍騰鳳集。", "盡爲風消土喫，狐掇蟻拾，黃金不啼玉不泣。", "白楊騷屑，亂風愁月。", "折碑石人，莽穢榛沒。", "牛羊窸窣，時見牧童兒，弄枯骨。"]'),
('3dc985d9-c158-4b44-a138-0a84046ad574','臨高臺','貫休','唐','唐诗','tang','','[]','涼風吹遠念，使我升高臺。',48,'全唐诗/poet.tang.45000.json','["涼風吹遠念，使我升高臺。", "寧知數片雲，不是舊山來。", "故人天一涯，久客殊未回。", "鴈來不得書，空寄聲哀哀。"]'),
('0643fb8d-f9d3-43fd-afdd-af860fe2e781','杞梁妻','貫休','唐','唐诗','tang','','[]','秦之無道兮四海枯，築長城兮遮北胡。',81,'全唐诗/poet.tang.45000.json','["秦之無道兮四海枯，築長城兮遮北胡。", "築人築土一萬里，杞梁貞婦啼嗚嗚。", "上無父兮中無夫，下無子兮孤復孤。", "一號城崩塞色苦，再號杞梁骨出土。", "疲魂飢魄相逐歸，陌上少年莫相非。"]'),
('4a9b1423-886f-4131-98d9-9485b423774a','古離別','貫休','唐','唐诗','tang','','["\u957f\u6c5f", "\u522b\u79bb", "\u8b66\u793a", "\u7231\u60c5"]','離恨如旨酒，古今飲皆醉。',48,'全唐诗/poet.tang.45000.json','["離恨如旨酒，古今飲皆醉。", "只恐長江水，盡是兒女淚。", "伊余非此輩，送人空把臂。", "他日再相逢，清風動天地。"]'),
('b18303e0-3fd6-4d77-b32a-de7c0a81785d','戰城南二首 一','貫休','唐','唐诗','tang','','[]','萬里桑乾傍，茫茫古蕃壤。',60,'全唐诗/poet.tang.45000.json','["萬里桑乾傍，茫茫古蕃壤。", "將軍貌憔悴，撫劍悲年長。", "胡兵尚陵逼，久住亦非強。", "邯鄲少年輩，箇箇有伎倆。", "拖槍半夜去，雪片大如掌。"]'),
('c5f8a792-07da-4cb7-b73d-cbd827fbef17','戰城南二首 二','貫休','唐','唐诗','tang','','[]','磧中有陰兵，戰馬時驚蹶。',48,'全唐诗/poet.tang.45000.json','["磧中有陰兵，戰馬時驚蹶。", "輕猛李陵心，摧殘蘇武節。", "黃金鎖子甲，風吹色如鐵。", "十載不封侯，茫茫向誰說。"]'),
('01300dd3-4cc0-4704-951f-48aee9578526','少年行 一','貫休','唐','唐诗','tang','','[]','錦衣鮮華手擎鶻，閑行氣貌多輕忽。',32,'全唐诗/poet.tang.45000.json','["錦衣鮮華手擎鶻，閑行氣貌多輕忽。", "稼穡艱難總不知，五帝三王是何物。"]'),
('f981000b-8a6a-4391-8be0-0908498376f2','少年行 二','貫休','唐','唐诗','tang','','[]','自拳五色裘，迸入他人宅。',24,'全唐诗/poet.tang.45000.json','["自拳五色裘，迸入他人宅。", "却捉蒼頭奴，玉鞭打一百。"]'),
('378c9a7b-6342-4e69-a07e-c154a77e0a90','少年行 三','貫休','唐','唐诗','tang','','[]','面白如削玉，猖狂曲江曲。',24,'全唐诗/poet.tang.45000.json','["面白如削玉，猖狂曲江曲。", "馬上黃金鞍，適來新賭得。"]'),
('143b1f06-47db-4b06-b10c-a37cd8372375','夢遊仙四首 一','貫休','唐','唐诗','tang','','[]','夢到海中山，入箇白銀宅。',24,'全唐诗/poet.tang.45000.json','["夢到海中山，入箇白銀宅。", "逢見一道士，稱是李八伯。"]'),
('edee2b50-743e-4c16-9bbd-38a933a1f9ae','夢遊仙四首 二','貫休','唐','唐诗','tang','','[]','三四仙女兒，身著瑟瑟衣。',24,'全唐诗/poet.tang.45000.json','["三四仙女兒，身著瑟瑟衣。", "手把明月珠，打落金色梨。"]'),
('e8b5afc6-579c-4c77-9a4b-b94cc0147e0e','夢遊仙四首 三','貫休','唐','唐诗','tang','','[]','車渠地無塵，行至瑤池濱。',24,'全唐诗/poet.tang.45000.json','["車渠地無塵，行至瑤池濱。", "森森椿樹下，白龍來嗅人。"]'),
('d1de0b99-af67-466c-b27a-ae17ad5895d8','夢遊仙四首 四','貫休','唐','唐诗','tang','','[]','宮殿崢嶸籠紫氣，金渠玉砂五色水。',32,'全唐诗/poet.tang.45000.json','["宮殿崢嶸籠紫氣，金渠玉砂五色水。", "守閽仙婢相倚睡，偷摘蟠桃幾倒地。"]'),
('526b2aa9-3041-44a9-bd83-3387a31cfa21','輕薄篇二首 一','貫休','唐','唐诗','tang','','[]','繡林錦野，春態相壓。',52,'全唐诗/poet.tang.45000.json','["繡林錦野，春態相壓。", "誰家少年，馬蹄蹋蹋。", "鬬雞走狗夜不歸，一擲賭却如花妾。", "誰云不顛不狂，其名不彰。", "悲夫！。"]'),
('7edafc3b-0629-42e8-a597-c7ac03b2a908','輕薄篇二首 二','貫休','唐','唐诗','tang','','[]','木落蕭蕭，蟲鳴唧唧。',46,'全唐诗/poet.tang.45000.json','["木落蕭蕭，蟲鳴唧唧。", "不覺朱蔫臉紅，霜劫鬢漆。", "世途多事，泣向秋日。", "方今少壯不努力，老大徒傷悲。"]'),
('fb0c3d10-e664-45ff-b654-6be68cae002c','長安道','貫休','唐','唐诗','tang','','[]','憧憧合合，八表一轍。',88,'全唐诗/poet.tang.45000.json','["憧憧合合，八表一轍。", "黃塵霧合，車馬火熱。", "名湯風雨，利輾霜雪。", "千車萬馱，半宿關月。", "上有堯禹，下有夔卨。", "紫氣銀輪兮，常覆金闕。", "仙掌捧日兮，濁河澄澈。", "愚將草木兮有言，與華封人兮不別。"]'),
('0a110a6d-6a30-4bfd-afb5-92f8d077535b','洛陽塵','貫休','唐','唐诗','tang','','[]','昔時昔時洛城人，今作茫茫洛城塵。',116,'全唐诗/poet.tang.45000.json','["昔時昔時洛城人，今作茫茫洛城塵。", "我聞富有石季倫，樓臺五色干星辰。", "樂如天樂日夜聞，錦姝繡妾何紛紛。", "真珠簾中，姑射神人。", "文金線玉，香成暮雲。", "孫秀若不殺，晉室應更貧。", "伊水削行路，塚石花磷磷。", "蒼茫金谷園，牛羊齕荆榛。", "飛鳥好羽毛，疑是綠珠身。"]'),
('8d3f1a1c-b8cf-4d10-9d48-5ef77af95fb1','富貴曲二首 一','貫休','唐','唐诗','tang','','[]','有金張族，驕奢相續。',63,'全唐诗/poet.tang.45000.json','["有金張族，驕奢相續。", "瓊樹玉堂，雕墻繡轂。", "紈綺雜雜，鐘鼓合合。", "美人如白牡丹花，半日只舞得一曲。", "樂不樂，足不足，爭教他愛山青水綠。"]'),
('94a77918-76c6-44f6-8e8e-58fb7dd978d5','富貴曲二首 二','貫休','唐','唐诗','tang','','[]','如神若仙，似蘭同雪。',72,'全唐诗/poet.tang.45000.json','["如神若仙，似蘭同雪。", "樂戒于極，胡不知輟。", "只欲更綴上落花，恨不能把住明月。", "太山肉盡，東海酒竭。", "佳人醉唱，敲玉釵折。", "寧知耘田車水翁，日日日灸背欲裂。"]'),
('28f892da-d936-4767-a397-5a2273fe1c36','野田黃雀行','貫休','唐','唐诗','tang','','[]','高樹風多，吹爾巢落。',72,'全唐诗/poet.tang.45000.json','["高樹風多，吹爾巢落。", "深蒿葉暖，宜爾依泊。", "莫近鴞類，蛛網亦惡。", "飲野田之清水，食野田之黃粟。", "深花中睡，𡋯土裏浴。", "如此即全勝啄太倉之穀，而更穿人之屋。"]'),
('309461b0-8cf8-4288-8eca-6f610fa9d2ec','古意九首 一','貫休','唐','唐诗','tang','','[]','一雨火雲盡，閉門心冥冥。',84,'全唐诗/poet.tang.45000.json','["一雨火雲盡，閉門心冥冥。", "蘭花與芙蓉，滿院同芳馨。", "佳人天一涯，好鳥何嚶嚶。", "我有雙白璧，不羨于虞卿。", "我有徑寸珠，別是天地精。", "玩之室生白，瀟灑身安輕。", "只應天上人，見我雙眼明。"]'),
('bb398fc9-0346-4cd2-ab39-6ca8dba2e380','古意九首 二','貫休','唐','唐诗','tang','','[]','陽烏爍萬物，草木懷春恩。',72,'全唐诗/poet.tang.45000.json','["陽烏爍萬物，草木懷春恩。", "茫茫塵土飛，培壅名利根。", "我本是蓑笠，幼知天子尊。", "學爲毛氏詩，亦多直致言。", "不慕需臑類，附勢同崩奔。", "唯尋桃李蹊，去去長者門。"]'),
('68c2b127-eda7-498d-828e-46271de7d98f','古意九首 三','貫休','唐','唐诗','tang','','[]','美人如遊龍，被服金鴛鴦。',60,'全唐诗/poet.tang.45000.json','["美人如遊龍，被服金鴛鴦。", "手把古刀尺，在彼白玉堂。", "文章深掣曳，珂珮鳴丁當。", "好風吹桃花，片片落銀床。", "何妨學羽翰，遠逐朱鳥翔。"]'),
('3ea05842-1f5c-427f-ab89-9bbac4075eb1','古意九首 四','貫休','唐','唐诗','tang','','[]','乾坤有清氣，散入詩人脾。',60,'全唐诗/poet.tang.45000.json','["乾坤有清氣，散入詩人脾。", "聖賢遺清風，不在惡木枝。", "千人萬人中，一人兩人知。", "憶在東溪日，花開葉落時。", "幾擬以黃金，鑄作鍾子期。"]'),
('0d931fe9-b45d-4ca9-af65-26b5d5aac2bc','古意九首 五','貫休','唐','唐诗','tang','','[]','莫輕白雲白，不與風雨會。',61,'全唐诗/poet.tang.45000.json','["莫輕白雲白，不與風雨會。", "莫見守羊兒，或是初平輩。", "人生非日月，光輝豈常在。", "一榮與一辱，古今常相對。", "君不見于公門，子孫好冠蓋。"]'),
('0cdc8483-10f9-43d1-a125-e400ac468bf6','古意九首 六','貫休','唐','唐诗','tang','','[]','古交如真金，百煉色不回。',60,'全唐诗/poet.tang.45000.json','["古交如真金，百煉色不回。", "今交如暴流，儵忽生塵埃。", "我願君子氣，散爲青松栽。", "我恐荆棘花，只爲小人開。", "傷心復傷心，吟上高高臺。"]'),
('4e260c15-8a1d-43a3-ba62-4827397397e3','古意九首 七','貫休','唐','唐诗','tang','','[]','常思謝康樂，文章有神力。',72,'全唐诗/poet.tang.45000.json','["常思謝康樂，文章有神力。", "是何清風清，凜然似相識。", "一種爲頑嚚，得作翻經石。", "一種爲枯槁，得作登山屐。", "永嘉爲郡後，山水添鮮碧。", "何當學羽翰，一去觀遺跡。"]'),
('7f2ba1dc-4d47-4fee-9127-b28753702eb8','古意九首 八','貫休','唐','唐诗','tang','','[]','常思李太白，仙筆驅造化。',100,'全唐诗/poet.tang.45000.json','["常思李太白，仙筆驅造化。", "玄宗致之七寶床，虎殿龍樓無不可。", "一朝力士脫靴後，玉上青蠅生一箇。", "紫皇殿前五色麟，忽然掣斷黃金鎖。", "五湖大浪如銀山，滿船載酒撾鼓過。", "賀老成異物，顛狂誰敢和。", "寧知江邊墳，不是猶醉臥。"]'),
('96cbc2fa-2200-466f-b851-2fb48769623d','古意九首 九','貫休','唐','唐诗','tang','','[]','憶在山中時，丹桂花葳蕤。',108,'全唐诗/poet.tang.45000.json','["憶在山中時，丹桂花葳蕤。", "紅泉浸瑤草，白日生華滋。", "箬屋開地鑪，翠墻挂藤衣。", "看經竹窗邊，白猨三兩枝。", "東峰有老人，眼碧頭骨奇。", "種薤煮白石，旨趣如嬰兒。", "月上來打門，月落方始歸。", "授我微妙訣，恬澹無所爲。", "別來六七年，只恐白日飛。"]'),
('bb9659cd-3b17-448f-8d4f-9bdd007eab34','酷吏詞','貫休','唐','唐诗','tang','','[]','霰雨灂灂，風號如斸。',115,'全唐诗/poet.tang.45000.json','["霰雨灂灂，風號如斸。", "有叟有叟，暮投我宿。", "吁歎自語，云太守酷。", "如何如何，掠脂斡肉。", "吳姬唱一曲，等閑破紅束。", "韓娥唱一曲，錦段鮮照屋。", "寧知一曲兩曲謌，曾使千人萬人哭。", "不惟哭，亦白其頭，飢其族，所以祥風不來，和氣不復。", "蝗乎蠈忽，東西南北。"]'),
('963f4825-dd3c-4461-9ae8-4e1a296a9b95','還舉人歌行卷','貫休','唐','唐诗','tang','','[]','厚於鐵圍山上鐵，薄似雙成仙體纈。',64,'全唐诗/poet.tang.45000.json','["厚於鐵圍山上鐵，薄似雙成仙體纈。", "蜀機鳳雛動蹩躠，珊瑚枝枝撐著月。", "王愷家中藏難掘，顏回飢僝愁天雪。", "古松直筆雷不折，雪衣女啄蟠桃缺。"]'),
('e1d4f8d3-5714-4a2b-90e0-391d6eba2d6e','陳宮詞','貫休','唐','唐诗','tang','','[]','緬想當時宮闕盛，荒宴椒房懱堯聖。',64,'全唐诗/poet.tang.45000.json','["緬想當時宮闕盛，荒宴椒房懱堯聖。", "玉樹花歌百花裏，珊瑚窗中海日迸。", "大臣來朝酒未醒，酒醒忠諫多不聽。", "陳宮因此成野田，耕人犂破宮人鏡。"]'),
('1c0a8f64-89ff-4b84-abfc-2c3fcd8e2b8d','擬齊梁酬所知見贈二首 一','貫休','唐','唐诗','tang','','[]','靜只焚香坐，詠懷悲歲闌。',48,'全唐诗/poet.tang.45000.json','["靜只焚香坐，詠懷悲歲闌。", "佳人忽有贈，滿手紅琅玕。", "不獨耀肌魄，將行爲羽翰。", "酬如上青天，風雪空漫漫。"]'),
('b8eedaee-8d5b-4cf9-ace6-eda237c3c8e7','擬齊梁酬所知見贈二首 二','貫休','唐','唐诗','tang','','[]','美如仙鼎金，清如纖手琴。',60,'全唐诗/poet.tang.45000.json','["美如仙鼎金，清如纖手琴。", "孫登嘯一聲，縹緲不可尋。", "但覺神洋洋，如入三昧林。", "釋手復在手，古意深復深。", "慚無英瓊瑤，何以酬知音。"]'),
('487d58be-60e4-4d7c-9699-375301ed4f69','經古戰場','貫休','唐','唐诗','tang','','[]','茫茫凶荒，迥如天設。',120,'全唐诗/poet.tang.45000.json','["茫茫凶荒，迥如天設。", "駐馬四顧，氣候迂結。", "秋空崢嶸，黃日將沒。", "多少行人，白日見物。", "莫道路高低，盡是戰骨。", "莫見地赤碧，盡是征血。", "昔人昔人既能忠盡于力，身糜戈戟。", "脂其風，膏其域。", "今人何不繩其塍？", "植其食。", "而使空曠年年，常貯愁煙。", "使我至此，不能無言。"]'),
('2b02b5d9-6d1e-486b-b399-01cab26423fc','村行遇獵','貫休','唐','唐诗','tang','','[]','獵師紛紛走榛莽，女亦相隨把弓矢。',107,'全唐诗/poet.tang.45000.json','["獵師紛紛走榛莽，女亦相隨把弓矢。", "南北東西盡殺心，斷燒殘雲在圍裏。", "鶻拂荒田兔成血，竿打黃茅雉驚起。", "傷嗟箇輩亦是人，一生將此關身己。", "我聞天地之大德曰生，又聞萬事皆天意。", "何遣此人又如此，猶更願天公一丈雪，深山麋鹿盡凍死。"]'),
('444208cf-16ab-44c1-9908-6bf26d235f10','漁家','貫休','唐','唐诗','tang','','[]','赤蘆蓋屋低壓恰，沙漲柴門水痕疊。',96,'全唐诗/poet.tang.45000.json','["赤蘆蓋屋低壓恰，沙漲柴門水痕疊。", "黃雞青犬花蒙籠，漁女漁兒掃風葉。", "有叟相逢帶秋醉，自拔船樁色無媿。", "前山脚下得魚多，惡浪堆中盡頭睡。", "但得忘筌心自樂，肯羨前賢釣清渭。", "終須畫取挂秋堂，與爾爲鄰有深意。"]'),
('1cfb66ee-9b73-4c33-9fcf-8372639753cf','田家作','貫休','唐','唐诗','tang','','[]','田家老翁無可作，晝甑蒸梨香漠漠。',88,'全唐诗/poet.tang.45000.json','["田家老翁無可作，晝甑蒸梨香漠漠。", "只向堦前曝背眠，赤桑大葉時時落。", "古壍侵門桃竹密，倉囤峨峨欲遮日。", "自云孫子解耕耘，四五年來腹多實。", "我聞此語心自悲，世上悠悠豈得知，稼而不穡徒爾爲。"]'),
('a75558cd-3e5c-4776-bccb-c2f075ac9503','江邊祠','貫休','唐','唐诗','tang','','[]','松森森，江渾渾，江邊古祠空閉門。',64,'全唐诗/poet.tang.45000.json','["松森森，江渾渾，江邊古祠空閉門。", "精靈應醉社日酒，白龜咬斷菖蒲根。", "花殘泠紅宿雨滴，土龍甲濕鬼眼赤。", "天符早晚下空碧，昨夜前村行霹靂。"]'),
('49338a72-6850-4da6-9d4c-ed9760ecb164','苦熱寄赤松道者','貫休','唐','唐诗','tang','','[]','天雲如燒人如炙，天地鑪中更合適。',72,'全唐诗/poet.tang.45000.json','["天雲如燒人如炙，天地鑪中更合適。", "蟬喘雷乾冰井融，些子清風有何益。", "守羊真人聃之役，高吟招隱倚碧壁。", "紫氣紅煙鮮的的，澗茗園瓜麴塵色，驕冷奢涼合相憶。"]'),
('e33b261f-1996-463a-8c98-1043225b08bb','偶作二首 一','貫休','唐','唐诗','tang','','[]','新詩一千首，古錦初下機。',48,'全唐诗/poet.tang.45000.json','["新詩一千首，古錦初下機。", "除月與鬼神，別未有人知。", "子期去不返，浩浩良不悲。", "不知天地間，知者復是誰。"]'),
('46bc2d31-92f6-4e9b-a69e-df3ce6139ac0','偶作二首 二','貫休','唐','唐诗','tang','','[]','門前數枝路，路路車馬鳴。',84,'全唐诗/poet.tang.45000.json','["門前數枝路，路路車馬鳴。", "名埃與利塵，千里萬里行。", "只見青山高，豈見青山平。", "朱門勢峨峨，冠蓋何光明。", "黃鳥在花裏，青蟬奪其聲。", "爾生非金玉，豈常貴復貞。", "寄言之子心，可以歸無形。"]'),
('2a3c5a70-a796-46d2-8f22-87c21636da0e','夜夜曲','貫休','唐','唐诗','tang','','[]','蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。',32,'全唐诗/poet.tang.45000.json','["蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。", "孤燈耿耿征婦勞，更深撲落金錯刀。"]'),
('031f570d-e6de-4773-ad0f-ad417bae76f4','春晚書山家屋壁二首 一','貫休','唐','唐诗','tang','','[]','柴門寂寂黍飯馨，山家煙火春雨晴。',32,'全唐诗/poet.tang.45000.json','["柴門寂寂黍飯馨，山家煙火春雨晴。", "庭花濛濛水泠泠，小兒啼索樹上鶯。"]'),
('ca89ed95-a370-4413-ad31-55a752465d07','春晚書山家屋壁二首 二','貫休','唐','唐诗','tang','','["\u5c71", "\u5199\u666f", "\u6292\u60c5", "\u559c\u60a6", "\u7ec4\u8bd7", "\u4e61\u6751"]','水香塘黑蒲森森，鴛鴦鸂鶒如家禽。',64,'全唐诗/poet.tang.45000.json','["水香塘黑蒲森森，鴛鴦鸂鶒如家禽。", "前村後壟桑柘深，東鄰西舍無相侵。", "蠶娘洗繭前溪淥，牧童吹笛和衣浴。", "山翁留我宿又宿，笑指西坡瓜豆熟。"]'),
('81410c71-1b7d-4b01-a4ab-2bd3fe99e3f3','春晚閑居寄陳嵩伯','貫休','唐','唐诗','tang','','[]','春霖閉門久，春色聚庭木。',48,'全唐诗/poet.tang.45000.json','["春霖閉門久，春色聚庭木。", "一夢辭舊山，四鄰有新哭。", "菰蒲生白水，風篁擢纖玉。", "爲憶湖上翁，花時獨冥目。"]'),
('44ea5056-6a2f-4ed3-8161-771d9d706e9e','長持經僧','貫休','唐','唐诗','tang','','[]','嘮嘮長夜坐，嘮嘮早起。',82,'全唐诗/poet.tang.45000.json','["嘮嘮長夜坐，嘮嘮早起。", "杉森森，不見長，人聲續續如流水。", "摐金掙玉，吐宮嚥徵。", "頭低草木，手合神鬼。", "日消三兩黃金爭得止，而槁木朽枝，一食而已。", "傷嗟浮世之人，善事不曾入耳。"]'),
('6a84410e-3f39-42c8-bde8-caa85e59be9a','茫茫曲','貫休','唐','唐诗','tang','','[]','茫茫復茫茫，滿眼皆埃塵。',56,'全唐诗/poet.tang.45000.json','["茫茫復茫茫，滿眼皆埃塵。", "莫言白髮多，莖莖是愁筋。", "未達苦雕僞，及達多不仁。", "淺深與高低，盡能生棘榛，茫茫四大愁殺人。"]'),
('c67a341b-00d8-43fe-b731-49721065beab','古鏡詞上劉侍郎','貫休','唐','唐诗','tang','','[]','至寶不自寶，照古還照今。',108,'全唐诗/poet.tang.45000.json','["至寶不自寶，照古還照今。", "仙人手胼胝，寥泬秋沈沈。", "不是十二面，不是百煉金。", "若非八彩眉，不可輒照臨。", "即歸玉案頭，爲君整冠簪。", "即居吾君手，照出天下心。", "恭聞太宗朝，此鏡當宸襟。", "六合懸清光，萬里無塵侵。", "此鏡今又出，天地還得一。"]'),
('29b41a32-c7cb-4ec5-9c4b-5579ecb1b7bc','送姜道士歸南岳','貫休','唐','唐诗','tang','','[]','松品落落，雪格索索。',94,'全唐诗/poet.tang.45000.json','["松品落落，雪格索索。", "眼有三角，頭峭五岳。", "若不居岳，此處難著。", "藥僮貌蠻名鄙彼，葫蘆酒滿擔劣起。", "萬里長風嘯一聲，九貞須拍黃金几。", "落葉蕭蕭□杳□，送師言了意未了。", "意未了，他時爲我致取一部音聲鳥。"]'),
('d659c16e-1b35-4251-b67f-e220466dd599','了仙謠','貫休','唐','唐诗','tang','','[]','海中紫霧蓬萊島，安期子喬去何早。',96,'全唐诗/poet.tang.45000.json','["海中紫霧蓬萊島，安期子喬去何早。", "遊戲多騎白騏驎，鬚髮如銀未曾老。", "亦留仙訣在人間，齧鏃終言藥非道。", "始皇不得此深旨，遠遣徐福生憂惱。", "紫朮黃精心上苗，大還小還行中寶。", "若師方術棄心師，浪似雪山何處討。"]'),
('aeb4697e-c3da-4a14-8cbe-f96eff2ba28f','循吏曲上王使君','貫休','唐','唐诗','tang','','[]','需宿需宿，炳爛光合。',106,'全唐诗/poet.tang.45000.json','["需宿需宿，炳爛光合。", "蒸蒸婺民，鍾此多福。", "自東自西，自南自北。", "伊飛伊走，乳乳良牧。", "和氣無形，春光自成。", "大信不信，貽厥無朕。", "需女需女，爾亦須語。", "使君爲理，玄風震古。", "需女需女，爾亦須語。", "我願喙長三千里，枕著玉階奏明主。"]'),
('7f2f6cd2-3d78-43c3-bb25-3398c9dfde70','古鏡詞','貫休','唐','唐诗','tang','','[]','我有一面鏡，新磨似秋月。',48,'全唐诗/poet.tang.45000.json','["我有一面鏡，新磨似秋月。", "上唯金膏香，下狀驪龍窟。", "等閑不欲開，醜者多不悅。", "或問幾千年，軒轅手中物。"]'),
('08224bf6-bbdb-47b7-b7f8-e002f6199136','懷張爲周朴','貫休','唐','唐诗','tang','','[]','張周二夫子，詩好人太癖。',131,'全唐诗/poet.tang.45000.json','["張周二夫子，詩好人太癖。", "更不過嶺來，如今頭盡白。", "人傳禹力不到處，河聲流向西。", "又到處即閉戶，逢君方展眉。", "不知是不是，若是即大奇。", "我又聞二公，心與人不同。", "一生常在寂寞中，有時狂吟入僧宅。", "錦囊鳥啼荔枝紅，有時冥搜海山腦。", "珊瑚枝動日杲杲，聖君在上知不知，赤面濁醪許多好。"]'),
('54225f57-2dcc-4b0e-9461-4dd755b96241','題弘顗三藏院','貫休','唐','唐诗','tang','','[]','儀清態淡雕瓊瓌，捲簾瀟灑無塵埃。',149,'全唐诗/poet.tang.45000.json','["儀清態淡雕瓊瓌，捲簾瀟灑無塵埃。", "嶽茶如乳庭花開，信心弟子時時來。", "灌頂壇嚴伸㽬塞，三十年功苦拘束。", "梵僧夢裏授微言，雪嶺白牛力深得。", "水精一索香一爐，紅蓮花舌生醍醐。", "初聽喉音寶樓閣，如聞魔王宮殿拉金瓦落。", "次聽妙音大隨求，更覺人間萬事深悠悠。", "四音俱作清且柔，愛河濁浪却倒流。", "却倒流兮無處去，碧海含空日初曙。"]'),
('9c937474-d08e-47e8-bf3e-309d00eed91f','古意代友人投所知','貫休','唐','唐诗','tang','','[]','青松雖有花，有花不如無。',77,'全唐诗/poet.tang.45000.json','["青松雖有花，有花不如無。", "貧井泉雖清，且無金轆轤。", "客從遠方來，遺我古銅鏡。", "挂之玉堂上，如對軒轅聖。", "天龍睡坤腹，土蝕金鬣綠。", "因知燕趙佳人顏似玉，不得此鏡終不。"]'),
('6d5fecfd-f432-4fa6-8f77-3aee61fd3317','聞知己入翰林','貫休','唐','唐诗','tang','','[]','天驥頭似鳥，[倐]忽四天下。',62,'全唐诗/poet.tang.45000.json','["天驥頭似鳥，[倐]忽四天下。", "南金色如椹，入火不見火。", "吾交二名士，遽立于帝左。", "鳳姿既出世，天意囑在我。", "奇哉子淵頌，無可無不可。"]'),
('f011a00f-3463-4787-8149-e0505464dd7a','上裴大夫二首 一','貫休','唐','唐诗','tang','','[]','我有一端綺，花彩鸞鳳羣。',24,'全唐诗/poet.tang.45000.json','["我有一端綺，花彩鸞鳳羣。", "佳人金錯刀，何似裁此文。"]'),
('cbf318fe-e826-47b6-bc66-6e79a5b65832','上裴大夫二首 二','貫休','唐','唐诗','tang','','[]','我有白雲琴，樸斲天地精。',72,'全唐诗/poet.tang.45000.json','["我有白雲琴，樸斲天地精。", "俚耳不使聞，慮同衆樂聽。", "指指法仙法，聲聲聖人聲。", "一彈四時和，再彈中古清。", "庭前梧桐枝，颯颯南風生。", "還希師曠懷，見我心不輕。"]'),
('2d1233a3-6911-4c3b-a0fb-b5679fd28ca4','上劉商州','貫休','唐','唐诗','tang','','[]','周邵吁噓氣，結爲禎祥雲。',72,'全唐诗/poet.tang.45000.json','["周邵吁噓氣，結爲禎祥雲。", "客從遠方來，持此將贈君。", "時命偶不謬，授館終南東。", "愔愔良吏師，不寐如老農。", "丘軻文之天，代天有餘功。", "代天復代天，后稷何所從。"]'),
('2087809f-1af6-44d9-8b56-697c355752c1','閑居擬齊梁四首 一','貫休','唐','唐诗','tang','','[]','夜雨山草滋，爽籟生古木。',48,'全唐诗/poet.tang.45000.json','["夜雨山草滋，爽籟生古木。", "閑吟竹仙偈，清於嚼金玉。", "蟋蟀啼壞牆，苟免悲局促。", "道人優曇花，迢迢遠山綠。"]'),
('99a762e4-3c24-4830-9702-75bde063eed3','閑居擬齊梁四首 二','貫休','唐','唐诗','tang','','[]','果熟無低枝，芳香入屏帷。',48,'全唐诗/poet.tang.45000.json','["果熟無低枝，芳香入屏帷。", "故人久不來，萱草何離離。", "苦吟齋貌減，更被杉風吹。", "獨賴湖上翁，時爲烹露葵。"]'),
('41a710ba-f0fd-46df-97da-714c47c61840','閑居擬齊梁四首 三','貫休','唐','唐诗','tang','','[]','紅藕暎嘉魴，澄池照孤坐。',48,'全唐诗/poet.tang.45000.json','["紅藕暎嘉魴，澄池照孤坐。", "池痕放文彩，雨氣贈慵墮。", "山翁寄朮藥，幸得秋病可。", "終召十七人，雲中備香火。"]'),
('cbe61f2e-56fc-460e-9e26-98cb74b5c874','閑居擬齊梁四首 四','貫休','唐','唐诗','tang','','[]','清氣生滄洲，殘雲落林藪。',60,'全唐诗/poet.tang.45000.json','["清氣生滄洲，殘雲落林藪。", "放鶴久不歸，不知更歸否。", "支策到江湄，江臯木葉飛。", "自憐爲客遠，還如鵲遶枝。", "南枝復北枝，玉露沾毛衣。"]'),
('f36ec153-e2bf-4e00-8208-ac45b0fb3eb5','塞上曲二首 一','貫休','唐','唐诗','tang','','[]','錦袷胡兒黑如漆，騎羊上冰如箭疾。',64,'全唐诗/poet.tang.45000.json','["錦袷胡兒黑如漆，騎羊上冰如箭疾。", "蒲萄酒白雕腊紅，苜蓿根甜沙鼠出。", "單于右臂何須斷，天子昭昭本如日。", "一握黳髯一握絲，須知只爲平戎術。"]'),
('97d60e07-8e14-42cd-8c0d-4ba6ba51e238','塞上曲二首 二','貫休','唐','唐诗','tang','','[]','去年轉鬬陰山脚，生得單于却放却。',96,'全唐诗/poet.tang.45000.json','["去年轉鬬陰山脚，生得單于却放却。", "今年深入于不毛，胡兵拔帳遺弓刀。", "男兒須展平生志，爲國輸忠合天地。", "甲穿雖即失黃金，劒缺猶能生紫氣。", "塞草萋萋兵士苦，胡虜如今勿胡虜。", "封侯十萬始無心，玉關凱入君看取。"]'),
('11d9e605-c1b2-4651-92f2-bf024ae44875','擬齊梁體寄馮使君三首 一','貫休','唐','唐诗','tang','','[]','庭鳥多好音，相呼灌木中。',72,'全唐诗/poet.tang.45000.json','["庭鳥多好音，相呼灌木中。", "竹房更何有，還如鳥巢空。", "賴逢富人侯，真東晉謝公。", "煌煌發令姿，珂珮鳴丁冬。", "故山有深霞，未如旌旗紅。", "慚非衛霍松，何以當清風。"]'),
('3dc179e3-6b97-4513-9d55-8b9cdb6673e6','擬齊梁體寄馮使君三首 二','貫休','唐','唐诗','tang','','[]','露益蟬聲長，蕙蘭垂紫帶。',48,'全唐诗/poet.tang.45000.json','["露益蟬聲長，蕙蘭垂紫帶。", "清吟代明月，孤雲忽爲蓋。", "伊余石林人，本是燒畬輩。", "頻接謝公棊，輸多未曾賽。"]'),
('84980cd4-e51e-47b4-8cd2-ba00e9097cc3','擬齊梁體寄馮使君三首 三','貫休','唐','唐诗','tang','','[]','大道貴無心，聖賢爲始慕。',72,'全唐诗/poet.tang.45000.json','["大道貴無心，聖賢爲始慕。", "秋空共澄潔，美玉同貞素。", "偉哉桐江守，雌黃出金口。", "爲文能廢興，談道弭空有。", "雪林槁枯者，坐石聽亦久。", "還疑紫磨身，成居靈運後。"]'),
('b2da42c3-3266-4126-84f4-d4a5334b1ab0','書匡山老僧菴','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','篔簹紅實好鳥語，銀髯瘦僧貌如祖。',48,'全唐诗/poet.tang.45000.json','["篔簹紅實好鳥語，銀髯瘦僧貌如祖。", "香煙濛濛衣上聚，冥心縹緲入鐵圄。", "白麏作夢枕藤屨，東峯山媼貢瓜乳。"]'),
('089ebcfd-893b-432e-a3e8-af3f748b7722','讀顧況歌行','貫休','唐','唐诗','tang','','[]','雪泥露金冰滴瓦，楓檉火著僧留坐。',126,'全唐诗/poet.tang.45000.json','["雪泥露金冰滴瓦，楓檉火著僧留坐。", "忽覩逋翁一軸歌，始覺詩魔辜負我。", "花飛飛，雪霏霏，三珠樹曉珠纍纍。", "妖狐爬出西子骨，雷車拶破織女機。", "憶昔鄱陽寺中見一碣，逋翁詞兮逋翁札。", "庾翼未伏王右軍，李白不知誰擬殺。", "別，別，若非仙眼應難別。", "不可說，不可說，離亂亂離應打折。"]'),
('530741a2-f841-4fa4-94cf-673df4f8a172','冬末病中作二首 一','貫休','唐','唐诗','tang','','[]','冬風吹草木，亦吹我病根。',72,'全唐诗/poet.tang.45000.json','["冬風吹草木，亦吹我病根。", "故人久不來，冷落如丘園。", "聃龍與摩詰，吁歎非不聞。", "顧惟年少時，未合多憂懃。", "風鍾遠孤枕，雪水流凍痕。", "空餘微妙心，期空靜者論。"]'),
('692bdb40-7c79-4c9e-9b9d-3c476620896e','冬末病中作二首 二','貫休','唐','唐诗','tang','','[]','胸中有一物，旅拒復攻擊。',108,'全唐诗/poet.tang.45000.json','["胸中有一物，旅拒復攻擊。", "向下還上來，唯疑是肺石。", "山童頑且小，用之復何益。", "教洗煮茶鐺，雪團打鄰壁。", "宛轉無好姿，裴回更何適。", "庭前早梅樹，坐見花盡碧。", "屋老多鼠窠，窗卑露山脊。", "近來胸中物，已似輸藥力。", "微吟復微今，依稀似莊舃。"]'),
('a18a3990-6160-4bbd-8d5d-1565d9662e84','遇葉進士','貫休','唐','唐诗','tang','','[]','文章擬真宰，儀冠冷如[璧]。',62,'全唐诗/poet.tang.45000.json','["文章擬真宰，儀冠冷如[璧]。", "山寺偶相逢，眼青勝山色。", "氣隆多慷慨，語澹無他力。", "金繩殘果落，竹閣涼雨滴。", "自媿龍鍾人，見此沖天翼。"]'),
('19fd214b-2da6-4461-a40a-25800d2c2ef4','寄杜使君','貫休','唐','唐诗','tang','','[]','清辰捲珠簾，盥漱香滿室。',120,'全唐诗/poet.tang.45000.json','["清辰捲珠簾，盥漱香滿室。", "杉松經雪後，別有精彩出。", "琅函芙蓉書，開之向堦日。", "好鳥常解來，孤雲偶相失。", "有時作章句，氣概還鮮逸。", "茫茫世情世，誰人愛真實。", "清高慕玄度，宴默攀道一。", "殘磬隔風林，微陽解冰筆。", "亦知休明代，諒無經濟術。", "門前九箇峯，終擬爲文乞。"]'),
('9cfb1c1b-3f23-447b-9857-4a57aa71ac61','寄高員外','貫休','唐','唐诗','tang','','[]','冷冽蒼黃風似劈，雪骨冰筋滿瑤席。',80,'全唐诗/poet.tang.45000.json','["冷冽蒼黃風似劈，雪骨冰筋滿瑤席。", "庭松流汙相抵喫，霜絮重裘火無力。", "孤峯地鑪燒白櫪，龐眉道者應相憶。", "儵忽維陽歲云暮，寂寥不覺成章句。", "惟應將寄蘂珠宮，禪剎雲深一來否。"]'),
('dec600ff-f7f2-4824-8bc9-d429374b2b28','書陳處士屋壁二首 一','貫休','唐','唐诗','tang','','[]','有叟傲堯日，髮白肌膚紅。',48,'全唐诗/poet.tang.45000.json','["有叟傲堯日，髮白肌膚紅。", "妻子亦讀書，種蘭清溪東。", "白雲有奇色，紫桂含天風。", "即應迎鶴書，肯羨於洞洪。"]'),
('2257ed8f-1739-4a4d-9eb2-9ac80c778618','書陳處士屋壁二首 二','貫休','唐','唐诗','tang','','[]','高步前山前，高歌北山北。',74,'全唐诗/poet.tang.45000.json','["高步前山前，高歌北山北。", "數載賣甘橙，山貲近云足。", "新詩不將出，往往僧乞得。", "唯云李太白，亦是偷桃賊。", "吟狂鬼神走，酒釅天地[黑]。", "青芻生堦除，擷之束成束。"]'),
('a2cc6dcf-6c94-4fc7-a3e9-a514310a63b9','對月作','貫休','唐','唐诗','tang','','[]','今人看此月，古人看此月。',76,'全唐诗/poet.tang.45000.json','["今人看此月，古人看此月。", "如何古人心，難向今人說。", "古人求祿以及親，及之如之何。", "忠孝爲朱輪，今人求祿唯庇身。", "庇身如之何，惡木多斜文。", "斜文復斜文，顛窒何紛紛。"]'),
('45175096-5a3e-4dd1-ab2c-f822de0bd1e9','山茶花','貫休','唐','唐诗','tang','','[]','風裁日染開仙囿，百花色死猩血謬。',32,'全唐诗/poet.tang.45000.json','["風裁日染開仙囿，百花色死猩血謬。", "今朝一朵墮堦前，應有看人怨孫秀。"]'),
('d79e889a-3212-4cfc-b0ae-720e340a5c73','上孫使君','貫休','唐','唐诗','tang','','[]','聖主得賢臣，天地方交泰。',290,'全唐诗/poet.tang.45000.json','["聖主得賢臣，天地方交泰。", "恭惟嶽精粹，多出於昭代。", "君侯握文鏡，獨立塵埃外。", "王演俗容儀，崔陵小風概。", "馨香擁蘭雪，峻秀高嵩岱。", "嵇松領歲寒，莊劒無礱淬。", "威稜玉霜直，匠石金槌大。", "詩穿明月珠，道拍安期背。", "中興鸞鳳集，直道風雲會。", "萬卷似無書，三山如歷塊。", "德乎天所縱，清矣誰堪對。", "有法在朝端，無塵到冠蓋。", "具瞻從密勿，旦夕調鼎鼐。", "爲君整衢尊，爲君戢蕃塞。", "豈知吾后意，憂此毘陵最。", "親手賜彤弓，蒼生是繄賴。", "下車鄰寇散，是物冰壺內。", "龔遂[愛]廉平，次公太繁碎。", "袴襦砧動地，父母歌闤闠。", "□雪鏁戈鋋，非煙遶旌斾。", "寧思子產冰，肯羨任棠薤。", "忽如春再來，不獨天重戴。", "昂藏海嶠鶴，冷碧仙庭檜。", "物物動和氣，家家有新態。"]'),
('47426d63-51d4-4e03-bc27-323630bb1168','哭靈一上人','貫休','唐','唐诗','tang','','[]','一公何不在，空有遠公名。',72,'全唐诗/poet.tang.45000.json','["一公何不在，空有遠公名。", "共說岑山路，今時不可行。", "舊房松更老，新塔草初生。", "經論傳緇侶，文章遍墨卿。", "禪林枝幹折，法宇棟梁傾。", "誰俊修僧史，應知傳已成。"]'),
('b22f841a-91f2-4537-bc81-79fd1d56919d','行路難 一','貫休','唐','唐诗','tang','','[]','君不見山高海深人不測，古往今來轉青碧。',63,'全唐诗/poet.tang.45000.json','["君不見山高海深人不測，古往今來轉青碧。", "淺近輕浮莫與交，地卑只解生荆棘。", "誰道黃金如糞土，張耳陳餘斷消息。", "行路難，行路難，君自看。"]'),
('eca50797-22fc-4805-8db6-96546f8383eb','行路難 二','貫休','唐','唐诗','tang','','[]','不會當時作天地，剛有多般愚與智。',99,'全唐诗/poet.tang.45000.json','["不會當時作天地，剛有多般愚與智。", "到頭還用真宰心，何如上下皆清氣。", "大道冥冥不知處，那堪頓得羲和轡。", "義不義兮仁不仁，擬學長生更容易。", "負心爲罏復爲火，緣木求魚應且止。", "君不見燒金煉石古帝王，鬼火熒熒白楊裏。"]'),
('d7df0412-a577-49e5-aa8b-adb1a3d8d635','行路難 三','貫休','唐','唐诗','tang','','[]','君不見道傍廢井生古木，本是驕奢貴人屋。',113,'全唐诗/poet.tang.45000.json','["君不見道傍廢井生古木，本是驕奢貴人屋。", "幾度美人照影來，素綆銀缾濯纖玉。", "雲飛雨散今如此，繡闥雕甍作荒谷。", "沸渭笙歌君莫誇，不應常是西家哭。", "休誰遺編行者幾，至竟終須合天理。", "敗他成此亦何功，蘇張終作多言鬼。", "行路難，行路難，不在羊腸裏。"]'),
('bd949047-34b7-4d60-87ae-147c9b8e0c36','行路難 四','貫休','唐','唐诗','tang','','[]','九有茫茫共堯日，浪死虛生亦非一。',88,'全唐诗/poet.tang.45000.json','["九有茫茫共堯日，浪死虛生亦非一。", "清淨玄音竟不聞，花眼酒腸暗如漆。", "或偶因片言隻字登第光二親，又不能獻可替否航要津。", "口譚羲軒與周孔，履行不及屠沽人。", "行路難，行路難，日暮途遠空悲歎。"]'),
('b86cc3c8-715b-46fe-9a2f-0e72af8e599f','行路難 五','貫休','唐','唐诗','tang','','[]','君不見道傍樹有寄生枝，青青鬱鬱同榮衰。',127,'全唐诗/poet.tang.45000.json','["君不見道傍樹有寄生枝，青青鬱鬱同榮衰。", "無情之物尚如此，爲人不及還堪悲。", "父歸墳兮未朝夕，已分黃金爭田宅。", "高堂老母頭似霜，心作數支淚常滴。", "我聞忽如負芒刺，不獨爲君空歎息。", "古人尺布猶可縫，潯陽義犬令人憶。", "寄言世上爲人子，孝義團圓莫如此。", "若如此，不遄死兮更何俟。"]'),
('7b8fd964-d0aa-4328-9830-d7284d70bc53','泊秋江','貫休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','岸如洞庭山似剡，船漾清溪涼勝簟。',32,'全唐诗/poet.tang.45000.json','["岸如洞庭山似剡，船漾清溪涼勝簟。", "月白風高不得眠，枯葦叢邊釣師魘。"]'),
('e7d6ca40-9b7a-4088-9dcc-827bc79f19d2','嘲商客','貫休','唐','唐诗','tang','','[]','葦蕭蕭，風摵摵，落日江頭何處客。',32,'全唐诗/poet.tang.45000.json','["葦蕭蕭，風摵摵，落日江頭何處客。", "斜倚帆檣不喚人，五湖浪向心中白。"]'),
('049b232e-8ab1-4ccb-967e-4899bc6c6e12','寄王滌','貫休','唐','唐诗','tang','','[]','梅月多開戶，衣裳潤欲滴。',72,'全唐诗/poet.tang.45000.json','["梅月多開戶，衣裳潤欲滴。", "寂寥雖無形，不是小讐敵。", "地虛草木壯，雨白桃李赤。", "永日無人來，庭花苦狼籍。", "吟高好鳥覷，風靜茶煙直。", "唯思萊子來，衣拖五般色。"]'),
('42d13e43-6efe-4101-bf30-8685ef9c5cbd','上馮使君五首 一','貫休','唐','唐诗','tang','','[]','撐船碧江上，春日何遲遲。',24,'全唐诗/poet.tang.45000.json','["撐船碧江上，春日何遲遲。", "汀花最深處，拾得鴛鴦兒。"]'),
('ae39f4cf-c7c4-49f1-99cd-df8cfeaf765a','上馮使君五首 二','貫休','唐','唐诗','tang','','[]','漁父無憂苦，水仙亦何別。',24,'全唐诗/poet.tang.45000.json','["漁父無憂苦，水仙亦何別。", "眠在綠葦邊，不知釣筒發。"]'),
('46d5cea9-c175-494c-bde5-ba17a6e19cae','上馮使君五首 三','貫休','唐','唐诗','tang','','[]','樵叟無憂苦，地仙亦何別。',24,'全唐诗/poet.tang.45000.json','["樵叟無憂苦，地仙亦何別。", "茆屋岸花中，弄孫頭似雪。"]'),
('f6d58548-3293-4f9f-9142-7f4c71d09607','上馮使君五首 四','貫休','唐','唐诗','tang','','[]','扣舷得新詩，茶煮桃花水。',24,'全唐诗/poet.tang.45000.json','["扣舷得新詩，茶煮桃花水。", "㠔㠔數片帆，去去殊未已。"]'),
('2ba0bdf9-9c3b-4f2e-be4c-cb31824c1385','上馮使君五首 五','貫休','唐','唐诗','tang','','[]','仁政無不及，乳獺將子行。',24,'全唐诗/poet.tang.45000.json','["仁政無不及，乳獺將子行。", "誰家苦竹林，中有讀書聲。"]'),
('0b24845c-c5cb-4e7f-aa86-3cd08e92c742','擬君子有所思二首 一','貫休','唐','唐诗','tang','','[]','我愛正考甫，思賢作商頌。',103,'全唐诗/poet.tang.45000.json','["我愛正考甫，思賢作商頌。", "我愛揚子雲，理亂皆如鳳。", "振衣中夜起，露花香旖旎。", "撲碎驪龍明月珠，敲出鳳皇五色髓。", "陋巷蕭蕭風㭊㭊，緬想斯人勝珪璧。", "寂寥千載不相逢，無限區區盡虛擲。", "君不見沈約道，佳人不在茲，春光爲誰惜。"]'),
('00146da6-8344-44fe-8522-526cdf8cad77','擬君子有所思二首 二','貫休','唐','唐诗','tang','','[]','安得龍猛筆，點石爲黃金。',56,'全唐诗/poet.tang.45000.json','["安得龍猛筆，點石爲黃金。", "散爲酷吏家，使無貪殘心。", "甘棠密葉成翠幄，欵鳳不來天地塞。", "所以傾國傾城人，如今如今不可得。"]'),
('994573a0-8bec-4d71-81d4-6299d4d039ac','古塞下曲四首 一','貫休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','古塞腥膻地，胡兵聚如蠅。',48,'全唐诗/poet.tang.45000.json','["古塞腥膻地，胡兵聚如蠅。", "寒鵰中𩩉石，落在黃河冰。", "蒼茫邏逤城，枿枿賊氣興。", "鑄金禱秋穹，還擬相憑陵。"]'),
('b920728f-1c21-4af8-a85b-34d1930e9bc7','古塞下曲四首 二','貫休','唐','唐诗','tang','','[]','戰骨踐成塵，飛入征人目。',48,'全唐诗/poet.tang.45000.json','["戰骨踐成塵，飛入征人目。", "黃雲忽變黑，戰鬼作陣哭。", "陰風吼大漠，火號出不得。", "誰爲天子前，唱此邊城曲。"]'),
('1a9cd899-f5d3-4dfa-9d3d-27f1782942e9','古塞下曲四首 三','貫休','唐','唐诗','tang','','[]','日向平沙出，還向平沙沒。',56,'全唐诗/poet.tang.45000.json','["日向平沙出，還向平沙沒。", "飛蓬落軍營，驚鵰去天末。", "帝鄉青樓倚霄漢，歌吹掀天對花月。", "豈知塞上望鄉人，日日雙眸滴清血。"]'),
('75e88bc8-47d9-41dc-9416-50be12c9ab9f','古塞下曲四首 四','貫休','唐','唐诗','tang','','[]','狼煙在陣雲，匈奴愛輕敵。',48,'全唐诗/poet.tang.45000.json','["狼煙在陣雲，匈奴愛輕敵。", "領兵不知數，牛羊復吞磧。", "嚴冬大河枯，嫖姚去深擊。", "戰血染黃沙，風吹暎天赤。"]'),
('71da2ffd-7f42-4700-afee-3a6fe0dd1a02','鼓腹曲','貫休','唐','唐诗','tang','','[]','我昔不幸兮遭百罹，蒼蒼留我兮到好時。',116,'全唐诗/poet.tang.45000.json','["我昔不幸兮遭百罹，蒼蒼留我兮到好時。", "耳聞鐘鼓兮生豐肌，白髮却黑兮自不知。", "東鄰老人好吹笛，倉囤峨峨穀多赤。", "餅紅鰕兮㭊麋腊，有酒如濁醯兮呼我喫。", "往往醉倒潢洿之水邊兮人盡識，孰云六五帝兮四三皇。", "如夔如龍羞如龔黃，吾不知此之言兮是何之言兮。"]'),
('67eda351-739f-4349-aef7-3793896a3c4e','經曠禪師院','貫休','唐','唐诗','tang','','[]','吾師楞伽山中人，氣岸古淡僧麒麟。',197,'全唐诗/poet.tang.45000.json','["吾師楞伽山中人，氣岸古淡僧麒麟。", "曹溪老兄一與語，金玉聲利。", "泥棄唾委，兀兀如頑雲。", "驪珠兮固難價其價，靈芝兮何以根其根。", "真貌枯槁言樸略，衲衣爛黑燒嶽痕。", "憶昔十四五年前苦寒節，禮師問師楞伽月。", "此時師握玉麈尾，報我却云非日月。", "一敲粉碎狂性歇，庭松無韻冷撼骨。", "搔窗擦簷數枝雪，邇來流浪于吳越。", "一片閑雲空皎潔，再來尋師已蟬蛻。", "薝蔔枝枯醴泉竭，水檀香火遺影在。", "甘露松枝月中折，寶師往日真隱心，今日不能墮雙血。"]'),
('4135e905-70cf-4329-9c96-d95134949a77','邊上作三首 一','貫休','唐','唐诗','tang','','[]','山無綠兮水無清，風既毒兮沙亦腥。',32,'全唐诗/poet.tang.45000.json','["山無綠兮水無清，風既毒兮沙亦腥。", "胡兒走馬疾飛鳥，聯翩射落雲中聲。"]'),
('fe93599e-d985-4d78-bdb7-dddaa666cb29','邊上作三首 二','貫休','唐','唐诗','tang','','[]','陣雲忽向沙中起，探得胡兵過遼水。',32,'全唐诗/poet.tang.45000.json','["陣雲忽向沙中起，探得胡兵過遼水。", "堪嗟護塞征戍兒，未戰已疑身是鬼。"]'),
('af42490e-26c5-4b68-8103-532d4fc6744f','邊上作三首 三','貫休','唐','唐诗','tang','','[]','見說青塚穴，中有白野狐。',36,'全唐诗/poet.tang.45000.json','["見說青塚穴，中有白野狐。", "時時出沙磧，向東而號呼。", "號呼復號呼，畫師圖得無。"]'),
('34159e29-e317-4bd9-bc89-46f040bd8ecb','送張拾遺赴施州司戶','貫休','唐','唐诗','tang','','[]','道之大道古太古，二字爲名爭莽鹵。',164,'全唐诗/poet.tang.45000.json','["道之大道古太古，二字爲名爭莽鹵。", "社稷安危在直言，須歷堯堦撾諫鼓。", "恭聞吾皇至聖深無比，推席却几聽至理。", "一言偶未合堯聰，賈生須看湘江水。", "君不見頃者百官排闥赴延英，陽城不死存令名。", "又不見仲尼遙奇司馬子，珮玉垂紳合如此。", "公乎公乎施之掾，江上春風喜相見。", "畏天之命復行行，芙蓉爲衣勝絁絹。", "好音入耳應非久，三峽聞猨莫迴首。", "且啜千年羹，醉巴酒。"]'),
('e4c4ee12-b22c-433f-a82c-fd54538dd993','書倪氏屋壁三首 一','貫休','唐','唐诗','tang','','[]','茶烹綠乳花暎簾，撐沙苦筍銀纖纖。',32,'全唐诗/poet.tang.45000.json','["茶烹綠乳花暎簾，撐沙苦筍銀纖纖。", "窗中山色青翠黏，主人於我情無厭。"]'),
('8e422260-dad4-4f42-8d01-eeb08e55baa3','書倪氏屋壁三首 二','貫休','唐','唐诗','tang','','[]','白桑紅椹鶯咽咽，麵揉玉塵餅挑雪。',32,'全唐诗/poet.tang.45000.json','["白桑紅椹鶯咽咽，麵揉玉塵餅挑雪。", "將爲數日已一月，主人於我特地切。"]'),
('416b638a-4f61-4c5f-be68-788367160801','書倪氏屋壁三首 三','貫休','唐','唐诗','tang','','[]','水嬌草媚掩山路，睡槎鴛鴦如畫作。',32,'全唐诗/poet.tang.45000.json','["水嬌草媚掩山路，睡槎鴛鴦如畫作。", "春光靄靄忽已暮，主人剛地不放去。"]'),
('9477a2d1-3108-45a6-93e3-6b3f56d9bed6','續姚梁公坐右銘','貫休','唐','唐诗','tang','','[]','善爲爾諸身，行爲爾性命。',255,'全唐诗/poet.tang.45000.json','["善爲爾諸身，行爲爾性命。", "禍福必可轉，莫慤言前定。", "見人之得，如己之得。", "則美無不克，見人之失。", "如己之失，是亨貞吉。", "反此之徒，天鬼必誅。", "福先禍始，好殺滅[紀]。", "不得不止，守謙寡慾。", "善善惡惡，不得不作。", "無見貴熱，諂走蹩躠。", "無輕賤微，上下相依。", "古聖著書，矻矻孳孳。", "忠孝信行，越食逾衣。", "生天地間，未或非假。", "身危彩虹，景速奔馬。", "胡不自彊，將升玉堂。", "胡爲自墜，言虛行僞。", "豔殃爾壽須戒，酒腐爾腸須畏。", "勵志須至，撲滿必破。", "非莫非於餙非，過莫過於文過。", "及物陰功，子孫必封。", "無恃文學，是司奇薄。", "患隨不忍，害逐無足。", "一此一彼，諧宮合徵。"]'),
('66725f40-86fd-4d39-b906-5bb47a7b5336','上盧少卿覓千文','貫休','唐','唐诗','tang','','[]','荆山有美玉，含華尚炳爛。',60,'全唐诗/poet.tang.45000.json','["荆山有美玉，含華尚炳爛。", "堪爲聖君璽，堪爲聖君案。", "草木潤不彫，煙霞覆不散。", "野人到山下，仰視星辰畔。", "倘或如栗黃，保之上霄漢。"]'),
('548d265e-163c-4961-8869-1ccf7bf346aa','謝盧少卿惠千文','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','廬山有石鏡，高倚無塵垢。',48,'全唐诗/poet.tang.45000.json','["廬山有石鏡，高倚無塵垢。", "晝景分煙蘿，夜魄侵星斗。", "苞含物象列，搜照魚龍吼。", "寄謝天地間，毫端皆我有。"]'),
('2cd7213a-5931-48bb-bc52-933feeedf20d','大蜀皇帝壽春節進堯銘舜頌二首 堯銘','貫休','唐','唐诗','tang','','[]','金冊昭昭，列聖孤標。',180,'全唐诗/poet.tang.45000.json','["金冊昭昭，列聖孤標。", "仲尼有言，巍巍帝堯。", "承天眷命，罔厥矜驕。", "四德炎炎，堦蓂不凋。", "永孚於休，垂衣飄颻。", "吾皇則之，小心翼翼。", "秉陽亭毒，不遑暇食。", "土堦苔綠，茅茨雪滴。", "君既天賦，相亦天錫。", "德輈金鏡，以聖繼聖。", "漢高將將，太宗兵柄。", "吾皇則之，日新德盛。", "朽索六馬，罔墜厥命。", "熙熙蓼蕭，塊潤風調。", "舞擎干羽，囿入蒭蕘。", "既玉其葉，亦金其枝。", "葉葉枝枝，百工允釐。", "享國如堯，不疑不疑。"]'),
('bc3f76e0-612a-4477-b75c-48fc94778f2d','大蜀皇帝壽春節進堯銘舜頌二首 舜頌','貫休','唐','唐诗','tang','','[]','高高歷山，有黍有粟。',160,'全唐诗/poet.tang.45000.json','["高高歷山，有黍有粟。", "皇皇大舜，合堯玄德。", "五典克從，四門伊穆。", "大道將行，天下爲公。", "臨下有赫，選賢用能。", "吾皇則之，無斁無逸。", "綏厥品彙，光光得一。", "千輻臨頂，十在隨蹕。", "大哉大同，爲光爲龍。", "吾皇則之，聖謀隆隆。", "納隍孜孜，攷攷切切。", "六宗是禋，五瑞斯列。", "排麟環鳳，披香立雪。", "四夷納賮，九圍有截。", "昔救世師，降生竺乾。", "壽春亦然，萬年萬年。"]'),
('3f1a79cf-d96c-429e-b422-8571a8be136a','大蜀高祖潛龍日獻陳情偈頌','貫休','唐','唐诗','tang','','[]','有叟有叟，居岳之室。',150,'全唐诗/poet.tang.45000.json','["有叟有叟，居岳之室。", "忽振金湯，下彼巉崪。", "聞蜀風景，地寧得一。", "富人侯王，旦奭摩詰。", "龍角日角，紫氣盤屈。", "揭日月行，符湯禹出。", "天步孔艱，橫流犯蹕。", "穆穆蜀俗，整整師律。", "髯髮垂雪，忠貞貫日。", "四人蘇活，萬里豐謐。", "無雨不膏，有露皆滴。", "有叟有叟，無實行實。", "一瓶一衲，既朴且質。", "幸蒙顧盼，詞煖恩鬱。", "軒鏡光中，願如善吉。"]'),
('ab17b5a3-0877-4c22-b700-157aabd9e444','寄大願和尚','貫休','唐','唐诗','tang','','[]','道朗居太山，達磨住熊耳。',264,'全唐诗/poet.tang.45000.json','["道朗居太山，達磨住熊耳。", "手擎清涼月，靈光溢天地。", "盡騎金師子，去世久已矣。", "吾師隱廬岳，外念全刳削。", "擲孔聖之日月，相空王之橐籥。", "曾升麟德殿，譚無著。", "賜衣三銖讓不著，唯思紅泉白石閣。", "因隨裴楷離京索，邇來便止於匡霍。", "瀑布千尋噴冷煙，旃檀一枝翹瘦鶴。", "峴首故人清信在，千書萬書取不諾。", "微人昔爲門下人，扣玄佩惠無邊垠。", "自憐亦是師子子，未逾三載能嚬呻。", "一從散席歸寧後，溪寺更有誰相親。", "青山古木入白浪，赤松道士爲東鄰。", "焚香西望情何極，不及曇詵淚空滴。", "桐江太守社中人，還送郄超米千石。", "寶書遽掩修章句，萬里空函亦何益。", "終須一替辟虵人，未解融神出空寂。"]'),
('2d6bfbad-eb99-4f8e-981e-c84f2b56f23a','上顧大夫','貫休','唐','唐诗','tang','','[]','碧海漾仙洲，驪珠外無寶。',168,'全唐诗/poet.tang.45000.json','["碧海漾仙洲，驪珠外無寶。", "一岳倚青冥，羣山盡如草。", "君侯聖朝瑞，動只關玄造。", "誰云倚天劍，含霜在懷抱。", "誰云青雲險，門前是平道。", "洪民亦何幸，里巷清如掃。", "至化無經綸，至神無祝禱。", "即應炳文柄，孤平去浩浩。", "即應調鼎味，比屋堪封保。", "野人慕正化，來自海邊島。", "經傳髻裏珠，詩學池中藻。", "閉門十餘載，庭杉共枯槁。", "今朝投至鑒，得不傾肝腦。", "斯文如未精，歸山更探討。"]'),
('be6921ff-6aaa-43d8-a0d0-730a4c56e42a','寒月送玄士入天台','貫休','唐','唐诗','tang','','[]','之子逍遙塵世薄，格淡於雲語如鶴。',143,'全唐诗/poet.tang.45000.json','["之子逍遙塵世薄，格淡於雲語如鶴。", "相見唯談海上山，碧側青斜冷相沓。", "芒鞋竹杖寒凍時，玉霄忽去非有期。", "僮擔赤籠密雪裏，世人無人留得之。", "想入紅霞路深邃，孤峰縱嘯仙飆起。", "星精聚觀泣海鬼，月湧薄煙花點水。", "送君丁寧有深旨，好尋佛窟遊銀地。", "雪眉衲僧皆正氣，伊昔貞白先同此意。", "若得神聖之藥，即莫忘遠相寄。"]'),
('6bffbe8d-b870-4677-915d-ce1cfe699e76','上杜使君','貫休','唐','唐诗','tang','','[]','爲魚須處海，爲木須在岳。',156,'全唐诗/poet.tang.45000.json','["爲魚須處海，爲木須在岳。", "一登君子堂，頓覺心寥廓。", "右聽青女鏡，左聽宣尼鐸。", "政術似蒲盧，詩情出沖漠。", "從來苦清苦，近更加澹薄。", "訟庭何所有，一隻兩隻鶴。", "煙霞色擁墻，禾黍香侵郭。", "嚴霜與美雨，皆從二天落。", "蒼生苦瘡痍，如何盡消削。", "聖君新雨露，更作誰恩渥。", "即捉五色筆，密勿金鑾角。", "即同房杜手，把乾坤橐籥。", "休說卜圭峰，開門對林壑。"]'),
('6fad8b1f-159f-4826-b7c2-14d4cb7b37e9','送僧入馬頭山','貫休','唐','唐诗','tang','','[]','馬頭寶峰，秀塞寒空。',156,'全唐诗/poet.tang.45000.json','["馬頭寶峰，秀塞寒空。", "有叟有叟，真隱其中。", "無味醍醐，亦非般若。", "白趾碧目，數百瀟灑。", "苦竹大於杉，白熊臥如馬。", "金鍾撼壑，布水噴瓦。", "芙蓉堂開峰月入，岳精踏雪立屋下。", "伊余解攀緣，已是非常者。", "更有叟，獨往來，與我語。", "情無剛彊，氣透今古。", "竹笠援補，芒鞋藤乳。", "北風倒人，乾雪不聚。", "滿頭霜雪湯雪去，湯雪去。", "無人及，空望真氣江上立。"]'),
('5cf044ce-bd24-412c-88c7-de1224ad97e7','上盧使君','貫休','唐','唐诗','tang','','[]','夔龍在廟堂，雖然有僉議。',180,'全唐诗/poet.tang.45000.json','["夔龍在廟堂，雖然有僉議。", "蒼生得父母，自是天之意。", "鄱陽氣候正，文物皆鮮媚。", "金鏡有餘光，春風少閑地。", "膺門倚寒碧，到者寧容易。", "賓從皆鳳毛，爪牙悉猨臂。", "樓臺千萬戶，錦繡龍歌沸。", "大惠蟲鳥全，至嚴龍虎畏。", "可憐召伯樹，婆裟不勝翠。", "詩搜日月華，道嚥神仙味。", "嘉樹白雀來，祥煙甘露墜。", "中川一帶香，□開幽邃地。", "逸少情有餘，東山境不啻。", "恭聞聖天子，廊廟猶虛位。", "應知黎庶心，只恐徵書至。"]'),
('5ec79aef-b871-4cd4-9020-2ae523d1c1db','送顥雅禪師','貫休','唐','唐诗','tang','','[]','霜鋒擗石鳥雀聚，帆凍陰飆吹不舉。',84,'全唐诗/poet.tang.45000.json','["霜鋒擗石鳥雀聚，帆凍陰飆吹不舉。", "芬陀利香釋驎虎，幡幢冒雪爭迎取。", "春光主，芙蓉堂窄堆花乳，手提金桴打金鼓。", "天花娉婷下如雨，狻猊座上師子語。", "苦却樂，樂却苦，盧至黃金忽如土。"]'),
('ad293cec-27a2-40e3-b276-dff5567b3c41','和楊使君遊赤松山','貫休','唐','唐诗','tang','','[]','爲郡三星無一事，龔黃意外扳喬松。',128,'全唐诗/poet.tang.45000.json','["爲郡三星無一事，龔黃意外扳喬松。", "日邊揚歷不爭路，雲外苔蘚須留蹤。", "溪月未落漏滴滴，隼旟已入山重重。", "捫蘿蓋輸山屐伴，駐斾不見朝霞濃。", "乳猨劇黠掛險樹，露木翠脆生諸峰。", "初平謝公道非遠，黯然物外心相逢。", "石羊依稀齕瑤草，桃花彷彿開仙宮。", "終當歸補吾君衮，好山好水那相容。"]'),
('5cca6a4d-c12b-4615-8b65-d0cbc7bff23b','送崔使君','貫休','唐','唐诗','tang','','[]','柳門柳門，芳草芊綿。',166,'全唐诗/poet.tang.45000.json','["柳門柳門，芳草芊綿。", "日日日日，黯然黯然。", "子牟戀闕歸闕，王粲下樓相別。", "食實得地，頗淹歲月。", "今朝天子在上，合雪必雪。", "況絳之牧，文行炳潔。", "釋謂緣因，久昵清塵。", "王嘉迎安，遠狎遺民。", "嫓彼二子，厥或相似。", "論文不文，話道無滓。", "士有貴逼，勢不可遏。", "麟步規矩，鳳翥昂枿。", "峴首仁蹤項頻跋，商雲乳麝香可撮。", "望塵□□連紫闥，吾皇必用整乾坤，莫忘江頭白頭達。"]'),
('2cc440c7-195a-4b79-87e6-4b7b20b8a260','杜侯行','貫休','唐','唐诗','tang','','[]','天目連天搏秀氣，崢嶸作起新城地。',281,'全唐诗/poet.tang.45000.json','["天目連天搏秀氣，崢嶸作起新城地。", "德門鍾秀光盛時，三虎八龍皆世瑞。", "頃者天厖亂下鯨翻海，烽火崩騰照行在。", "江表唯傳君子營，劍衝牛斗疏真宰。", "金昆玉季輕三鼓，煮海懸魚臣節苦。", "鴈影參差入瑞煙，荆花燦爛開仙圃。", "我聞大中咸通真令主，相惟大杜兼小杜。", "但能致君活國濟生人，亦何必須踏金梯，折桂樹。", "宣宗懿宗調舜琴，大杜小杜爲殷霖。", "出將入相兮功德深，生人受賜兮直至今。", "杜侯兄弟繼之後，璞玉渾金美騰口。", "常言一呼百萬何足云，終取封侯之印大如斗。", "功聞吾皇似堯禹，搜索賢良皆面覩。", "杜侯杜侯，君儻修令德，克有終，即必還爲大杜兼小杜。", "人之戴兮天筆註，國之福兮天固祚。", "四海無波八表臣，如今而後君看取。"]'),
('fcc288e7-f096-45f4-ace3-eb1d795effdc','偶作五首 一','貫休','唐','唐诗','tang','','[]','誰信心火多，多能焚大國。',96,'全唐诗/poet.tang.45000.json','["誰信心火多，多能焚大國。", "誰信鬢上絲，莖莖出蠶腹。", "嘗聞養蠶婦，未曉上桑樹。", "下樹畏蠶飢，兒啼亦不顧。", "一春膏血盡，豈止應王賦。", "如何酷吏酷，盡爲搜將去。", "蠶蛾爲蝶飛，僞葉空滿枝。", "冤梭與恨機，一見一霑衣。"]'),
('1bd1fcda-a97c-44b6-9fcf-4fc1ceaf4df5','偶作五首 二','貫休','唐','唐诗','tang','','[]','機生機，巧生巧，心鑊烘烘日煎炒。',48,'全唐诗/poet.tang.45000.json','["機生機，巧生巧，心鑊烘烘日煎炒。", "闖蜀眉嚬遊海島，扶桑椹熟金烏飽。", "金烏飽，飛復飛，四天下人眼眙眙。"]'),
('5f08a3dd-01f6-46b5-908c-3bfd21e509da','偶作五首 三','貫休','唐','唐诗','tang','','[]','孰云我輕薄，石頭如何喚作玉。',63,'全唐诗/poet.tang.45000.json','["孰云我輕薄，石頭如何喚作玉。", "孰云我是非，隨邪逐惡又爭得。", "古人終不事悠悠，一言道合死即休。", "豈不見大鵬點翼蓋十洲，是何之物鳴啾啾。"]'),
('cf83f240-214a-4762-8364-fc752ecd5798','偶作五首 四','貫休','唐','唐诗','tang','','[]','君子食即食，何必在珍華。',68,'全唐诗/poet.tang.45000.json','["君子食即食，何必在珍華。", "小人食不食，縱食如泥沙。", "清歌且莫唱，妙舞亦休誇。", "爾非鳳灸麒麟肉，焉能一掛於齒牙。", "去來去來歸去來，紅泉正灑芙蓉霞。"]'),
('4845f4b5-bb3f-48b6-9108-a4f12eb5b5f7','偶作五首 五','貫休','唐','唐诗','tang','','[]','君不見金陵風臺月榭煙霞光，如今五里十里野火燒茫茫。',149,'全唐诗/poet.tang.45000.json','["君不見金陵風臺月榭煙霞光，如今五里十里野火燒茫茫。", "君不見西施綠珠顏色可傾國，樂極悲來留不得。", "君不見漢王力盡得乾坤，如何秋雨灑廟門。", "銅臺老樹作精魅，金谷野狐多子孫。", "幾許繁華幾更改，唯有堯舜周召丘軻似長在。", "坐看樓閣成丘墟，莫話桑田變成海。", "吾有清涼雪山雪，天上人間常皎潔。", "茫茫慾火欲燒人，惆悵無因爲君說。"]'),
('7822273d-bc96-4f18-9be7-e35f3434a460','山中作','貫休','唐','唐诗','tang','','[]','山爲水精宮，藉花無塵埃。',54,'全唐诗/poet.tang.45000.json','["山爲水精宮，藉花無塵埃。", "吟狂岳似動，筆落天瓊瓌。", "伊余自樂道，不論才不才。", "有時鬼笑兩三聲，疑是大謝小謝李白來。"]'),
('2920c9a1-bdab-4435-82e1-d47c75b7df5f','聞前王使君在澤潞居','貫休','唐','唐诗','tang','','[]','爲善無近名，竊名者得聲不如心，誠哉是言也。',211,'全唐诗/poet.tang.45000.json','["爲善無近名，竊名者得聲不如心，誠哉是言也。", "使君聖朝瑞，乾符初刺婺。", "德變人性靈，筆變人風土。", "煙霞與蟲鳥，和氣將美雨。", "千里與萬里，各各來相附。", "信哉有良吏，玄讖應百數。", "古人古人自古人，今日又見民歌六七袴。", "不幸大寇崩騰來，孤城勢孤固難錮。", "攀轅既不及，旌斾衝風露。", "大駕已西幸，飄零何處去？", "婺人空悲哀，對生祠泣沾莓苔。", "忽聞暫寄河之北，兵強四面無塵埃。", "唯祝鑾輿早歸來，用此咎繇仲虺才。", "使四野霧廓，八紘鏡開。", "皇天無親，長與善鄰，宜哉宜哉。"]'),
('c68e9289-7c74-449f-ac83-6f8924d8b848','將入匡山別芳晝二公二首 一','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','噴嵐堆黛塞寒碧，窗前古雪入白石。',32,'全唐诗/poet.tang.45000.json','["噴嵐堆黛塞寒碧，窗前古雪入白石。", "臨岐約我來不來，若來須撥紅霞覓。"]'),
('39b52015-5f01-4243-ba21-b1e7289c9326','將入匡山別芳晝二公二首 二','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','紅豆樹間滴紅雨，戀師不得依師住。',32,'全唐诗/poet.tang.45000.json','["紅豆樹間滴紅雨，戀師不得依師住。", "世情世界愁殺人，錦繡谷中歸舍去。"]'),
('6de0cbea-6106-46fb-83e3-3399c7e15958','送楊秀才','貫休','唐','唐诗','tang','','[]','北山峨峨香拂拂，翠漲青奔勢巉崪。',154,'全唐诗/poet.tang.45000.json','["北山峨峨香拂拂，翠漲青奔勢巉崪。", "赤松君宅在其中，紫金爲墻珠作室。", "玻璃門外仙獓睡，幢節森森絳煙密。", "水精簾捲桃花開，文錦娉婷衆非一。", "撫長離，坎答鼓。", "花姑吹簫，弄玉起舞。", "三萬八千爲半日，海涸鼇枯等閑覩。", "愛共安期碁，苦識彭祖祖。", "有時朝玉京，紅雲擁金虎。", "石橋亦是神仙住，白鳳飛來又飛去。", "五雲縹緲羽翼高，世人仰望心空勞。"]'),
('f235b793-9b94-4451-a5c4-14b30ed54060','別杜將軍','貫休','唐','唐诗','tang','','[]','伊余本是胡爲者，採蕈鋤茶在窮野。',138,'全唐诗/poet.tang.45000.json','["伊余本是胡爲者，採蕈鋤茶在窮野。", "偶披蓑笠事空王，餘力爲文擬何謝。", "少年心在青雲端，知音滿地皆龍鸞。", "遽逢天步艱難日，深藏溪谷空長歎。", "偶出重圍遇英哲，留我江樓經歲月。", "身隈玉帳香滿衣，夢歷金盆雨和雪。", "東風來兮歌式微，深雲道人召來歸。", "燕辭大廈兮將何爲，濛濛花雨兮鶯飛飛，一汀楊柳同依依。"]'),
('5daf4987-6227-49bf-8375-446332ed4f4e','送夢上人歸京','貫休','唐','唐诗','tang','','[]','伊余龍鍾歸海涯，千山萬水情自怡。',136,'全唐诗/poet.tang.45000.json','["伊余龍鍾歸海涯，千山萬水情自怡。", "夢公別我還上國，江邊慘執行遲遲。", "向我道雲中覓伴未得伴，又示我數首新詩盡是詩。", "只恐不如此，若如此如此，即須天子知。", "蕭蕭金吹荆門口，槐菊鬬黃落葉走。", "前程勝事未可涯，但空圭峰難入手。", "蓮峰掌記韓拾遺，鴈行雍穆世所稀。", "二十年前即別離，憑師一話吟朝飢。"]'),
('59841f8a-df17-4d9d-99b8-3b447d3cc54a','問岳禪師疾','貫休','唐','唐诗','tang','','[]','世病如山岳，世醫皆拱手。',98,'全唐诗/poet.tang.45000.json','["世病如山岳，世醫皆拱手。", "道病如金鎖，師遭鎖鎖否。", "伊昔芙蓉頰，談經似主涉。", "蘇合晝氤氳，天花似飛蝶。", "覺樹垂實，魔輩刺疾。", "病也不問，終不皴膝。", "春光冉冉，不上爾質。", "東風浩浩，謾入爾室。", "云何斯人，而有斯疾。"]'),
('0f717aea-de1d-4c03-b5b4-2e84875a269d','上荆南府主三讓德政碑','貫休','唐','唐诗','tang','','[]','明明赫赫中興主，動納諸隍冠前古。',163,'全唐诗/poet.tang.45000.json','["明明赫赫中興主，動納諸隍冠前古。", "四海英雄盡戢兵，皆如圪圪天金柱。", "萬姓多論政與德，請樹豐碑似山岳。", "一從寇滅二十年，琬琰雕鐫賜重疊。", "荆州化風何卓異，寡欲無爲合天地。", "雖立貞碑與衆殊，字字皆是吾皇意。", "君侯捧碑西拜泣，臣且何人恩洊及。", "鳳皇銜下雕龍文，德昧政虛爭敢立。", "函封三奏心匍匐，堅讓此碑聲蓋國。", "我恐江淹五色筆，作不立此碑之碑文不得。"]'),
('4c379ad7-41ed-418e-ba95-6dfb40b01eca','施萬病丸','貫休','唐','唐诗','tang','','[]','我聞昔有海上翁，鬚眉皎白塵土中。',96,'全唐诗/poet.tang.45000.json','["我聞昔有海上翁，鬚眉皎白塵土中。", "葫蘆盛藥行如風，病者與藥皆惺憁。", "藥王藥上親兄弟，救人急於己諸體。", "玉毫調御偏讚揚，金輪釋梵咸歸禮。", "賢守運心亦相似，不吝親親拘子子。", "曾聞古德有深言，由來大士皆如此。"]'),
('8e3beb3e-384b-415d-8b9a-92e7b3b3c0af','甘雨應祈','貫休','唐','唐诗','tang','','[]','春雨偶愆期，草木亦未覺。',188,'全唐诗/poet.tang.45000.json','["春雨偶愆期，草木亦未覺。", "君侯不遑處，退食或閉閣。", "東海浪滔滔，西江波漠漠。", "得不願身爲大虬，金其角，玉其甲。", "一吸再喢，雲平霧匝。", "華暢九有，清傾六合。", "使不蘇者蘇，不足者足。", "情通上玄，如膏綿綿。", "有叟有叟，鼓腹歌於道邊。", "歌曰：麥苗芃芃兮鶬鶊飛，日出而作兮日入歸，如彼草木兮雨露肥。", "古人三樂兮，我樂多之。", "天之成兮，地之平兮。", "柘系黃兮，瓠葉青兮。", "乳女啼兮，蒸黍馨兮。", "炙背捫虱兮，復何經營兮。"]'),
('dcf396a5-34c7-4f7e-80e2-4ed286d89ac7','寄韓團練','貫休','唐','唐诗','tang','','[]','真宰動洪鑪，萬物皆消息。',168,'全唐诗/poet.tang.45000.json','["真宰動洪鑪，萬物皆消息。", "唯有三珠樹，不用東風力。", "君子天廟器，頭骨何巉崱。", "海內久聞名，江西偶相識。", "誰不有詩機，麟龍不解織。", "誰不有心地，蘭茝不曾植。", "多君二俱作，獨立千仞壁。", "話道出先天，憑師動臻極。", "青霄鴈行律，紅露荆花滴。", "偶然成遠別，別後長相憶。", "行至鄱陽郡，又見謝安石。", "留我遇殘冬，身心苦恬寂。", "江上春又至，引頸山空積。", "何日再相逢，天香滿瑤席。"]'),
('bad8119c-a952-494d-8d13-2bfadfa43c05','春野作五首 一','貫休','唐','唐诗','tang','','[]','閑步淺青平綠，流水征車自逐。',30,'全唐诗/poet.tang.45000.json','["閑步淺青平綠，流水征車自逐。", "誰家挾彈少年，擬打紅衣[啄]木。"]'),
('8d301c1b-a0f9-4ce9-a299-74fe08a31036','春野作五首 二','貫休','唐','唐诗','tang','','[]','山花雨打盡，滿地如爛錦。',24,'全唐诗/poet.tang.45000.json','["山花雨打盡，滿地如爛錦。", "遠尋鷓鴣雛，拾得一團蕈。"]'),
('79d591d4-9cbd-4424-bab5-3f75dd8a2965','春野作五首 三','貫休','唐','唐诗','tang','','[]','大牛苦耕田，乳犢望似泣。',24,'全唐诗/poet.tang.45000.json','["大牛苦耕田，乳犢望似泣。", "萬事皆天意，綠草頭蕺蕺。"]'),
('49963281-37ec-4930-b46d-2167f9799321','春野作五首 四','貫休','唐','唐诗','tang','','[]','斜陽射破冢，髑髏半出地。',24,'全唐诗/poet.tang.45000.json','["斜陽射破冢，髑髏半出地。", "不知誰氏子，猶自作意氣。"]'),
('14d1d929-ec98-4841-8097-b47179050aa9','春野作五首 五','貫休','唐','唐诗','tang','','[]','拋牛沙上鬬百草，鉏隴老人又太老。',32,'全唐诗/poet.tang.45000.json','["拋牛沙上鬬百草，鉏隴老人又太老。", "薄煙漠漠覆桑棗，戴嵩醉後取次掃。"]'),
('2ea2805c-d7d1-4005-9f72-9fd3b606a410','深山逢老僧二首 一','貫休','唐','唐诗','tang','','[]','衲衣線麄心似月，自把短鋤鋤榾柮。',32,'全唐诗/poet.tang.45000.json','["衲衣線麄心似月，自把短鋤鋤榾柮。", "青石溪邊踏葉行，數片雲隨兩眉雪。"]'),
('76124fa1-0a96-470d-a832-8f0742278cd5','深山逢老僧二首 二','貫休','唐','唐诗','tang','','[]','山童貌頑名乞乞，放火燒畬采崖蜜。',32,'全唐诗/poet.tang.45000.json','["山童貌頑名乞乞，放火燒畬采崖蜜。", "擔頭何物帶山香，一籮白蕈一籮栗。"]'),
('565fe987-81c5-439e-98c5-5600c795adfa','道情偈','貫休','唐','唐诗','tang','','[]','草木亦有性，與我將不別。',48,'全唐诗/poet.tang.45000.json','["草木亦有性，與我將不別。", "我若似草木，成道無時節。", "世人不會道，向道却嗔道。", "傷嗟此輩人，寶山不得寶。"]'),
('1605dbfb-06a9-4fe7-9dcf-b8932826532c','懷二三朝友','貫休','唐','唐诗','tang','','[]','傷心復傷心，流光似飛電。',85,'全唐诗/poet.tang.45000.json','["傷心復傷心，流光似飛電。", "有惠驪龍十斛珠，不如一見君子面。", "愁人復愁人，滿眼皆埃塵。", "有惠黃金一萬斤，不如一見於仁人。", "我昔讀詩書，如今盡拋也。", "只記得田叔孟溫舒，帝王滿口呼長者。"]'),
('f3dc4fbc-522c-4834-9cbd-ef747969f1e2','偶作','貫休','唐','唐诗','tang','','[]','君子稱一善，馨香遍九垓。',60,'全唐诗/poet.tang.45000.json','["君子稱一善，馨香遍九垓。", "小人妬一善，處處生嫌猜。", "口如暴死人，鐵尺抝不開。", "稂莠蝕田髓，積陰成冬雷。", "因知咋舌人，千古空悠哉。"]'),
('4b2c787e-9399-499b-b5f8-c71be1879676','義士行','貫休','唐','唐诗','tang','','[]','先生先生不可遇，愛平不平眉斗豎。',32,'全唐诗/poet.tang.45000.json','["先生先生不可遇，愛平不平眉斗豎。", "黃昏雨雹空似黳，別我不知何處去。"]'),
('cffd0769-b125-4945-896d-d4caf42ec0ed','觀懷素草書歌','貫休','唐','唐诗','tang','','[]','張顛顛後顛非顛，直至懷素之顛始是顛。',400,'全唐诗/poet.tang.45000.json','["張顛顛後顛非顛，直至懷素之顛始是顛。", "師不譚經不說禪，筋力唯於草書朽。", "顛狂却恐是神仙，有神助兮人莫及。", "鐵石畫兮墨須入，金尊竹葉數斗餘。", "半斜半傾山衲濕，醉來把筆獰如虎。", "粉壁素屏不問主，亂拏亂抹無規矩。", "羅剎石上坐伍子胥，蒯通八字立對漢高祖。", "勢崩騰兮不可止，天機暗轉鋒鋩裏。", "閃電光邊霹靂飛，古栢身中𣵡龍死。", "駭人心兮目眓{目臭}，頓人足兮神辟易。", "乍如沙場大戰後，斷槍橛箭皆狼籍。", "又似深山朽石上，古病松枝掛鐵錫。", "月兔筆，天竈墨，斜鑿黃金側剉玉。", "珊瑚枝長大束束，天馬驕獰不可勒。", "東却西，南又北，倒又起，斷復續。", "忽如鄂公喝住單雄信，秦王肩上𠞈著棗木槊。", "懷素師，懷素師，若不是星辰降瑞，即必是河岳孕靈。", "固宜須冷笑逸少，爭得不心醉伯英。", "天台古杉一千尺，崖崩劁折何崢嶸。", "或細微，仙衣半拆金線垂。", "或妍媚，桃花半紅公子醉。", "我恐山爲墨兮磨海水，天與筆兮書大地。", "乃能畧展狂僧意，常恨與師不相識。", "一見此書空歎息，伊昔張渭任華葉季良。"]'),
('5689d532-07b4-467b-9725-ee2642c76144','送盧舍人三首 一','貫休','唐','唐诗','tang','','[]','一曰：勸君不用登峴首山，讀羊祜碑。',53,'全唐诗/poet.tang.45000.json','["一曰：勸君不用登峴首山，讀羊祜碑。", "男兒事業須自奇，此碑山頭如日月。", "日日照人人不知，人不知，青山白雲徒爾爲。"]'),
('19185848-0d6e-423a-9b40-54fb433442cb','送盧舍人三首 二','貫休','唐','唐诗','tang','','[]','二曰：勸君登商山，不用覓商山皓。',102,'全唐诗/poet.tang.45000.json','["二曰：勸君登商山，不用覓商山皓。", "雲深雪深騾馬倒，我願終南太華變爲金。", "吾后見之不爲寶，我願九州四海紙。", "幅幅與君爲諫草，使躡卨踐夔。", "逢軒見皞，日環五色。", "是物得老，如此即商山皓。", "商山皓，君不用討他，他必來相討。"]'),
('8fc8539e-1fd5-414a-a3a7-f8cf2e10e1dc','送盧舍人三首 三','貫休','唐','唐诗','tang','','[]','三曰：君不見釋梵諸天壽億垓，天上人間去復來。',157,'全唐诗/poet.tang.45000.json','["三曰：君不見釋梵諸天壽億垓，天上人間去復來。", "君又不見紫金爲輪一千幅，寶洲□四皆臣伏。", "輪王釋梵作何因，祗是弘隆大乘福。", "自古皇王與賢哲，頂敬心師刻金玉。", "報通三世釋迦言，莫將梁武爲題目。", "君不見近代韋裴蔣與蕭，文房書府師百僚。", "代天理物映千古，布髮掩泥非一朝。", "大哉釋梵輪王璞，已矣何人繼先覺。", "行行珍重寄斯言，斯言不是尋常曲。"]'),
('5548982c-af27-4a74-988e-98d95c66758a','宿深村','貫休','唐','唐诗','tang','','[]','行行一宿深村裏，雞犬豐年鬧如市。',32,'全唐诗/poet.tang.45000.json','["行行一宿深村裏，雞犬豐年鬧如市。", "黃昏見客合家喜，月下取魚戽塘水。"]'),
('cef18895-f2cc-4542-9b66-b51473e3d1f6','黃鶯','貫休','唐','唐诗','tang','','[]','一種爲春禽，花中開羽翼。',36,'全唐诗/poet.tang.45000.json','["一種爲春禽，花中開羽翼。", "如何此鳥身，便是黃金色。", "黃金色，若逢竹實終不食。"]'),
('3ca56169-b0b3-4dd6-b8ef-9f013f4b193e','送越將歸會稽','貫休','唐','唐诗','tang','','[]','面如玉盤身八尺，燕語清獰戰袍窄。',64,'全唐诗/poet.tang.45000.json','["面如玉盤身八尺，燕語清獰戰袍窄。", "古嶽龍腥一匣霜，江上相逢雙眼碧。", "冉冉春光方婉娩，黯然別我歸稽巘。", "他年必帥邯鄲兒，與我殺輕班定遠。"]'),
('2c26b989-0b62-4d52-9f62-fc5c71eb945b','別仙客','貫休','唐','唐诗','tang','','[]','巨鼇頭縮翻仙翠，蟠桃爛落珊瑚地。',32,'全唐诗/poet.tang.45000.json','["巨鼇頭縮翻仙翠，蟠桃爛落珊瑚地。", "浪濺霓旌濕鵬翅，畧別千年太容易。"]'),
('4b307d65-7a4f-41ad-9ba3-8c1edd4589c9','寒江上望','貫休','唐','唐诗','tang','','[]','荒岸燒未死，白雲癡不動。',24,'全唐诗/poet.tang.45000.json','["荒岸燒未死，白雲癡不動。", "極目無人行，浪打取魚籠。"]'),
('ca0ab538-c4ad-42ba-8ed3-4c8a7ca1b96b','讀唐史','貫休','唐','唐诗','tang','','[]','我愛李景伯，內宴執良規。',60,'全唐诗/poet.tang.45000.json','["我愛李景伯，內宴執良規。", "君臣道昭彰，天顏終熙怡。", "大簸怕清風，糠粃繚亂飛。", "洪鑪烹五金，黃金終自奇。", "大哉爲忠臣，捨此何所之。"]'),
('593ed65c-1082-495d-b677-a341751b2a35','樵叟','貫休','唐','唐诗','tang','','[]','樵父貌飢帶塵土，自言一生苦寒苦。',32,'全唐诗/poet.tang.45000.json','["樵父貌飢帶塵土，自言一生苦寒苦。", "擔頭擔箇赤瓷甖，斜陽獨立濛籠塢。"]'),
('ff25c2e2-054b-4968-a63f-f779da127d60','春山行','貫休','唐','唐诗','tang','','[]','重疊太古色，濛濛花雨時。',48,'全唐诗/poet.tang.45000.json','["重疊太古色，濛濛花雨時。", "好峰行恐盡，流水語相隨。", "黑壤生紅黍，黃猨領白兒。", "因思石橋月，曾與故人期。"]'),
('68d30fd3-058d-4305-b4f6-e62bc97535b0','送諫官南遷','貫休','唐','唐诗','tang','','[]','危行危言者，從天落海涯。',48,'全唐诗/poet.tang.45000.json','["危行危言者，從天落海涯。", "如斯爲遠客，始是好男兒。", "瘴雜交州雨，犀揩馬援碑。", "不知千萬里，誰復識辛毗。"]'),
('6f578b08-7dd6-414e-bcc7-23acbed69df6','懷香爐峰道人','貫休','唐','唐诗','tang','','[]','常思峰頂叟，石窟土爲牀。',48,'全唐诗/poet.tang.45000.json','["常思峰頂叟，石窟土爲牀。", "日日先見日，煙霞多異香。", "冥心同槁木，掃雪帶微陽。", "終必相尋去，斯人不可忘。"]'),
('0b9b6763-fff0-4951-bf14-acc5bdc07a43','觀李翰林真二首 一','貫休','唐','唐诗','tang','','[]','日角浮紫氣，凜然塵外清。',48,'全唐诗/poet.tang.45000.json','["日角浮紫氣，凜然塵外清。", "雖稱李太白，知是那星精。", "御宴千鍾飲，蕃書一筆成。", "宜哉杜工部，不錯道騎鯨。"]'),
('a42c920e-9a02-46aa-868c-65922521e2f8','觀李翰林真二首 二','貫休','唐','唐诗','tang','','[]','誰氏子丹青，毫端曲有靈。',48,'全唐诗/poet.tang.45000.json','["誰氏子丹青，毫端曲有靈。", "屹如山忽墮，爽似酒初醒。", "天馬難攏勒，仙房久閉扃。", "若非如此輩，何以傲彤庭。"]'),
('6cde46e0-fe46-48f5-a25e-078b75bf1f3c','晚泊湘江作','貫休','唐','唐诗','tang','','[]','煙浪瀁秋色，高吟似有鄰。',48,'全唐诗/poet.tang.45000.json','["煙浪瀁秋色，高吟似有鄰。", "一輪湘渚月，萬古獨醒人。", "岸濕穿花遠，風香禱廟頻。", "祗應諛佞者，到此不傷神。"]'),
('3ec8c54b-2eda-48f6-b177-99b116d27b07','淮上逢故人','貫休','唐','唐诗','tang','','[]','故園離亂後，十載始逢君。',48,'全唐诗/poet.tang.45000.json','["故園離亂後，十載始逢君。", "長恨南熏奏，尋常只自聞。", "荒窗秋見岳，赤地夜生雲。", "莫歎謀身晚，中興正用文。"]'),
('908f68ec-e7d3-4d08-9564-19f4b10d12ba','讀杜工部集二首 一','貫休','唐','唐诗','tang','','[]','造化拾無遺，唯應杜甫詩。',48,'全唐诗/poet.tang.45000.json','["造化拾無遺，唯應杜甫詩。", "豈非玄域橐，奪得古人旗。", "日月精華薄，山川氣概卑。", "古今吟不盡，惆悵不同時。"]'),
('8e7c374d-32dc-449d-9f57-ee519658a459','讀杜工部集二首 二','貫休','唐','唐诗','tang','','[]','甫也道亦喪，孤身出蜀城。',48,'全唐诗/poet.tang.45000.json','["甫也道亦喪，孤身出蜀城。", "彩毫終不撅，白雲更能輕。", "命薄相如命，名齊李白名。", "不知耒陽令，何以葬先生。"]'),
('e5d77052-7f2e-430e-9e2c-50a000250542','題簡禪師院','貫休','唐','唐诗','tang','','[]','機忘室亦空，靜與沃洲同。',48,'全唐诗/poet.tang.45000.json','["機忘室亦空，靜與沃洲同。", "唯有半庭竹，能生竟日風。", "思山海月上，出定印香終。", "繼後傳衣者，還須立雪中。"]'),
('4a40f2eb-0402-4c4a-aa1d-008f15f26862','讀劉得仁賈島集二首 一','貫休','唐','唐诗','tang','','[]','二公俱作者，其奈亦迂儒。',48,'全唐诗/poet.tang.45000.json','["二公俱作者，其奈亦迂儒。", "且有諸峰在，何將一第吁。", "句還如菡萏，誰復贈襜褕。", "想得重泉下，依前與衆殊。"]'),
('001a7fb3-c61b-42aa-82bc-28d470be9b08','讀劉得仁賈島集二首 二','貫休','唐','唐诗','tang','','[]','役思曾衝尹，多言阻國親。',48,'全唐诗/poet.tang.45000.json','["役思曾衝尹，多言阻國親。", "桂枝何所直，陋巷不勝貧。", "馬病唯湯雪，門荒劣有人。", "伊余吟亦苦，爲爾一眉嚬。"]'),
('175daf3f-fa38-4918-b8b0-59a838cc0d40','天台老僧','貫休','唐','唐诗','tang','','[]','獨住無人處，松龕嶽色侵。',48,'全唐诗/poet.tang.45000.json','["獨住無人處，松龕嶽色侵。", "僧中九十臘，雲外一生心。", "白髮垂不剃，青眸笑轉深。", "猶能指孤月，爲我暫開襟。"]'),
('30c5a9be-4fc0-4953-9341-83e924d9b2b0','經費隱君舊宅','貫休','唐','唐诗','tang','','[]','巉巖玉九株，秀濕掩蒼梧。',48,'全唐诗/poet.tang.45000.json','["巉巖玉九株，秀濕掩蒼梧。", "祥瑞久不出，羲軒消得無。", "雨和高瀑濁，燒熁大櫧枯。", "到此思歸去，迢迢隔五湖。"]'),
('f0c7bf66-3a40-487d-82fe-9af8017e6562','秋末懷舊山','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','昔住匡廬北，無人知姓名。',48,'全唐诗/poet.tang.45000.json','["昔住匡廬北，無人知姓名。", "侵雲收穀粟，引蟻上柑橙。", "寒雨雪兼落，枯林虎獨行。", "誰能將白髮，共向此中生。"]'),
('da1610bf-679f-49e6-8ab3-2e926f45ccc3','春過鄱陽湖','貫休','唐','唐诗','tang','','[]','百慮片帆下，風波極目看。',48,'全唐诗/poet.tang.45000.json','["百慮片帆下，風波極目看。", "吳山兼鳥沒，楚色入衣寒。", "過此愁人處，始知行路難。", "夕陽沙島上，回首一長歎。"]'),
('fd191111-d21a-4629-b8ea-746b065847e0','寄僧野和尚','貫休','唐','唐诗','tang','','[]','鳥外更誰親，諸峰即四鄰。',48,'全唐诗/poet.tang.45000.json','["鳥外更誰親，諸峰即四鄰。", "白頭寒枕石，青衲爛無塵。", "橡栗堆行徑，猨猴遶定身。", "儻然重結社，願作掃壇人。"]'),
('f22a59d9-515a-4678-8b84-b95f753ac599','寄馮使君','貫休','唐','唐诗','tang','','[]','端居碧雲暮，好鳥啼紅芳。',48,'全唐诗/poet.tang.45000.json','["端居碧雲暮，好鳥啼紅芳。", "滿郭桃李熟，捲簾風雨香。", "清吟繡段句，默念芙蓉章。", "未得歸山去，頻升謝守堂。"]'),
('ef62eaac-02c0-48eb-a6a1-23c45c4fe25e','寄紫閣隱者','貫休','唐','唐诗','tang','','[]','積翠藏一叟，常思未得遊。',48,'全唐诗/poet.tang.45000.json','["積翠藏一叟，常思未得遊。", "不知在巖下，爲復在峰頭。", "苔上枯藤笐，泉淋破石樓。", "伊余更何事，不學此翁休。"]'),
('2c6210d5-bdbc-4b33-87c6-50e1f988a7e9','寄天台道友','貫休','唐','唐诗','tang','','[]','大是清虛地，高吟到日晡。',120,'全唐诗/poet.tang.45000.json','["大是清虛地，高吟到日晡。", "水聲金磬亂，雲片玉盤粗。", "仙有遺蹤在，人還得意無。", "石碑文不值，壁畫色多枯。", "冷立千年鶴，閑燒六一爐。", "松枝垂似物，山勢秀難圖。", "紫府程非遠，清溪徑不迂。", "馨香柏上露，皎潔水中珠。", "賢聖無他術，圓融只在吾。", "寄言桐柏子，珍重保之乎。"]'),
('a12abc62-60d5-490c-b41f-3c3242f69fc7','旅中懷孫路','貫休','唐','唐诗','tang','','[]','暮塵微雨收，蟬急楚鄉秋。',48,'全唐诗/poet.tang.45000.json','["暮塵微雨收，蟬急楚鄉秋。", "一片月出海，幾家人上樓。", "砌香殘果落，汀草宿煙浮。", "唯有知音者，相思歌白頭。"]'),
('72c08cb2-34c6-4196-8302-fc80165bbecd','貽世','貫休','唐','唐诗','tang','','[]','至理不誤物，悠悠自不明。',48,'全唐诗/poet.tang.45000.json','["至理不誤物，悠悠自不明。", "黃金燒欲盡，白髮火邊生。", "苦惑神仙䜝，難收日月精。", "捕風兼繫影，信矣不須爭。"]'),
('58b4d694-56c7-4946-bdc5-4f27deb5b512','覽李秀才卷','貫休','唐','唐诗','tang','','[]','香沐整山衣，開君一軸詩。',48,'全唐诗/poet.tang.45000.json','["香沐整山衣，開君一軸詩。", "吟當秋景苦，味出雪林遲。", "經濟幾人到，工夫兩鬢知。", "因嗟和氏淚，不是等閑垂。"]'),
('3305e7cf-60ac-4306-87a1-79c080ecb2c7','懷方干張爲','貫休','唐','唐诗','tang','','[]','冥搜入仙窟，半夜水堂前。',36,'全唐诗/poet.tang.45000.json','["冥搜入仙窟，半夜水堂前。", "吾道祗如此，古人多亦然。", "螢沈荒塢霧，月苦綠梧蟬。"]'),
('091dfdbf-c8d1-4d28-9da0-f956f5583bbf','四皓圖','貫休','唐','唐诗','tang','','[]','何人圖四皓，如語話嘮嘮。',48,'全唐诗/poet.tang.45000.json','["何人圖四皓，如語話嘮嘮。", "雙鬢雪相似，是誰年最高。", "溪苔連豹褥，仙酒汙雲袍。", "想得忘秦日，伊余亦合逃。"]'),
('88626846-4a90-4f2e-8582-d2d17ed3eb29','懷白閣道侶','貫休','唐','唐诗','tang','','[]','寒思白閣層，石屋兩三僧。',48,'全唐诗/poet.tang.45000.json','["寒思白閣層，石屋兩三僧。", "斜雪掃不盡，飢猨喚得應。", "香然一字火，磬過數潭冰。", "終必相尋去，孤懷久不勝。"]'),
('84a2c28d-7421-4ef3-8d56-9b22f6239263','讀孟郊集','貫休','唐','唐诗','tang','','[]','東野子何之，詩人始見詩。',48,'全唐诗/poet.tang.45000.json','["東野子何之，詩人始見詩。", "清刳霜雪髓，吟動鬼神司。", "舉世言多媚，無人師此師。", "因知吾道後，冷淡亦如斯。"]'),
('3b5f0e5c-4a1b-4356-92e8-f689f47d8701','懷四明亮公','貫休','唐','唐诗','tang','','[]','孤峰含紫煙，師住此安禪。',48,'全唐诗/poet.tang.45000.json','["孤峰含紫煙，師住此安禪。", "不下便不下，如斯太可憐。", "坐侵天井黑，吟久海霞蔫。", "豈覺塵埃裏，干戈已十年。"]'),
('fae002b8-9045-43d3-be91-69102ee2f677','秋過錢塘江','貫休','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','巨浸東隅極，山吞大野平。',48,'全唐诗/poet.tang.45000.json','["巨浸東隅極，山吞大野平。", "因知吳相恨，不盡海濤聲。", "黑氣騰蛟窟，秋雲入戰城。", "遊人千萬里，過此白髭生。"]'),
('1f4b7a50-1c95-49ae-8f30-c57dc39bda98','上俞許二判官','貫休','唐','唐诗','tang','','[]','近拋蓑笠者，急善遇休明。',48,'全唐诗/poet.tang.45000.json','["近拋蓑笠者，急善遇休明。", "未省親宗伯，焉能識正聲。", "病容經夏在，岳夢入秋幷。", "無限林中意，今逢許郭傾。"]'),
('e79adefc-4434-4a9e-beae-1cced23d00d8','懷劉得仁','貫休','唐','唐诗','tang','','[]','詩名動帝畿，身謝亦因詩。',48,'全唐诗/poet.tang.45000.json','["詩名動帝畿，身謝亦因詩。", "白日只如哭，皇天得不知。", "旅墳孤𨃤岳，羸僕泣如兒。", "多少求名者，聞之淚盡垂。"]'),
('cb0565db-2757-412d-8dcd-10e47a27741e','歸故林後寄二三知己','貫休','唐','唐诗','tang','','[]','昨別楚江邊，逡巡早數年。',48,'全唐诗/poet.tang.45000.json','["昨別楚江邊，逡巡早數年。", "詩雖清到後，人更瘦於前。", "岸翠連喬嶽，汀沙入壞田。", "何時重一見，談笑有茶煙。"]'),
('7359e37f-faf1-44d9-b7ea-a00dc0e465b6','春寄西山陳陶','貫休','唐','唐诗','tang','','[]','搔首復搔首，孤懷草萋萋。',48,'全唐诗/poet.tang.45000.json','["搔首復搔首，孤懷草萋萋。", "春光已滿目，君在西山西。", "塹水成文去，庭柯擎翠低。", "所思不可見，黃鳥花中啼。"]'),
('3d39c680-b9ea-4866-847b-c5ce3237929b','秋末江行','貫休','唐','唐诗','tang','','[]','四顧木落盡，扁舟增所思。',48,'全唐诗/poet.tang.45000.json','["四顧木落盡，扁舟增所思。", "雲衝遠燒出，帆轉大荒遲。", "天際霜雪作，水邊蒿艾衰。", "斷猨不堪聽，一聽亦同悲。"]'),
('f8dc1637-e7f7-4982-9936-b45d4e44e459','送人歸新羅','貫休','唐','唐诗','tang','','[]','昨夜西風起，送君歸故鄉。',48,'全唐诗/poet.tang.45000.json','["昨夜西風起，送君歸故鄉。", "積愁窮地角，見日上扶桑。", "蜃氣生初霽，潮痕匝亂荒。", "從茲頭各白，魂夢一相望。"]'),
('49c329a1-eceb-4993-a1d2-9d6497af346f','思匡山賈匡','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','山兄詩癖甚，寒夜更何爲。',48,'全唐诗/poet.tang.45000.json','["山兄詩癖甚，寒夜更何爲。", "覓句唯頑坐，嚴霜打不知。", "石膏黏木屐，崖蜜落冰池。", "近見禪僧說，生涯勝往時。"]'),
('b8fbd555-2a68-478b-a457-25dbfd053e66','偶作','貫休','唐','唐诗','tang','','[]','十載獨扃扉，唯爲二雅詩。',48,'全唐诗/poet.tang.45000.json','["十載獨扃扉，唯爲二雅詩。", "道孤終不雜，頭白更何疑。", "句冷杉松與，霜嚴鼓角知。", "修心對閑鏡，明月印秋池。"]'),
('baf9995f-364c-4c99-b981-41838cf562c2','贈方干','貫休','唐','唐诗','tang','','[]','盛名與高隱，合近謝敷村。',48,'全唐诗/poet.tang.45000.json','["盛名與高隱，合近謝敷村。", "弟子已得桂，先生猶灌園。", "垂綸侵海介，拾句歷雲根。", "白日昇天路，如君別有門。"]'),
('f70914bd-6189-41db-b71d-0150db9ea2f9','漁父','貫休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一葉一竿竹，眉鬚雪欲零。',48,'全唐诗/poet.tang.45000.json','["一葉一竿竹，眉鬚雪欲零。", "陸應無祖業，香必是伊腥。", "兒亦名魚鷓，歌稱我洞庭。", "回頭深自媿，舊業近滄溟。"]'),
('bddf11e8-b166-40f0-acfb-73d4a2cb6e0e','題友人山居','貫休','唐','唐诗','tang','','[]','卜居鄰塢寺，魂夢又相關。',48,'全唐诗/poet.tang.45000.json','["卜居鄰塢寺，魂夢又相關。", "鶴本如雲白，君初似我閑。", "月明僧渡水，木落火連山。", "從此天台約，來茲未得還。"]'),
('958ba357-f213-43d2-b5c5-da1e222cfabc','寄宋使君','貫休','唐','唐诗','tang','','[]','寺倚烏龍腹，窗中見碧稜。',48,'全唐诗/poet.tang.45000.json','["寺倚烏龍腹，窗中見碧稜。", "空廊人畫祖，古殿鶴窺燈。", "風吼深松雪，爐寒一鼎冰。", "唯應謝內史，知此道心澄。"]'),
('1ae34a5d-57eb-4d41-a539-40831acfcbab','懷武夷紅石子二首 一','貫休','唐','唐诗','tang','','[]','常思紅石子，獨自住山椒。',48,'全唐诗/poet.tang.45000.json','["常思紅石子，獨自住山椒。", "窗外猩猩語，爐中奼奼嬌。", "乳香諸洞滴，地秀衆峰朝。", "曾見奇人說，煙霞恨太遙。"]'),
('9ec3b793-5144-4531-ad9d-3461bb10692e','懷武夷紅石子二首 二','貫休','唐','唐诗','tang','','[]','弋者終何慕，高吟坐綠鼇。',48,'全唐诗/poet.tang.45000.json','["弋者終何慕，高吟坐綠鼇。", "燒侵薑芋窖，僧與水雲袍。", "竹鞘畬刀缺，松枝獵箭勞。", "何時一相見，清話擘蟠桃。"]'),
('517cc330-aad1-4218-bf53-27cd8314a62f','送人征蠻','貫休','唐','唐诗','tang','','[]','七縱七擒處，君行事可攀。',48,'全唐诗/poet.tang.45000.json','["七縱七擒處，君行事可攀。", "亦知磨一劒，不獨定諸蠻。", "樹盡低銅柱，潮常沸火山。", "名須麟閣上，好去及瓜還。"]'),
('5c957047-1970-4e2a-95ff-18018f2fa0b5','懷周朴張爲','貫休','唐','唐诗','tang','','[]','二子無消息，多應各自耕。',48,'全唐诗/poet.tang.45000.json','["二子無消息，多應各自耕。", "巴江思杜甫，漳水憶劉楨。", "白髮應全白，生涯作麽生。", "寄書多不達，空念重行行。"]'),
('9330db84-8fa0-4a78-a829-68d40a824ad8','寄令狐郎中','貫休','唐','唐诗','tang','','[]','雨打繁暑盡，放懷步微涼。',48,'全唐诗/poet.tang.45000.json','["雨打繁暑盡，放懷步微涼。", "綠苔狂似人，入我白玉堂。", "塹鳥眠堪畫，庭檉夜益香。", "唯應蘂宮子，時到虎溪傍。"]'),
('3c698a82-92fb-417f-bd4d-187d615b3fe5','鄱陽道中作','貫休','唐','唐诗','tang','','[]','鄱陽古岸邊，無一樹無蟬。',48,'全唐诗/poet.tang.45000.json','["鄱陽古岸邊，無一樹無蟬。", "路轉他山大，砧驅鄉思偏。", "湖平帆盡落，天淡月初圓。", "何事堯雲下，干戈滿許田。"]'),
('d840a583-6308-4307-bf1e-b2d734f21d98','歸故林別知己','貫休','唐','唐诗','tang','','["\u957f\u6c5f"]','別離無古今，柳色向人深。',48,'全唐诗/poet.tang.45000.json','["別離無古今，柳色向人深。", "萬里長江水，平生不印心。", "遠書容北雁，贈別謝南金。", "媿勉青雲志，余懷非陸沈。"]'),
('ff40d41a-7501-4e90-ac9e-62288b730b87','送僧遊天台','貫休','唐','唐诗','tang','','[]','囊空心亦空，城郭去騰騰。',48,'全唐诗/poet.tang.45000.json','["囊空心亦空，城郭去騰騰。", "眼作麽是眼，僧誰識此僧。", "歇隈紅樹久，笑看白雲崩。", "已有天台約，深秋必共登。"]'),
('15efe7df-33f0-4fc5-8abb-fad09d91380b','詠竹根珓子','貫休','唐','唐诗','tang','','[]','出處慙林藪，才微幸一陽。',48,'全唐诗/poet.tang.45000.json','["出處慙林藪，才微幸一陽。", "不緣懷片善，豈得近馨香。", "節亦因人淨，聲從擲地彰。", "但令筋力在，永願報時昌。"]'),
('7a3bfb22-eaa7-46af-80e4-15cecba0b18a','硯瓦','貫休','唐','唐诗','tang','','[]','淺薄雖頑朴，其如近筆端。',48,'全唐诗/poet.tang.45000.json','["淺薄雖頑朴，其如近筆端。", "低心蒙潤久，入匣更身安。", "應念研磨苦，無爲瓦礫看。", "儻然仁不棄，還可比琅玕。"]'),
('1dc06baa-9966-4a88-9a9b-fa9ed08e5d4a','水壺子','貫休','唐','唐诗','tang','','[]','良匠曾陶瑩，多居筆硯中。',48,'全唐诗/poet.tang.45000.json','["良匠曾陶瑩，多居筆硯中。", "一從親几案，常恐近兒童。", "卓立澄心久，提攜注意通。", "不應嫌器小，還有濟人功。"]'),
('d816f1a2-982e-4540-8998-6562fdffb025','筆','貫休','唐','唐诗','tang','','[]','莫訝書紳苦，功成在一毫。',48,'全唐诗/poet.tang.45000.json','["莫訝書紳苦，功成在一毫。", "自從蒙管錄，便覺用心勞。", "手點時難棄，身閑架亦高。", "何妨成五色，永願助風騷。"]'),
('8ca6ed24-6521-402f-849f-c4df46748ae8','棊','貫休','唐','唐诗','tang','','[]','棊信無聲樂，偏宜境寂寥。',48,'全唐诗/poet.tang.45000.json','["棊信無聲樂，偏宜境寂寥。", "著高圖暗合，勢王氣彌驕。", "人事掀天盡，光陰動地銷。", "因知韋氏論，不獨爲吳朝。"]'),
('0c846acb-1c14-4cd8-9877-9126c8248e68','夜對雪作寄友生','貫休','唐','唐诗','tang','','[]','皓彩中宵合，開門失所蹤。',48,'全唐诗/poet.tang.45000.json','["皓彩中宵合，開門失所蹤。", "何年今夜意，共子在孤峰。", "氣射燈花落，光侵壁罅濃。", "唯君心似我，吟到五更鐘。"]'),
('ce2eeecf-98d5-4d01-81fb-89dce5b62d9f','題惠琮律師院','貫休','唐','唐诗','tang','','[]','苦節兼青目，公卿話有餘。',48,'全唐诗/poet.tang.45000.json','["苦節兼青目，公卿話有餘。", "唯傳黃葉喻，還似白泉居。", "猨撥孤雲破，鐘撞衆木疎。", "社壇蹤跡在，重結復何如。"]'),
('e61110c9-d584-4cea-ab75-1fcd50a9e4ac','寄清泠山道人','貫休','唐','唐诗','tang','','[]','常憶清泠子，深雲種早禾。',48,'全唐诗/poet.tang.45000.json','["常憶清泠子，深雲種早禾。", "萬緣雖不涉，一句子如何。", "蹤跡諸峰匝，衣裳老虱多。", "江頭無事也，終必到煙蘿。"]'),
('c3e8a03c-15f1-4db6-9450-b762972df3be','秋盡途中作','貫休','唐','唐诗','tang','','[]','行行芳草歇，潭島葉紛紛。',48,'全唐诗/poet.tang.45000.json','["行行芳草歇，潭島葉紛紛。", "山色路無盡，砧聲客強聞。", "殘陽曜極野，黑水浸空墳。", "那得無鄉思，前程入楚雲。"]'),
('23f86497-8343-4196-8337-f352aad57684','秋居寄王相公三首 一','貫休','唐','唐诗','tang','','[]','禪林蟬□落，地燥可生苔。',48,'全唐诗/poet.tang.45000.json','["禪林蟬□落，地燥可生苔。", "好句慵收拾，清風作麽來。", "餅唯餐喜悅，社已得宗雷。", "還似山中日，柴門更不開。"]'),
('26eb858c-23f4-4b8d-bdee-217eff1c5acd','秋居寄王相公三首 二','貫休','唐','唐诗','tang','','[]','松聲高似瀑，藥熟色如花。',48,'全唐诗/poet.tang.45000.json','["松聲高似瀑，藥熟色如花。", "誰道全無病，時猶不在家。", "山童舂菽粉，園叟送銀瓜。", "誰訪孫弘閣，談玄到日斜。"]'),
('2771e0fb-a3b4-413a-9c16-7621c1b67867','秋居寄王相公三首 三','貫休','唐','唐诗','tang','','[]','氣與非常合，常人爭得知。',48,'全唐诗/poet.tang.45000.json','["氣與非常合，常人爭得知。", "直須窮到底，始是出家兒。", "閣雀銜紅粟，鄰僧背古碑。", "祗應王與謝，時有沃州期。"]'),
('e5caae55-5b5d-48e2-8818-10fc9d18ac72','讀玄宗幸蜀記','貫休','唐','唐诗','tang','','[]','宋璟姚崇死，中庸遂變移。',144,'全唐诗/poet.tang.45000.json','["宋璟姚崇死，中庸遂變移。", "如何遊萬里，祗爲一胡兒。", "泣溻乾坤色，飄零日月旗。", "火從龍闕起，淚向馬嵬垂。", "始憶張丞相，全師郭子儀。", "百官皆剽劫，九廟盡崩隳。", "塵撲銀輪暗，雷奔棧閣危。", "倖臣方賜死，野老不勝悲。", "及霤飄淪日，行宮寂寞時。", "人心雖未厭，天意亦難知。", "聖兩歸丹禁，承乾動四夷。", "因知納諫諍，始是太平基。"]'),
('fe5a10b9-a93d-4525-aa75-2d13eb823d14','聞徵四處士','貫休','唐','唐诗','tang','','[]','一詔羣公起，移山四海聞。',48,'全唐诗/poet.tang.45000.json','["一詔羣公起，移山四海聞。", "因知丈夫事，須佐聖明君。", "白酒全傾甕，蒲輪半載雲。", "從茲居諫署，筆硯幾人焚。"]'),
('e01077e4-9b2f-4ff5-8ec2-b2beb06c1959','送友人下第遊邊','貫休','唐','唐诗','tang','','[]','失意窮邊去，孤城值晚春。',48,'全唐诗/poet.tang.45000.json','["失意窮邊去，孤城值晚春。", "黑山霞不赤，白日鬼隨人。", "角咽胡風緊，沙昏磧月新。", "明時至公在，迴首莫因循。"]'),
('6ca6a371-c799-4418-b228-bbf007af7117','寄匡山紀公','貫休','唐','唐诗','tang','','["\u5e90\u5c71"]','錦繡谷中人，相思入夢頻。',48,'全唐诗/poet.tang.45000.json','["錦繡谷中人，相思入夢頻。", "寄言無別事，琢句似終身。", "書卷須求旨，鬚根易得銀。", "斯言如不惑，千里亦相親。"]'),
('379416d5-eb98-44ef-8fd7-41eb405b5952','聞無相道人順世五首 一','貫休','唐','唐诗','tang','','[]','一事不經營，孤峰長老情。',36,'全唐诗/poet.tang.45000.json','["一事不經營，孤峰長老情。", "惟餐橡子餅，愛說道君兄。", "池藕香貍掘，山神白日行。"]'),
('84e54795-d406-4b1c-b77a-45de6ba025aa','聞無相道人順世五首 二','貫休','唐','唐诗','tang','','[]','自昔尋師日，顛峰絕頂頭。',48,'全唐诗/poet.tang.45000.json','["自昔尋師日，顛峰絕頂頭。", "雖聞不相似，特地使人愁。", "庭樹雪摧殘，上有白獮猴。", "大哉法中龍，去去不可留。"]'),
('db52ba9d-b7c0-4a0a-9b69-4d55c3d4f2f5','聞無相道人順世五首 三','貫休','唐','唐诗','tang','','[]','常思將道者，高論地爐傍。',48,'全唐诗/poet.tang.45000.json','["常思將道者，高論地爐傍。", "迂談無世味，夜深山木僵。", "下山遭離亂，多病惟深藏。", "一別三十年，煙水空茫茫。"]'),
('eafffc19-3d74-4a0d-9d90-22fa3b4143dc','聞無相道人順世五首 四','貫休','唐','唐诗','tang','','[]','石霜既順世，吾師亦不住。',48,'全唐诗/poet.tang.45000.json','["石霜既順世，吾師亦不住。", "杉桂有猩猩，糠粃無句句。", "土肥多孟蕨，道老如孾孺。", "莫比優曇花，斯人更難遇。"]'),
('02c5bb93-e6f6-4caf-8bfd-2d45a818d7ee','聞無相道人順世五首 五','貫休','唐','唐诗','tang','','[]','百千萬億偈，共他勿交涉。',48,'全唐诗/poet.tang.45000.json','["百千萬億偈，共他勿交涉。", "所以那老人，密傳與迦葉。", "吾師得此法，不論劫不劫。", "去矣不可留，無踪若爲躡。"]'),
('2ee8df6b-525b-408e-bbdb-b5381367ed1f','苦熱','貫休','唐','唐诗','tang','','[]','松桂枝不動，陽烏飛半天。',48,'全唐诗/poet.tang.45000.json','["松桂枝不動，陽烏飛半天。", "稻麻須結實，沙石欲生煙。", "毒氣仍干扇，高枝不立蟬。", "舊山多積雪，歸去是何年。"]'),
('7cbe381a-7b22-4e7e-ab21-99565ee597c5','鄂渚贈祥公','貫休','唐','唐诗','tang','','[]','寂寥堆積者，自爲是高僧。',48,'全唐诗/poet.tang.45000.json','["寂寥堆積者，自爲是高僧。", "客遠何人識，吟多冷病增。", "松煙青透壁，雪氣細吹燈。", "猶賴師於我，依依非面朋。"]'),
('89e8030c-3a82-4507-9813-a5f235e7362b','懷武昌棲一二首 一','貫休','唐','唐诗','tang','','[]','常憶能吟一，房連古帝墟。',48,'全唐诗/poet.tang.45000.json','["常憶能吟一，房連古帝墟。", "無端多忤物，唯我獨知渠。", "病愈囊空後，神清木落初。", "祗因烽火起，書札自茲疎。"]'),
('7f217011-f281-4957-9db6-797bbe42f2fb','懷武昌棲一二首 二','貫休','唐','唐诗','tang','','[]','清風江上月，霜灑月中砧。',48,'全唐诗/poet.tang.45000.json','["清風江上月，霜灑月中砧。", "得句先呈佛，無人知此心。", "寂寥從鬼出，蒼翠到門深。", "惟有雙峰寺，時時獨去尋。"]'),
('2c940534-e56b-470c-8637-7b727a602811','寒食郊外','貫休','唐','唐诗','tang','','[]','寒食將吾族，相隨過石溪。',48,'全唐诗/poet.tang.45000.json','["寒食將吾族，相隨過石溪。", "塚花沾酒落，林鳥學人啼。", "白水穿蕪疾，新霞出霧低。", "不堪迴首望，家在赤松西。"]'),
('12f8ead1-ed1c-4bd2-8c7c-c433b5f10e7b','送道士歸天台','貫休','唐','唐诗','tang','','[]','道高留不住，道去更何云。',48,'全唐诗/poet.tang.45000.json','["道高留不住，道去更何云。", "舉世皆趨世，如君始愛君。", "徑侵銀地滑，瀑到石城聞。", "它日如相憶，金桃一爲分。"]'),
('044d89e7-3b5a-40e1-8ae8-e6273de393ac','經孟浩然鹿門舊居二首 一','貫休','唐','唐诗','tang','','[]','孟子終焉處，遊人得得過。',50,'全唐诗/poet.tang.45000.json','["孟子終焉處，遊人得得過。", "⿰木養深黃狖小，地煗白雲多。", "孔聖嗟大謬，玄宗爭奈何。", "空餘峴山色，千古共嵯峨。"]'),
('eeda7c05-18ee-447c-a4b4-361dcec8f0e8','經孟浩然鹿門舊居二首 二','貫休','唐','唐诗','tang','','[]','花落谷鶯啼，精靈安在哉。',48,'全唐诗/poet.tang.45000.json','["花落谷鶯啼，精靈安在哉。", "青山不可問，永日獨裴回。", "塚穴應藏虎，荒碑祗見苔。", "伊余亦惆悵，昨日郢城迴。"]'),
('81de46df-7a5c-4e45-b174-e7f026d1f11d','春送禪師歸閩中','貫休','唐','唐诗','tang','','[]','春色滿三湘，送師還故鄉。',48,'全唐诗/poet.tang.45000.json','["春色滿三湘，送師還故鄉。", "穿霞逢黑鴧，乞食得紅薑。", "大化宗門闢，孤禪海樹涼。", "儻爲新句偈，寄我亦何妨。"]'),
('bb03845a-507c-4a85-b25a-2cd7b2103ed2','途中逢周朴','貫休','唐','唐诗','tang','','[]','東西南北路，相遇共興哀。',48,'全唐诗/poet.tang.45000.json','["東西南北路，相遇共興哀。", "世濁無知己，子從何處來？", "菊衰芳草在，程遠宿煙開。", "儻遇中興主，還應不用媒。"]');
